--dim tables stored procedures
CREATE OR ALTER  PROCEDURE [stg].[sp_DIM_TXN_ERROR_LOG_TABLES] @LoadID BIGINT
AS
BEGIN
    SET XACT_ABORT ON;
    SET NOCOUNT ON;
    DECLARE @TABLENAME VARCHAR(60),
            @PROCESSNAME VARCHAR(60) = 'TXN_ERROR_LOG',
            @TODAY DATE = GETDATE(),
            @TODAYDT DATETIME2(0) = GETDATE(),
            @INSERTS BIGINT = 0,
            @UPDATES BIGINT = 0,
            @ERRORS BIGINT = 0,
            @UNCHANGED BIGINT = 0;
    BEGIN TRY
        BEGIN TRANSACTION
		/**************************************************/
        SET @TableName = 'D_ERROR_LOG_FLAG';
        MERGE [dbo].[D_ERROR_LOG_FLAG] AS TGT
        USING
        (
            SELECT DISTINCT
                ISNULL(TRIM([FLAG]), '')
            FROM [stg].[DMS_TXN_ERROR_LOG] 
            WHERE [FLAG] IS NOT NULL
                  OR [FLAG] <> ''
        ) AS SRC
        (ERROR_LOG_FLAG)
        ON (ISNULL(TRIM(TGT.[ERROR_LOG_FLAG_CODE]), '') = ISNULL(TRIM(SRC.[ERROR_LOG_FLAG]), ''))
        WHEN NOT MATCHED THEN
            INSERT
            (
                [ERROR_LOG_FLAG_CODE],
                [ERROR_LOG_FLAG_DESC]
            )
            VALUES
            (ISNULL(TRIM(SRC.[ERROR_LOG_FLAG]), ''), CONCAT(SRC.[ERROR_LOG_FLAG], ' - TO BE CONFIRMED'))
        OUTPUT @PROCESSNAME,
               @TABLENAME,
               $action,
               @TODAY,
               inserted.[ERROR_LOG_FLAG_ID],
               deleted.[ERROR_LOG_FLAG_DESC],
               inserted.[ERROR_LOG_FLAG_DESC]
        INTO [process].[DMS_DIMENSION_CHANGES];
        /**************************************************/
        SET @TableName = 'D_ERROR';
			MERGE [dbo].[D_ERROR] AS TGT
			USING
			(
				SELECT DISTINCT ISNULL(TRIM([ERROR_NAME]), '')
				FROM [stg].[DMS_TXN_ERROR_LOG]
				WHERE [ERROR_NAME] IS NOT NULL
				  OR TRIM([ERROR_NAME]) <> ''
			) AS SRC
        (ERROR_NAME)
        ON (ISNULL(TRIM(TGT.[ERROR_DESC]), '') = ISNULL(TRIM(SRC.[ERROR_NAME]), ''))
        WHEN NOT MATCHED THEN
            INSERT
            (
                [ERROR_DESC]
            )
            VALUES (ISNULL(TRIM(SRC.[ERROR_NAME]), ''))
        OUTPUT @PROCESSNAME,
               @TABLENAME,
               $action,
               @TODAY,
               inserted.[ERROR_ID],
               deleted.[ERROR_DESC],
               inserted.[ERROR_DESC]
        INTO [process].[DMS_DIMENSION_CHANGES];
		/**************************************************/
		SET @TableName = 'D_TRANSACTION';
        MERGE [dbo].[D_TRANSACTION] AS TGT
        USING
        (
			SELECT DISTINCT
                ISNULL(TRIM([TXN_NAME]), '')
            FROM [STG].[DMS_TXN_ERROR_LOG] 
            WHERE [TXN_NAME] IS NOT NULL
                  OR [TXN_NAME] <> ''
        ) AS SRC
        ([TRANSACTION])
        ON (ISNULL(TRIM(TGT.[TRANSACTION_DESCRIPTION]), '') = ISNULL(TRIM(SRC.[TRANSACTION]), ''))
        WHEN NOT MATCHED THEN
            INSERT
            (	
                [TRANSACTION_DESCRIPTION]
            )
            VALUES
            (ISNULL(TRIM(SRC.[TRANSACTION]), ''))
        OUTPUT @PROCESSNAME,
               @TABLENAME,
               $action,
               @TODAY,
               inserted.[TRANSACTION_ID],
               deleted.[TRANSACTION_DESCRIPTION],
               inserted.[TRANSACTION_DESCRIPTION]
        INTO [process].[DMS_DIMENSION_CHANGES];
        /**************************************************/
        SET @TableName = 'D_IDENTIFIER';
        MERGE [dbo].[D_IDENTIFIER] AS TGT
        USING
        (
        SELECT DISTINCT ISNULL(TRIM([IDENTIFIER_NAME]), '')
        FROM [stg].[DMS_TXN_ERROR_LOG]
        WHERE [IDENTIFIER_NAME] IS NOT NULL
            OR TRIM([IDENTIFIER_NAME]) <> ''
        ) AS SRC
        (IDENTIFIER_NAME)
        ON (ISNULL(TRIM(TGT.[IDENTIFIER_NAME]), '') = ISNULL(TRIM(SRC.[IDENTIFIER_NAME]), ''))
        WHEN NOT MATCHED THEN
            INSERT
            (
                [IDENTIFIER_NAME]
            )
            VALUES (ISNULL(TRIM(SRC.[IDENTIFIER_NAME]), ''))
        OUTPUT @PROCESSNAME,
               @TABLENAME,
               $action,
               @TODAY,
               inserted.[IDENTIFIER_ID],
               deleted.[IDENTIFIER_NAME],
               inserted.[IDENTIFIER_NAME]
        INTO [process].[DMS_DIMENSION_CHANGES];
   /**************************************************/
        COMMIT TRANSACTION
    END TRY
    BEGIN CATCH
        ROLLBACK;
        PRINT ERROR_MESSAGE()
        UPDATE [sqlmi-dev-dp-cex-control-db].[dbo].[Load_Audit]
        SET Load_ErrorMsg = ERROR_MESSAGE()
        WHERE LoadID = @LoadID
    END CATCH
    IF @@TRANCOUNT > 0
        ROLLBACK;
END
GO
