--Enterprise tables stored procedures
--------------------------------------------------------------------------------------------------------------------------------
CREATE OR ALTER     PROCEDURE [stg].[sp_UPDATE_TXN_ERROR_LOG] @LoadID BIGINT
AS
BEGIN
    SET XACT_ABORT ON;
    SET NOCOUNT ON;
    DECLARE @Inserts BIGINT = 0,
            @Updates BIGINT = 0,
            @Errors BIGINT = 0,
            @Unchanged BIGINT = 0,
            @Deletes BIGINT = 0,
            @OriginalRowCount BIGINT = 0,
            @Staged BIGINT = 0,
            @RowsAffected BIGINT = 0,
            @masterRunID VARCHAR(100) = '',
            @TodayDT DATETIME2(3) = GETUTCDATE(),
            @Today DATE = GETUTCDATE(),
            @Yesterday DATE = TRY_CONVERT(DATE, DATEADD(DAY, -1, GETUTCDATE())),
            @EOM INT = DATEPART(DAY, GETUTCDATE()),
            @LoadDate DATE = GETUTCDATE();

    BEGIN TRY
        BEGIN TRANSACTION
------------------------------------------------------------------------------------------------------------------------------		
	TRUNCATE TABLE [process].[TXN_ERROR_LOG]
	INSERT INTO [process].[TXN_ERROR_LOG]
           ([PK_ERROR_ID]
           ,[FK_ERROR_LOG_FLAG_ID]
           ,[FK_ERROR_ID]
           ,[CREATED_DATE]
           ,[FK_TRANSACTION_ID]
           ,[FK_IDENTIFIER_ID]
           ,[IDENTIFIER_VALUE]
           ,[HASH_VALUE])

	SELECT
			ISNULL(TRY_CONVERT(INT, SRC.[ERROR_ID]), 0) AS [PK_ERROR_ID],
			ISNULL(TRY_CONVERT(TINYINT, ERR.ERROR_LOG_FLAG_ID), 0) AS [FK_ERROR_LOG_FLAG_ID],
			ISNULL(TRY_CONVERT(SMALLINT, ERRROR.[ERROR_ID]), 0) AS [FK_ERROR_ID],
			ISNULL(TRY_CONVERT(DATE, SRC.[CREATED_ON]), '1900-01-01') AS [CREATED_DATE],
			ISNULL(TRY_CONVERT(SMALLINT, ERRR.[TRANSACTION_ID]), 0) AS [FK_TRANSACTION_ID],
			ISNULL(TRY_CONVERT(TINYINT, ID.[IDENTIFIER_ID]), 0) AS [FK_IDENTIFIER_ID],
			ISNULL(TRY_CONVERT(VARCHAR(16), SRC.[IDENTIFIER_VALUE]), '') AS [IDENTIFIER_VALUE],
		   HASHBYTES(
                        'sha1',
                            CONCAT_WS('|',
									ISNULL(TRY_CONVERT(TINYINT, ERR.ERROR_LOG_FLAG_ID), 0),
									ISNULL(TRY_CONVERT(SMALLINT, ERRROR.[ERROR_ID]), 0),
									ISNULL(TRY_CONVERT(DATE, SRC.[CREATED_ON]), '1900-01-01'),
									ISNULL(TRY_CONVERT(SMALLINT, ERRR.[TRANSACTION_ID]), 0),
									ISNULL(TRY_CONVERT(TINYINT, ID.[IDENTIFIER_ID]), 0),
									ISNULL(TRY_CONVERT(VARCHAR(16), SRC.[IDENTIFIER_VALUE]), '')
									))
									AS [HASH_VALUE]
     FROM STG.[DMS_TXN_ERROR_LOG] AS SRC
     INNER JOIN DBO.D_ERROR_LOG_FLAG AS ERR
     ON ISNULL(TRIM(SRC.[FLAG]), '') = ERR.ERROR_LOG_FLAG_CODE
     INNER JOIN DBO.D_TRANSACTION AS ERRR
     ON ISNULL(TRIM(SRC.[TXN_NAME]), '') = ERRR.TRANSACTION_DESCRIPTION
     INNER JOIN DBO.D_ERROR AS ERRROR
     ON ISNULL(TRIM(SRC.[ERROR_NAME]), '') = ERRROR.ERROR_DESC
     INNER JOIN DBO.D_IDENTIFIER AS ID
     ON ISNULL(TRIM(SRC.[IDENTIFIER_NAME]), '') = ID.IDENTIFIER_NAME;

------------------------------------------------------------------------------------------------------------------------------
	UPDATE DBO
	SET 
	DBO.FK_ERROR_LOG_FLAG_ID = PRO.FK_ERROR_LOG_FLAG_ID,
	DBO.FK_ERROR_ID = PRO.FK_ERROR_ID,
	DBO.CREATED_DATE = PRO.CREATED_DATE,
	DBO.FK_TRANSACTION_ID = PRO.FK_TRANSACTION_ID,
	DBO.FK_IDENTIFIER_ID = PRO.FK_IDENTIFIER_ID,
	DBO.IDENTIFIER_VALUE = PRO.IDENTIFIER_VALUE
	FROM [process].[TXN_ERROR_LOG] AS PRO
	INNER JOIN DBO.E_TXN_ERROR_LOG AS DBO
	ON ISNULL(DBO.PK_ERROR_ID, 0) = PRO.PK_ERROR_ID
	WHERE PRO.HASH_VALUE <> DBO.HASH_VALUE;

	SET @Updates = @@ROWCOUNT;
------------------------------------------------------------------------------------------------------------------------------
	INSERT INTO [DBO].[E_TXN_ERROR_LOG]
           ([PK_ERROR_ID]
           ,[FK_ERROR_LOG_FLAG_ID]
           ,[FK_ERROR_ID]
           ,[CREATED_DATE]
           ,[FK_TRANSACTION_ID]
           ,[FK_IDENTIFIER_ID]
           ,[IDENTIFIER_VALUE]
           ,[HASH_VALUE])
		   
	SELECT 
		    PRO.PK_ERROR_ID,
			PRO.FK_ERROR_LOG_FLAG_ID,
			PRO.FK_ERROR_ID,
			PRO.CREATED_DATE,
			PRO.FK_TRANSACTION_ID,
			PRO.FK_IDENTIFIER_ID,
			PRO.IDENTIFIER_VALUE,
			PRO.HASH_VALUE
			FROM [process].[TXN_ERROR_LOG] AS PRO
			LEFT JOIN DBO.E_TXN_ERROR_LOG AS DBO
			ON ISNULL(DBO.PK_ERROR_ID, 0) = PRO.PK_ERROR_ID
			WHERE DBO.PK_ERROR_ID IS NULL;
			
			SET @Inserts = @@ROWCOUNT;
------------------------------------------------------------------------------------------------------------------------------
        /* Insert to Audit Table */
        UPDATE [sqlmi-dev-dp-cex-control-db].dbo.Load_Audit
        SET Staged_Rows = @Staged,
            New_Rows = @Inserts,
            Updated_Rows = @Updates,
            Deleted_Rows = @Deletes,
            Error_Rows = @Errors,
            Unchanged_Rows = @Unchanged,
            Load_ErrorMsg = CASE
                                WHEN Load_ErrorMsg = '' THEN
                                    ''
                                ELSE
                                    'Resolved on ' + FORMAT(GETDATE(), 'dd/MM/yyyy a   hh:mmtt') + ' - '
                                    + Load_ErrorMsg
                            END
        WHERE LoadID = @LoadID
        COMMIT TRANSACTION
    END TRY
    BEGIN CATCH
        ROLLBACK;
        /* Insert error message to Audit Table */
        UPDATE [sqlmi-dev-dp-cex-control-db].dbo.Load_Audit
        SET Load_ErrorMsg = ERROR_MESSAGE()
        WHERE LoadID = @LoadID
    END CATCH
    /* Revert entire process if failure */
    IF @@TRANCOUNT > 0
        ROLLBACK;
END
GO
