           ,[BILLING_ADDRESS_BUILDING_NAME]
           ,[BILLING_ADDRESS_LINE_1]
           ,[BILLING_ADDRESS_LINE_2]
           ,[BILLING_ADDRESS_LINE_3]
           ,[BILLING_ADDRESS_LINE_4]
           ,[BILLING_ADDRESS_LINE_5]
           ,[BILLING_ADDRESS_POSTCODE]
           ,[CONTACT_NAME]
           ,[CONTACT_EMAIL]
           ,[CONTACT_NUMBER]
           ,[HASH_VALUE])

	SELECT
           ISNULL(TRY_CONVERT(TINYINT, WTR.[WATER_RETAILER_ID]), 0) AS [FK_RETAILER_ID],
           ISNULL(TRY_CONVERT(TINYINT, WHOLE.WHOLESALER_ID), 0) AS [FK_OTHER_WHOLESALER_ID],
           ISNULL(TRY_CONVERT(INT, SRC.[D2009_Pairing_Reference]), 0) AS [PAIRING_REFERENCE],
           ISNULL(TRY_CONVERT(TINYINT, PAIR.PAIRING_REFERENCE_REASON_ID), 0)  AS [FK_PAIRING_REFERENCE_REASON_ID],
           ISNULL(TRY_CONVERT(TINYINT, CORE.SERVICE_CATEGORY_ID), 0) AS [FK_SERVICE_CATEGORY_ID],
		   ISNULL(TRY_CONVERT(VARCHAR(16), SRC.[D2091_Other_SPID]), '') AS [OTHER_SPID],
		   ISNULL(TRY_CONVERT(TINYINT, NEW.NEW_CONNECTION_TYPE_ID), 0) AS [FK_NEW_CONNECTION_TYPE_ID],
		   ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[D2037_VOA_BA_Reference]), '') AS [VOA_BA_REFERENCE],
		   ISNULL(TRY_CONVERT(TINYINT, UPRN.VOA_BA_REASON_ID), 0) AS [FK_VOA_BA_REFERENCE_REASON_ID],
		   ISNULL(TRY_CONVERT(NUMERIC(20,0), SRC.[D2039_UPRN]), 0) AS [UPRN],
		   ISNULL(TRY_CONVERT(TINYINT, UPRN2.UPRN_REASON_ID), 0) AS [FK_UPRN_REASON_ID],
		   ISNULL(TRY_CONVERT(VARCHAR(128), SRC.[D5001_Free_Descriptor]), '') AS [FREE_DESCRIPTOR],
		   ISNULL(TRY_CONVERT(VARCHAR(128), SRC.[D5003_Primary_Addressable_Object]), '') AS [PRIMARY_ADDRESSABLE_OBJECT],
		   ISNULL(TRY_CONVERT(VARCHAR(128), SRC.[D5002_Secondary_Addressable_Object]), '') AS [SECONDARY_ADDRESSABLE_OBJECT],
		   ISNULL(TRY_CONVERT(VARCHAR(128), SRC.[D5004_Address_Line_1]), '') AS [ADDRESS_LINE_1],
		   ISNULL(TRY_CONVERT(VARCHAR(64), SRC.[D5005_Address_Line_2]), '') AS [ADDRESS_LINE_2],
		   ISNULL(TRY_CONVERT(VARCHAR(64), SRC.[D5006_Address_Line_3]), '') AS [ADDRESS_LINE_3],
		   ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[D5007_Address_Line_4]), '') AS [ADDRESS_LINE_4],
		   ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[D5008_Address_Line_5]), '') AS [ADDRESS_LINE_5],
		   ISNULL(TRY_CONVERT(VARCHAR(16), SRC.[D5009_Postcode]), '') AS [POSTCODE],
		   ISNULL(TRY_CONVERT(INT, SRC.[D5011_PAF_Address_Key]), 0) AS [PAF_ADDRESS_KEY],
           ISNULL(TRY_CONVERT(BIT, SRC.[D2053_Multiple_Wholesalers_Flag]), 0) AS [FLG_MULTIPLE_WHOLESALERS],
		   ISNULL(TRY_CONVERT(VARCHAR(16), SRC.[D2070_Landlord_SPID]), '') AS [LANDLORD_SPID],
		   ISNULL(TRY_CONVERT(VARCHAR(512), SRC.[D4003_Text_Comment_Field]), '') AS [TEXT_COMMENT_FIELD],
		   ISNULL(TRY_CONVERT(VARCHAR(16), SRC.[D2001_SPID]), '') AS [SPID],
		   ISNULL(TRY_CONVERT(DATE, SRC.[CreatedOn]), '1900-01-01') AS [CREATED_DATE],
		   ISNULL(TRY_CONVERT(DATETIME2(3), SRC.[LastUpdatedOn]), '1900-01-01 00:00:00.000') AS [LAST_UPDATED_ON],
		   ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[Transaction_Unique_ID]), '') AS [TRANSACTION_UNIQUE_ID],
		   ISNULL(TRY_CONVERT(TINYINT, TRANSACT.[TRANSACTION_STATUS_ID]), 0) AS [FK_TRANSACTION_STATUS_ID],
		   ISNULL(TRY_CONVERT(TINYINT, MOSL.MOSL_MESSAGE_ID), 0) AS [FK_MOSL_MESSAGE_ID],
		   ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[Request_ID]), '') AS [REQUEST_ID],
		   ISNULL(TRY_CONVERT(VARCHAR(64), SRC.[D2028_Business_Name]), '') AS [BUSINESS_NAME],
		   ISNULL(TRY_CONVERT(VARCHAR(128), SRC.[D2050_Customer_Banner_Name]), '') AS [CUSTOMER_BANNER_NAME],
		   ISNULL(TRY_CONVERT(VARCHAR(64), SRC.[D5012_Billing_Address_Building_Name]), '') AS [BILLING_ADDRESS_BUILDING_NAME],
		   ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[D5013_Billing_Address_Line_1]), '') AS [BILLING_ADDRESS_LINE_1],
		   ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[D5014_Billing_Address_Line_2]), '') AS [BILLING_ADDRESS_LINE_2],
		   ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[D5015_Billing_Address_Line_3]), '') AS [BILLING_ADDRESS_LINE_3],
		   ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[D5016_Billing_Address_Line_4]), '') AS [BILLING_ADDRESS_LINE_4],
		   ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[D5017_Billing_Address_Line_5]), '') AS [BILLING_ADDRESS_LINE_5],
		   ISNULL(TRY_CONVERT(VARCHAR(16), SRC.[D5018_Billing_Address_Postcode]), '') AS [BILLING_ADDRESS_POSTCODE],
		   ISNULL(TRY_CONVERT(VARCHAR(256), SRC.[D4032_Contact_Name]), '') AS [CONTACT_NAME],
		   ISNULL(TRY_CONVERT(VARCHAR(256), SRC.[D4033_Contact_Email]), '') AS [CONTACT_EMAIL],
		   ISNULL(TRY_CONVERT(VARCHAR(256), SRC.[D4034_Contact_Number]), '') AS [CONTACT_NUMBER],
		   HASHBYTES(
                        'sha1',
                            CONCAT_WS('|',
									ISNULL(TRY_CONVERT(TINYINT, WTR.[WATER_RETAILER_ID]), 0),
									ISNULL(TRY_CONVERT(TINYINT, WHOLE.WHOLESALER_ID), 0),
									ISNULL(TRY_CONVERT(TINYINT, PAIR.PAIRING_REFERENCE_REASON_ID), 0),
									ISNULL(TRY_CONVERT(TINYINT, CORE.SERVICE_CATEGORY_ID), 0),
									ISNULL(TRY_CONVERT(VARCHAR(16), SRC.[D2091_Other_SPID]), ''),
									ISNULL(TRY_CONVERT(TINYINT, NEW.NEW_CONNECTION_TYPE_ID), 0),
									ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[D2037_VOA_BA_Reference]), ''),
									ISNULL(TRY_CONVERT(TINYINT, UPRN.VOA_BA_REASON_ID), 0),
									ISNULL(TRY_CONVERT(NUMERIC(20,0), SRC.[D2039_UPRN]), 0),
									ISNULL(TRY_CONVERT(TINYINT, UPRN2.UPRN_REASON_ID), 0),
									ISNULL(TRY_CONVERT(VARCHAR(128), SRC.[D5001_Free_Descriptor]), ''),
									ISNULL(TRY_CONVERT(VARCHAR(128), SRC.[D5003_Primary_Addressable_Object]), ''),
									ISNULL(TRY_CONVERT(VARCHAR(128), SRC.[D5002_Secondary_Addressable_Object]), ''),
									ISNULL(TRY_CONVERT(VARCHAR(128), SRC.[D5004_Address_Line_1]), ''),
									ISNULL(TRY_CONVERT(VARCHAR(64), SRC.[D5005_Address_Line_2]), ''),
									ISNULL(TRY_CONVERT(VARCHAR(64), SRC.[D5006_Address_Line_3]), ''),
									ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[D5007_Address_Line_4]), ''),
									ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[D5008_Address_Line_5]), ''),
									ISNULL(TRY_CONVERT(VARCHAR(16), SRC.[D5009_Postcode]), ''),
									ISNULL(TRY_CONVERT(INT, SRC.[D5011_PAF_Address_Key]), 0),
									ISNULL(TRY_CONVERT(BIT, SRC.[D2053_Multiple_Wholesalers_Flag]), 0),
									ISNULL(TRY_CONVERT(VARCHAR(16), SRC.[D2070_Landlord_SPID]), ''),
									ISNULL(TRY_CONVERT(VARCHAR(512), SRC.[D4003_Text_Comment_Field]), ''),
									ISNULL(TRY_CONVERT(VARCHAR(16), SRC.[D2001_SPID]), ''),
									ISNULL(TRY_CONVERT(DATETIME2(3), SRC.[LastUpdatedOn]), '1900-01-01 00:00:00.000'),
									ISNULL(TRY_CONVERT(TINYINT, TRANSACT.[TRANSACTION_STATUS_ID]), 0),
									ISNULL(TRY_CONVERT(TINYINT, MOSL.MOSL_MESSAGE_ID), 0),
									ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[Request_ID]), ''),
									ISNULL(TRY_CONVERT(VARCHAR(64), SRC.[D2028_Business_Name]), ''),
									ISNULL(TRY_CONVERT(VARCHAR(128), SRC.[D2050_Customer_Banner_Name]), ''),
									ISNULL(TRY_CONVERT(VARCHAR(64), SRC.[D5012_Billing_Address_Building_Name]), ''),
									ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[D5013_Billing_Address_Line_1]), ''),
									ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[D5014_Billing_Address_Line_2]), ''),
									ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[D5015_Billing_Address_Line_3]), ''),
									ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[D5016_Billing_Address_Line_4]), ''),
									ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[D5017_Billing_Address_Line_5]), ''),
									ISNULL(TRY_CONVERT(VARCHAR(16), SRC.[D5018_Billing_Address_Postcode]), ''),
									ISNULL(TRY_CONVERT(VARCHAR(256), SRC.[D4032_Contact_Name]), ''),
									ISNULL(TRY_CONVERT(VARCHAR(256), SRC.[D4033_Contact_Email]), ''),
									ISNULL(TRY_CONVERT(VARCHAR(256), SRC.[D4034_Contact_Number]), '')
									))
									AS [HASH_VALUE]
     FROM STG.DMS_TXN_T101W AS SRC
     INNER JOIN DBO.D_WATER_RETAILER_ID AS WTR
     ON ISNULL(TRIM(SRC.[D4011_Retailer_ID]), '') = WTR.WATER_RETAILER_CODE
	 INNER JOIN DBO.D_WHOLESALER AS WHOLE
	 ON ISNULL(TRIM(SRC.[D4018_Other_Wholesaler_ID]), '') = WHOLE.WHOLESALER_CODE
	 INNER JOIN DBO.D_PAIRING_REFERENCE_REASON AS PAIR
	 ON ISNULL(TRIM(SRC.[D2086_Pairing_Reference_Reason_Code]), '') = PAIR.PAIRING_REFERENCE_REASON_CODE
	 INNER JOIN DBO.D_CORE_SERVICE_CATEGORY AS CORE
	 ON ISNULL(TRIM(SRC.[D2002_Service_Category]), '') = CORE.SERVICE_CATEGORY_CODE
	 INNER JOIN DBO.D_NEW_CONNECTION_TYPE AS NEW
	 ON ISNULL(TRIM(SRC.[D2023_New_Connection_Type]), '') = NEW.NEW_CONNECTION_TYPE_CODE
	 INNER JOIN DBO.D_VOA_BA_REFERENCE_REASON AS UPRN
	 ON ISNULL(TRIM(SRC.[D2038_VOA_BA_Reference_Reason_Code]), '') = UPRN.VOA_BA_REASON_CODE
	 INNER JOIN DBO.D_UPRN_REASON_CODE AS UPRN2
	 ON ISNULL(TRIM(SRC.[D2040_UPRN_Reason_Code]), '') = UPRN2.UPRN_REASON_CODE
	 INNER JOIN DBO.D_MOSL_MESSAGE AS MOSL
	 ON ISNULL(TRIM(SRC.[MOSL_Message]), '') = MOSL.MOSL_MESSAGE_CODE
     INNER JOIN DBO.D_TRANSACTION_STATUS AS TRANSACT
     ON ISNULL(TRIM(SRC.[Transaction_Status]), '') = TRANSACT.TRANSACTION_STATUS;

------------------------------------------------------------------------------------------------------------------------------
	UPDATE DBO
	SET 
	DBO.FK_RETAILER_ID = PRO.FK_RETAILER_ID,
	DBO.FK_OTHER_WHOLESALER_ID = PRO.FK_OTHER_WHOLESALER_ID,
	DBO.FK_PAIRING_REFERENCE_REASON_ID = PRO.FK_PAIRING_REFERENCE_REASON_ID,
	DBO.FK_SERVICE_CATEGORY_ID = PRO.FK_SERVICE_CATEGORY_ID,
	DBO.OTHER_SPID = PRO.OTHER_SPID,
	DBO.FK_NEW_CONNECTION_TYPE_ID = PRO.FK_NEW_CONNECTION_TYPE_ID,
	DBO.VOA_BA_REFERENCE = PRO.VOA_BA_REFERENCE,
	DBO.FK_VOA_BA_REFERENCE_REASON_ID = PRO.FK_VOA_BA_REFERENCE_REASON_ID,
	DBO.UPRN = PRO.UPRN,
	DBO.FK_UPRN_REASON_ID = PRO.FK_UPRN_REASON_ID,
	DBO.FREE_DESCRIPTOR = PRO.FREE_DESCRIPTOR,
	DBO.PRIMARY_ADDRESSABLE_OBJECT = PRO.PRIMARY_ADDRESSABLE_OBJECT,
	DBO.SECONDARY_ADDRESSABLE_OBJECT = PRO.SECONDARY_ADDRESSABLE_OBJECT,
	DBO.ADDRESS_LINE_1 = PRO.ADDRESS_LINE_1,
	DBO.ADDRESS_LINE_2 = PRO.ADDRESS_LINE_2,
	DBO.ADDRESS_LINE_3 = PRO.ADDRESS_LINE_3,
	DBO.ADDRESS_LINE_4 = PRO.ADDRESS_LINE_4,
	DBO.ADDRESS_LINE_5 = PRO.ADDRESS_LINE_5,
	DBO.POSTCODE = PRO.POSTCODE,
	DBO.PAF_ADDRESS_KEY = PRO.PAF_ADDRESS_KEY,
	DBO.FLG_MULTIPLE_WHOLESALERS = PRO.FLG_MULTIPLE_WHOLESALERS,
	DBO.LANDLORD_SPID = PRO.LANDLORD_SPID,
	DBO.TEXT_COMMENT_FIELD = PRO.TEXT_COMMENT_FIELD,
	DBO.SPID = PRO.SPID,
	DBO.LAST_UPDATED_ON = PRO.LAST_UPDATED_ON,
	DBO.FK_TRANSACTION_STATUS_ID = PRO.FK_TRANSACTION_STATUS_ID,
	DBO.FK_MOSL_MESSAGE_ID = PRO.FK_MOSL_MESSAGE_ID,
	DBO.REQUEST_ID = PRO.REQUEST_ID,
	DBO.BUSINESS_NAME = PRO.BUSINESS_NAME,
	DBO.CUSTOMER_BANNER_NAME = PRO.CUSTOMER_BANNER_NAME,
	DBO.BILLING_ADDRESS_BUILDING_NAME = PRO.BILLING_ADDRESS_BUILDING_NAME,
	DBO.BILLING_ADDRESS_LINE_1 = PRO.BILLING_ADDRESS_LINE_1,
	DBO.BILLING_ADDRESS_LINE_2 = PRO.BILLING_ADDRESS_LINE_2,
	DBO.BILLING_ADDRESS_LINE_3 = PRO.BILLING_ADDRESS_LINE_3,
	DBO.BILLING_ADDRESS_LINE_4 = PRO.BILLING_ADDRESS_LINE_4,
	DBO.BILLING_ADDRESS_LINE_5 = PRO.BILLING_ADDRESS_LINE_5,
	DBO.BILLING_ADDRESS_POSTCODE = PRO.BILLING_ADDRESS_POSTCODE,
	DBO.CONTACT_NAME = PRO.CONTACT_NAME,
	DBO.CONTACT_EMAIL = PRO.CONTACT_EMAIL,
	DBO.CONTACT_NUMBER = PRO.CONTACT_NUMBER
	FROM [process].[TXN_T101W] AS PRO
	INNER JOIN DBO.E_TXN_T101_WHOLESALER AS DBO
	ON ISNULL(DBO.SPID, '') = PRO.SPID
	AND ISNULL(DBO.TRANSACTION_UNIQUE_ID, '') = PRO.TRANSACTION_UNIQUE_ID
	AND ISNULL(DBO.LAST_UPDATED_ON, '1900-01-01 00:00:00.000') = PRO.LAST_UPDATED_ON
	AND ISNULL(DBO.REQUEST_ID, '') = PRO.REQUEST_ID
	WHERE PRO.HASH_VALUE <> DBO.HASH_VALUE;

	SET @Updates = @@ROWCOUNT;
------------------------------------------------------------------------------------------------------------------------------
	INSERT INTO [DBO].[E_TXN_T101_WHOLESALER]
           ([FK_RETAILER_ID]
           ,[FK_OTHER_WHOLESALER_ID]
           ,[PAIRING_REFERENCE]
           ,[FK_PAIRING_REFERENCE_REASON_ID]
           ,[FK_SERVICE_CATEGORY_ID]
           ,[OTHER_SPID]
           ,[FK_NEW_CONNECTION_TYPE_ID]
           ,[VOA_BA_REFERENCE]
           ,[FK_VOA_BA_REFERENCE_REASON_ID]
           ,[UPRN]
           ,[FK_UPRN_REASON_ID]
           ,[FREE_DESCRIPTOR]
           ,[PRIMARY_ADDRESSABLE_OBJECT]
           ,[SECONDARY_ADDRESSABLE_OBJECT]
           ,[ADDRESS_LINE_1]
           ,[ADDRESS_LINE_2]
           ,[ADDRESS_LINE_3]
           ,[ADDRESS_LINE_4]
           ,[ADDRESS_LINE_5]
           ,[POSTCODE]
           ,[PAF_ADDRESS_KEY]
           ,[FLG_MULTIPLE_WHOLESALERS]
           ,[LANDLORD_SPID]
           ,[TEXT_COMMENT_FIELD]
           ,[SPID]
           ,[CREATED_DATE]
           ,[LAST_UPDATED_ON]
           ,[TRANSACTION_UNIQUE_ID]
           ,[FK_TRANSACTION_STATUS_ID]
           ,[FK_MOSL_MESSAGE_ID]
           ,[REQUEST_ID]
           ,[BUSINESS_NAME]
           ,[CUSTOMER_BANNER_NAME]
           ,[BILLING_ADDRESS_BUILDING_NAME]
           ,[BILLING_ADDRESS_LINE_1]
           ,[BILLING_ADDRESS_LINE_2]
           ,[BILLING_ADDRESS_LINE_3]
           ,[BILLING_ADDRESS_LINE_4]
           ,[BILLING_ADDRESS_LINE_5]
           ,[BILLING_ADDRESS_POSTCODE]
           ,[CONTACT_NAME]
           ,[CONTACT_EMAIL]
           ,[CONTACT_NUMBER]
           ,[HASH_VALUE])
		   
	SELECT 
		    PRO.FK_RETAILER_ID,
			PRO.FK_OTHER_WHOLESALER_ID,
			PRO.PAIRING_REFERENCE,
			PRO.FK_PAIRING_REFERENCE_REASON_ID,
			PRO.FK_SERVICE_CATEGORY_ID,
			PRO.OTHER_SPID,
			PRO.FK_NEW_CONNECTION_TYPE_ID,
			PRO.VOA_BA_REFERENCE,
			PRO.FK_VOA_BA_REFERENCE_REASON_ID,
			PRO.UPRN,
			PRO.FK_UPRN_REASON_ID,
			PRO.FREE_DESCRIPTOR,
			PRO.PRIMARY_ADDRESSABLE_OBJECT,
			PRO.SECONDARY_ADDRESSABLE_OBJECT,
			PRO.ADDRESS_LINE_1,
			PRO.ADDRESS_LINE_2,
			PRO.ADDRESS_LINE_3,
			PRO.ADDRESS_LINE_4,
			PRO.ADDRESS_LINE_5,
			PRO.POSTCODE,
			PRO.PAF_ADDRESS_KEY,
			PRO.FLG_MULTIPLE_WHOLESALERS,
			PRO.LANDLORD_SPID,
			PRO.TEXT_COMMENT_FIELD,
			PRO.SPID,
			PRO.CREATED_DATE,
			PRO.LAST_UPDATED_ON,
			PRO.TRANSACTION_UNIQUE_ID,
			PRO.FK_TRANSACTION_STATUS_ID,
			PRO.FK_MOSL_MESSAGE_ID,
			PRO.REQUEST_ID,
			PRO.BUSINESS_NAME,
			PRO.CUSTOMER_BANNER_NAME,
			PRO.BILLING_ADDRESS_BUILDING_NAME,
			PRO.BILLING_ADDRESS_LINE_1,
			PRO.BILLING_ADDRESS_LINE_2,
			PRO.BILLING_ADDRESS_LINE_3,
			PRO.BILLING_ADDRESS_LINE_4,
			PRO.BILLING_ADDRESS_LINE_5,
			PRO.BILLING_ADDRESS_POSTCODE,
			PRO.CONTACT_NAME,
			PRO.CONTACT_EMAIL,
			PRO.CONTACT_NUMBER,
			PRO.HASH_VALUE
			FROM [process].[TXN_T101W] AS PRO
			LEFT JOIN DBO.E_TXN_T101_WHOLESALER AS DBO
			ON ISNULL(DBO.SPID, '') = PRO.SPID
			AND ISNULL(DBO.TRANSACTION_UNIQUE_ID, '') = PRO.TRANSACTION_UNIQUE_ID
			AND ISNULL(DBO.LAST_UPDATED_ON, '1900-01-01 00:00:00.000') = PRO.LAST_UPDATED_ON
			AND ISNULL(DBO.REQUEST_ID, '') = PRO.REQUEST_ID
			WHERE DBO.SPID IS NULL
			AND DBO.TRANSACTION_UNIQUE_ID IS NULL
			AND DBO.LAST_UPDATED_ON IS NULL
			AND DBO.REQUEST_ID IS NULL;
			
			SET @Inserts = @@ROWCOUNT;
------------------------------------------------------------------------------------------------------------------------------
        /* Insert to Audit Table */
        UPDATE [sqlmi-dev-dp-cex-control-db].dbo.Load_Audit
        SET Staged_Rows = @Staged,
            New_Rows = @Inserts,
            Updated_Rows = @Updates,
            Deleted_Rows = @Deletes,
            Error_Rows = @Errors,
            Unchanged_Rows = @Unchanged,
            Load_ErrorMsg = CASE
                                WHEN Load_ErrorMsg = '' THEN
                                    ''
                                ELSE
                                    'Resolved on ' + FORMAT(GETDATE(), 'dd/MM/yyyy a   hh:mmtt') + ' - '
                                    + Load_ErrorMsg
                            END
        WHERE LoadID = @LoadID
        COMMIT TRANSACTION
    END TRY
    BEGIN CATCH
        ROLLBACK;
        /* Insert error message to Audit Table */
        UPDATE [sqlmi-dev-dp-cex-control-db].dbo.Load_Audit
        SET Load_ErrorMsg = ERROR_MESSAGE()
        WHERE LoadID = @LoadID
    END CATCH
    /* Revert entire process if failure */
    IF @@TRANCOUNT > 0
        ROLLBACK;
END
GO
