CREATE OR ALTER     PROCEDURE [stg].[sp_UPDATE_TXN_T102_MARKET_OPERATOR] @LoadID BIGINT
AS
BEGIN
    SET XACT_ABORT ON;
    SET NOCOUNT ON;
    DECLARE @Inserts BIGINT = 0,
            @Updates BIGINT = 0,
            @Errors BIGINT = 0,
            @Unchanged BIGINT = 0,
            @Deletes BIGINT = 0,
            @OriginalRowCount BIGINT = 0,
            @Staged BIGINT = 0,
            @RowsAffected BIGINT = 0,
            @masterRunID VARCHAR(100) = '',
            @TodayDT DATETIME2(3) = GETUTCDATE(),
            @Today DATE = GETUTCDATE(),
            @Yesterday DATE = TRY_CONVERT(DATE, DATEADD(DAY, -1, GETUTCDATE())),
            @EOM INT = DATEPART(DAY, GETUTCDATE()),
            @LoadDate DATE = GETUTCDATE();

    BEGIN TRY
        BEGIN TRANSACTION
------------------------------------------------------------------------------------------------------------------------------		
	TRUNCATE TABLE [process].[TXN_T102M]
	INSERT INTO [process].[TXN_T102M]
           ([SPID]
           ,[PAIRING_REFERENCE]
           ,[FK_PAIRING_REFERENCE_REASON_ID]
           ,[FK_NEW_CONNECTION_TYPE_ID]
           ,[FK_GAP_SITE_ALLOCATION_METHOD_ID]
           ,[FK_VOA_BA_REFERENCE_REASON_ID]
           ,[FK_WHOLESALER_ID]
           ,[FK_UPRN_REASON_ID]
           ,[FK_RETAILER_ID]
           ,[VOA_BA_REFERENCE]
           ,[UPRN]
           ,[FREE_DESCRIPTOR]
           ,[PRIMARY_ADDRESSABLE_OBJECT]
           ,[SECONDARY_ADDRESSABLE_OBJECT]
           ,[ADDRESS_LINE_1]
           ,[ADDRESS_LINE_2]
           ,[ADDRESS_LINE_3]
           ,[ADDRESS_LINE_4]
           ,[ADDRESS_LINE_5]
           ,[POSTCODE]
           ,[PAF_ADDRESS_KEY]
           ,[FLG_MULTIPLE_WHOLESALERS]
           ,[LANDLORD_SPID]
           ,[TEXT_COMMENT_FIELD]
           ,[TRANSACTION_UNIQUE_ID]
           ,[CREATED_DATE]
           ,[LAST_UPDATED_ON]
           ,[FK_TRANSACTION_STATUS_ID]
           ,[FLG_DMS_SYNC]
           ,[REQUEST_ID]
           ,[BUSINESS_NAME]
           ,[CUSTOMER_BANNER_NAME]
           ,[BILLING_ADDRESS_BUILDING_NAME]
           ,[BILLING_ADDRESS_LINE_1]
           ,[BILLING_ADDRESS_LINE_2]
           ,[BILLING_ADDRESS_LINE_3]
           ,[BILLING_ADDRESS_LINE_4]
           ,[BILLING_ADDRESS_LINE_5]
           ,[BILLING_ADDRESS_POSTCODE]
           ,[CONTACT_NAME]
           ,[CONTACT_EMAIL]
           ,[CONTACT_NUMBER]
           ,[HASH_VALUE])

	SELECT
            ISNULL(TRY_CONVERT(VARCHAR(16), SRC.[D2001_SPID]), '') AS [SPID],
            ISNULL(TRY_CONVERT(INT, SRC.[D2009_Pairing_Reference]), 0) AS [PAIRING_REFERENCE],
            ISNULL(TRY_CONVERT(TINYINT, PAIR.[PAIRING_REFERENCE_REASON_ID]), 0) AS [FK_PAIRING_REFERENCE_REASON_ID],
            ISNULL(TRY_CONVERT(TINYINT, NEW.[NEW_CONNECTION_TYPE_ID]), 0) AS [FK_NEW_CONNECTION_TYPE_ID],
            ISNULL(TRY_CONVERT(TINYINT, GAP.[GAP_SITE_ALLOCATION_ID]), 0) AS [FK_GAP_SITE_ALLOCATION_METHOD_ID],
            ISNULL(TRY_CONVERT(TINYINT, VOA.[VOA_BA_REASON_ID]), 0) AS [FK_VOA_BA_REFERENCE_REASON_ID],
            ISNULL(TRY_CONVERT(TINYINT, WHOLE.[WHOLESALER_ID]), 0) AS [FK_WHOLESALER_ID],
            ISNULL(TRY_CONVERT(TINYINT, UPR.[UPRN_REASON_ID]), 0) AS [FK_UPRN_REASON_ID],
            ISNULL(TRY_CONVERT(TINYINT, RET.[WATER_RETAILER_ID]), 0) AS [FK_RETAILER_ID],
            ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[D2037_VOA_BA_Reference]), '') AS [VOA_BA_REFERENCE],
            ISNULL(TRY_CONVERT(NUMERIC(20,0), SRC.[D2039_UPRN]), 0) AS [UPRN],
            ISNULL(TRY_CONVERT(VARCHAR(128), SRC.[D5001_Free_Descriptor]), '') AS [FREE_DESCRIPTOR],
            ISNULL(TRY_CONVERT(VARCHAR(128), SRC.[D5003_Primary_Addressable_Object]), '') AS [PRIMARY_ADDRESSABLE_OBJECT],
