    INNER JOIN DBO.D_VOA_BA_REFERENCE_REASON AS VOA
    ON ISNULL(TRIM(SRC.[D2038_VOA_BA_Reference_Reason_Code]), '') = VOA.VOA_BA_REASON_CODE 
    INNER JOIN DBO.D_WHOLESALER AS WHOLE
    ON ISNULL(TRIM(SRC.[D4025_Wholesaler_ID]), '') = WHOLE.WHOLESALER_CODE 
    INNER JOIN DBO.D_UPRN_REASON_CODE AS UPR
    ON ISNULL(TRIM(SRC.[D2040_UPRN_Reason_Code]), '') = UPR.UPRN_REASON_CODE 
    INNER JOIN DBO.D_WATER_RETAILER_ID AS RET
    ON ISNULL(TRIM(SRC.[D4011_Retailer_ID]), '') = RET.WATER_RETAILER_CODE
    INNER JOIN DBO.D_TRANSACTION_STATUS AS TRANSACT
    ON ISNULL(TRIM(SRC.[Transaction_Status]), '') = TRANSACT.TRANSACTION_STATUS;
