            PRO.ADDRESS_LINE_1,
            PRO.ADDRESS_LINE_2,
            PRO.ADDRESS_LINE_3,
            PRO.ADDRESS_LINE_4,
            PRO.ADDRESS_LINE_5,
            PRO.POSTCODE,
            PRO.PAF_ADDRESS_KEY,
            PRO.FLG_MULTIPLE_WHOLESALERS,
            PRO.LANDLORD_SPID,
            PRO.TEXT_COMMENT_FIELD,
            PRO.TRANSACTION_UNIQUE_ID,
            PRO.CREATED_DATE,
            PRO.LAST_UPDATED_ON,
            PRO.FK_TRANSACTION_STATUS_ID,
            PRO.FLG_DMS_SYNC,
            PRO.REQUEST_ID,
            PRO.BUSINESS_NAME,
            PRO.CUSTOMER_BANNER_NAME,
            PRO.BILLING_ADDRESS_BUILDING_NAME,
            PRO.BILLING_ADDRESS_LINE_1,
            PRO.BILLING_ADDRESS_LINE_2,
            PRO.BILLING_ADDRESS_LINE_3,
            PRO.BILLING_ADDRESS_LINE_4,
            PRO.BILLING_ADDRESS_LINE_5,
            PRO.BILLING_ADDRESS_POSTCODE,
            PRO.CONTACT_NAME,
            PRO.CONTACT_EMAIL,
            PRO.CONTACT_NUMBER,
            PRO.HASH_VALUE
			FROM [process].[TXN_T102M] AS PRO
			LEFT JOIN DBO.[E_TXN_T102_MARKET_OPERATOR] AS DBO
			ON ISNULL(DBO.SPID, '') = PRO.SPID
			AND ISNULL(DBO.TRANSACTION_UNIQUE_ID, '') = PRO.TRANSACTION_UNIQUE_ID
			AND ISNULL(DBO.LAST_UPDATED_ON, '1900-01-01 00:00:00.000') = PRO.LAST_UPDATED_ON
			AND ISNULL(DBO.REQUEST_ID, '') = PRO.REQUEST_ID
			WHERE DBO.SPID IS NULL
			AND DBO.TRANSACTION_UNIQUE_ID IS NULL
			AND DBO.LAST_UPDATED_ON IS NULL
			AND DBO.REQUEST_ID IS NULL;
			
			SET @Inserts = @@ROWCOUNT;
------------------------------------------------------------------------------------------------------------------------------
        /* Insert to Audit Table */
        UPDATE [sqlmi-dev-dp-cex-control-db].dbo.Load_Audit
        SET Staged_Rows = @Staged,
            New_Rows = @Inserts,
            Updated_Rows = @Updates,
            Deleted_Rows = @Deletes,
            Error_Rows = @Errors,
            Unchanged_Rows = @Unchanged,
            Load_ErrorMsg = CASE
                                WHEN Load_ErrorMsg = '' THEN
                                    ''
                                ELSE
                                    'Resolved on ' + FORMAT(GETDATE(), 'dd/MM/yyyy a   hh:mmtt') + ' - '
                                    + Load_ErrorMsg
                            END
        WHERE LoadID = @LoadID
        COMMIT TRANSACTION
    END TRY
    BEGIN CATCH
        ROLLBACK;
        /* Insert error message to Audit Table */
        UPDATE [sqlmi-dev-dp-cex-control-db].dbo.Load_Audit
        SET Load_ErrorMsg = ERROR_MESSAGE()
        WHERE LoadID = @LoadID
    END CATCH
    /* Revert entire process if failure */
    IF @@TRANCOUNT > 0
        ROLLBACK;
END
