           ,[GISY]
           ,[METER_LOCATION_FREE_DESCRIPTOR]
           ,[METER_OUTREADER_GISX]
           ,[METER_OUTREADER_GISY]
           ,[METER_OUTREADER_LOCATION_FREE_DESCRIPTOR]
           ,[METER_TREATMENT]
           ,[FK_METER_LOCATION_ID]
           ,[FK_METER_OUTREADER_LOCATION_ID]
           ,[FLG_COMBI_METER]
           ,[FLG_REMOTE_READ]
           ,[FK_REMOTE_READ_TYPE_ID]
           ,[OUTREADER_ID]
           ,[OUTREADER_PROTOCOL]
