           ,[METER_READ]
           ,[METER_READ_DATE]
           ,[FK_METER_READ_TYPE_ID]
           ,[FK_METER_READ_METHOD_ID]
           ,[FK_METER_ADDITION_REASON_ID]
           ,[FREE_DESCRIPTOR]
           ,[PRIMARY_ADDRESSABLE_OBJECT]
           ,[SECONDARY_ADDRESSABLE_OBJECT]
           ,[ADDRESS_LINE_1]
           ,[ADDRESS_LINE_2]
           ,[ADDRESS_LINE_3]
           ,[ADDRESS_LINE_4]
           ,[ADDRESS_LINE_5]
           ,[POSTCODE]
           ,[PAF_ADDRESS_KEY]
           ,[TEXT_COMMENT_FIELD]
           ,[CREATED_DATE]
           ,[LAST_UPDATED_ON]
           ,[TRANSACTION_UNIQUE_ID]
           ,[FK_TRANSACTION_STATUS_ID]
           ,[FLG_DMS_SYNC]
           ,[REQUEST_ID]
           ,[HASH_VALUE])

	SELECT
            ISNULL(TRY_CONVERT(VARCHAR(16), SRC.[D2001_SPID]), '') AS [SPID],
            ISNULL(TRY_CONVERT(SMALLINT, METER.METER_MANUFACTURER_ID), 0) AS [FK_METER_MANUFACTURER_ID],
            ISNULL(TRY_CONVERT(VARCHAR(50), SRC.[D3014_Manufacturer_Meter_Serial_Number]), '') AS [MANUFACTURER_METER_SERIAL_NUMBER],
            ISNULL(TRY_CONVERT(TINYINT, SRC.[D3004_Number_of_Digits]), 0) AS [NUMBER_OF_DIGITS],
            ISNULL(TRY_CONVERT(TINYINT, MEASURE.METER_MEASUREMENT_UNIT_ID), 0) AS [FK_MEASUREMENT_UNITS_AT_METER_ID],
            ISNULL(TRY_CONVERT(TINYINT, MEASUREMENT.[MEASUREMENT_UNITS_FREE_DESCRIPTOR_ID]), 0) AS [FK_MEASUREMENT_UNITS_FREE_DESCRIPTOR_ID],
            ISNULL(TRY_CONVERT(SMALLINT, SRC.D3003_Physical_Meter_Size), 0) AS [PHYSICAL_METER_SIZE_MM],
            ISNULL(TRY_CONVERT(SMALLINT, SRC.D3002_Water_Chargeable_Meter_Size), 0) AS [WATER_CHARGEABLE_METER_SIZE_MM],
            ISNULL(TRY_CONVERT(TINYINT, FREQ.METER_READ_MIN_FREQUENCY_ID), 0) AS [FK_METER_READ_MINIMUM_FREQUENCY_ID],
            ISNULL(TRY_CONVERT(NUMERIC(5,2), SRC.[D3007_Return_to_Sewer]), 0.00) AS [RETURN_TO_SEWER],
            ISNULL(TRY_CONVERT(SMALLINT, SRC.D3005_Sewerage_Chargeable_Meter_Size), 0) AS [SEWERAGE_CHARGEABLE_METER_SIZE_MM],
            ISNULL(TRY_CONVERT(BIT, SRC.[D3015_Datalogger_Wholesaler]), 0) AS [FLG_DATALOGGER_WHOLESALER],
            ISNULL(TRY_CONVERT(BIT, SRC.[D3016_Datalogger_NonWholesaler]), 0) AS [FLG_DATALOGGER_NON_WHOLESALER],
            ISNULL(TRY_CONVERT(NUMERIC(8,1), SRC.[D3017_GISX]), 0.0) AS [GISX],
            ISNULL(TRY_CONVERT(NUMERIC(8,1), SRC.[D3018_GISY]), 0.0) AS [GISY],
            ISNULL(TRY_CONVERT(VARCHAR(256), SRC.[D3019_Meter_Location_Free_Descriptor]), '') AS [METER_LOCATION_FREE_DESCRIPTOR],
            ISNULL(TRY_CONVERT(NUMERIC(8,1), SRC.[D3030_Meter_Outreader_GISX]), 0.0) AS [METER_OUTREADER_GISX],
            ISNULL(TRY_CONVERT(NUMERIC(8,1), SRC.[D3031_Meter_Outreader_GISY]), 0.0) AS [METER_OUTREADER_GISY],
            ISNULL(TRY_CONVERT(VARCHAR(256), SRC.[D3032_Meter_Outreader_Location_Free_Descriptor]), '') AS [METER_OUTREADER_LOCATION_FREE_DESCRIPTOR],
            ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[D3022_Meter_Treatment]), '') AS [METER_TREATMENT],
            ISNULL(TRY_CONVERT(TINYINT, LOCA.METER_LOCATION_ID), 0) AS [FK_METER_LOCATION_ID],
            ISNULL(TRY_CONVERT(TINYINT, OUT.METER_LOCATION_ID), 0) AS [FK_METER_OUTREADER_LOCATION_ID],
            ISNULL(TRY_CONVERT(BIT, SRC.[D3034_Combi_Meter_Flag]), 0) AS [FLG_COMBI_METER],
            ISNULL(TRY_CONVERT(BIT, SRC.[D3037_Remote_Read_Flag]), 0) AS [FLG_REMOTE_READ],
            ISNULL(TRY_CONVERT(TINYINT, REMOTE.REMOTE_READ_ID), 0) AS [FK_REMOTE_READ_TYPE_ID],
            ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[D3039_Outreader_ID]), '') AS [OUTREADER_ID],
            ISNULL(TRY_CONVERT(VARCHAR(512), SRC.[D3040_Outreader_Protocol]), '') AS [OUTREADER_PROTOCOL],
            ISNULL(TRY_CONVERT(INT, SRC.[D2010_Yearly_Volume_Estimate]), 0) AS [YEARLY_VOLUME_ESTIMATE],
            ISNULL(TRY_CONVERT(INT, SRC.[D3008_Meter_Read]), 0) AS [METER_READ],
            ISNULL(TRY_CONVERT(DATE, SRC.[D3009_Meter_Read_Date]), '1900-01-01') AS [METER_READ_DATE],
            ISNULL(TRY_CONVERT(TINYINT, TYPE.METER_READ_TYPE_ID), 0) AS [FK_METER_READ_TYPE_ID],
            ISNULL(TRY_CONVERT(TINYINT, METHOD.STAGING_METER_READ_METHOD_ID), 0) AS [FK_METER_READ_METHOD_ID],
            ISNULL(TRY_CONVERT(TINYINT, ADDITION.METER_ADDITION_REASON_ID), 0) AS [FK_METER_ADDITION_REASON_ID],
            ISNULL(TRY_CONVERT(VARCHAR(128), SRC.[D5001_Free_Descriptor]), '') AS [FREE_DESCRIPTOR],
            ISNULL(TRY_CONVERT(VARCHAR(128), SRC.[D5003_Primary_Addressable_Object]), '') AS [PRIMARY_ADDRESSABLE_OBJECT],
            ISNULL(TRY_CONVERT(VARCHAR(128), SRC.[D5002_Secondary_Addressable_Object]), '') AS [SECONDARY_ADDRESSABLE_OBJECT],
            ISNULL(TRY_CONVERT(VARCHAR(128), SRC.[D5004_Address_Line_1]), '') AS [ADDRESS_LINE_1],
            ISNULL(TRY_CONVERT(VARCHAR(64), SRC.[D5005_Address_Line_2]), '') AS [ADDRESS_LINE_2],
            ISNULL(TRY_CONVERT(VARCHAR(64), SRC.[D5006_Address_Line_3]), '') AS [ADDRESS_LINE_3],
            ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[D5007_Address_Line_4]), '') AS [ADDRESS_LINE_4],
            ISNULL(TRY_CONVERT(VARCHAR(16), SRC.[D5008_Address_Line_5]), '') AS [ADDRESS_LINE_5],
            ISNULL(TRY_CONVERT(VARCHAR(16), SRC.[D5009_Postcode]), '') AS [POSTCODE],
            ISNULL(TRY_CONVERT(INT, SRC.[D5011_PAF_Address_Key]), 0) AS [PAF_ADDRESS_KEY],
            ISNULL(TRY_CONVERT(VARCHAR(512), SRC.[D4003_Text_Comment_Field]), '') AS [TEXT_COMMENT_FIELD],
            ISNULL(TRY_CONVERT(DATE, SRC.[CreatedOn]), '1900-01-01') AS [CREATED_DATE],
            ISNULL(TRY_CONVERT(DATETIME2(3), SRC.[LastUpdatedOn]), '1900-01-01 00:00:00.000') AS [LAST_UPDATED_ON],
            ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[Transaction_Unique_ID]), '') AS [TRANSACTION_UNIQUE_ID],
            ISNULL(TRY_CONVERT(TINYINT, TRANSACT.[TRANSACTION_STATUS_ID]), 0) AS [FK_TRANSACTION_STATUS_ID],
            ISNULL(TRY_CONVERT(BIT, CASE 
                                        WHEN SRC.[DMS_Sync_Flag] = 'Y' THEN 1 
                                        WHEN SRC.[DMS_Sync_Flag] = 'B' THEN 0 
                                        END), 0) AS [FLG_DMS_SYNC],
            ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[Request_ID]), '') AS [REQUEST_ID],
		    HASHBYTES(
                        'sha1',
                            CONCAT_WS('|',
									ISNULL(TRY_CONVERT(SMALLINT, METER.METER_MANUFACTURER_ID), 0),
                                    ISNULL(TRY_CONVERT(VARCHAR(50), SRC.[D3014_Manufacturer_Meter_Serial_Number]), ''),
                                    ISNULL(TRY_CONVERT(TINYINT, SRC.[D3004_Number_of_Digits]), 0),
                                    ISNULL(TRY_CONVERT(TINYINT, MEASURE.METER_MEASUREMENT_UNIT_ID), 0),
                                    ISNULL(TRY_CONVERT(TINYINT, MEASUREMENT.[MEASUREMENT_UNITS_FREE_DESCRIPTOR_ID]), 0),
                                    ISNULL(TRY_CONVERT(SMALLINT, SRC.D3003_Physical_Meter_Size), 0),
                                    ISNULL(TRY_CONVERT(SMALLINT, SRC.D3002_Water_Chargeable_Meter_Size), 0),
                                    ISNULL(TRY_CONVERT(TINYINT, FREQ.METER_READ_MIN_FREQUENCY_ID), 0),
                                    ISNULL(TRY_CONVERT(NUMERIC(5,2), SRC.[D3007_Return_to_Sewer]), 0.00),
                                    ISNULL(TRY_CONVERT(SMALLINT, SRC.D3005_Sewerage_Chargeable_Meter_Size), 0),
                                    ISNULL(TRY_CONVERT(BIT, SRC.[D3015_Datalogger_Wholesaler]), 0),
                                    ISNULL(TRY_CONVERT(BIT, SRC.[D3016_Datalogger_NonWholesaler]), 0),
                                    ISNULL(TRY_CONVERT(NUMERIC(8,1), SRC.[D3017_GISX]), 0.0),
                                    ISNULL(TRY_CONVERT(NUMERIC(8,1), SRC.[D3018_GISY]), 0.0),
                                    ISNULL(TRY_CONVERT(VARCHAR(256), SRC.[D3019_Meter_Location_Free_Descriptor]), ''),
                                    ISNULL(TRY_CONVERT(NUMERIC(8,1), SRC.[D3030_Meter_Outreader_GISX]), 0.0),
                                    ISNULL(TRY_CONVERT(NUMERIC(8,1), SRC.[D3031_Meter_Outreader_GISY]), 0.0),
                                    ISNULL(TRY_CONVERT(VARCHAR(256), SRC.[D3032_Meter_Outreader_Location_Free_Descriptor]), ''),
                                    ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[D3022_Meter_Treatment]), ''),
                                    ISNULL(TRY_CONVERT(TINYINT, LOCA.METER_LOCATION_ID), 0),
                                    ISNULL(TRY_CONVERT(TINYINT, OUT.METER_LOCATION_ID), 0),
                                    ISNULL(TRY_CONVERT(BIT, SRC.[D3034_Combi_Meter_Flag]), 0),
                                    ISNULL(TRY_CONVERT(BIT, SRC.[D3037_Remote_Read_Flag]), 0),
                                    ISNULL(TRY_CONVERT(TINYINT, REMOTE.REMOTE_READ_ID), 0),
                                    ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[D3039_Outreader_ID]), ''),
                                    ISNULL(TRY_CONVERT(VARCHAR(512), SRC.[D3040_Outreader_Protocol]), ''),
                                    ISNULL(TRY_CONVERT(INT, SRC.[D2010_Yearly_Volume_Estimate]), 0),
                                    ISNULL(TRY_CONVERT(INT, SRC.[D3008_Meter_Read]), 0),
                                    ISNULL(TRY_CONVERT(DATE, SRC.[D3009_Meter_Read_Date]), '1900-01-01'),
                                    ISNULL(TRY_CONVERT(TINYINT, TYPE.METER_READ_TYPE_ID), 0),
                                    ISNULL(TRY_CONVERT(TINYINT, METHOD.STAGING_METER_READ_METHOD_ID), 0),
                                    ISNULL(TRY_CONVERT(TINYINT, ADDITION.METER_ADDITION_REASON_ID), 0),
                                    ISNULL(TRY_CONVERT(VARCHAR(128), SRC.[D5001_Free_Descriptor]), ''),
                                    ISNULL(TRY_CONVERT(VARCHAR(128), SRC.[D5003_Primary_Addressable_Object]), ''),
                                    ISNULL(TRY_CONVERT(VARCHAR(128), SRC.[D5002_Secondary_Addressable_Object]), ''),
                                    ISNULL(TRY_CONVERT(VARCHAR(128), SRC.[D5004_Address_Line_1]), ''),
                                    ISNULL(TRY_CONVERT(VARCHAR(64), SRC.[D5005_Address_Line_2]), ''),
                                    ISNULL(TRY_CONVERT(VARCHAR(64), SRC.[D5006_Address_Line_3]), ''),
                                    ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[D5007_Address_Line_4]), ''),
                                    ISNULL(TRY_CONVERT(VARCHAR(16), SRC.[D5008_Address_Line_5]), ''),
                                    ISNULL(TRY_CONVERT(VARCHAR(16), SRC.[D5009_Postcode]), ''),
                                    ISNULL(TRY_CONVERT(INT, SRC.[D5011_PAF_Address_Key]), 0),
                                    ISNULL(TRY_CONVERT(VARCHAR(512), SRC.[D4003_Text_Comment_Field]), ''),
                                    ISNULL(TRY_CONVERT(DATE, SRC.[CreatedOn]), '1900-01-01'),
                                    ISNULL(TRY_CONVERT(DATETIME2(3), SRC.[LastUpdatedOn]), '1900-01-01 00:00:00.000'),
                                    ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[Transaction_Unique_ID]), ''),
                                    ISNULL(TRY_CONVERT(TINYINT, TRANSACT.[TRANSACTION_STATUS_ID]), 0),
                                    ISNULL(TRY_CONVERT(BIT, CASE 
                                                                WHEN SRC.[DMS_Sync_Flag] = 'Y' THEN 1 
                                                                WHEN SRC.[DMS_Sync_Flag] = 'B' THEN 0 
                                                                END), 0)
									))
									AS [HASH_VALUE]
    FROM [STG].[DMS_TXN_T104M] AS SRC
    INNER JOIN dbo.D_METER_MANUFACTURER AS METER
    ON ISNULL(TRIM(SRC.[D3013_Meter_Manufacturer]), '') = METER.METER_MANUFACTURER_DESCRIPTION 
    INNER JOIN DBO.D_METER_MEASUREMENT_UNIT AS MEASURE
    ON ISNULL(TRIM(SRC.[D3036_Measurement_Units_at_Meter]), '') = MEASURE.METER_MEASUREMENT_UNIT_CODE 
    INNER JOIN DBO.D_METER_READ_MINIMUM_FREQUENCY AS FREQ
    ON ISNULL(TRIM(SRC.[D3011_Meter_Read_Minimum_Frequency]), '') = FREQ.METER_READ_MIN_FREQUENCY_CODE 
    INNER JOIN DBO.D_METER_LOCATION_CODE AS LOCA
    ON ISNULL(TRIM(SRC.[D3025_Meter_Location_Code]), '') = LOCA.METER_LOCATION_CODE
    INNER JOIN DBO.D_METER_LOCATION_CODE AS OUT
    ON ISNULL(TRIM(SRC.[D3033_Meter_Outreader_Location_Code]), '') = OUT.METER_LOCATION_CODE 
    INNER JOIN DBO.D_REMOTE_READ_TYPE AS REMOTE
    ON ISNULL(TRIM(SRC.[D3038_Remote_Read_Type]), '') = REMOTE.REMOTE_READ_CODE
    INNER JOIN DBO.D_STAGING_METER_READ_TYPE AS TYPE
    ON ISNULL(TRIM(SRC.[D3010_Meter_Read_Type]), '') = TYPE.METER_READ_TYPE_CODE
    INNER JOIN DBO.D_STAGING_METER_READ_METHOD AS METHOD
    ON ISNULL(TRIM(SRC.[D3044_Meter_Read_Method]), '') = METHOD.METER_READ_METHOD_DESCRIPTION
    INNER JOIN DBO.D_METER_ADDITION_REASON AS ADDITION
    ON ISNULL(TRIM(SRC.[D3045_Meter_Addition_Reason]), '') = ADDITION.METER_ADDITION_REASON_CODE
    INNER JOIN DBO.D_TRANSACTION_STATUS AS TRANSACT
    ON ISNULL(TRIM(SRC.[Transaction_Status]), '') = TRANSACT.TRANSACTION_STATUS
    INNER JOIN DBO.D_MEASUREMENT_UNITS_FREE_DESCRIPTOR AS MEASUREMENT
    ON ISNULL(TRIM(SRC.[D3035_Measurement_Units_Free_Descriptor]), '') = MEASUREMENT.MEASUREMENT_UNITS_FREE_DESCRIPTOR;

