                        'sha1',
                            CONCAT_WS('|',
                                ISNULL(TRY_CONVERT(SMALLINT, METER.METER_MANUFACTURER_ID), 0),
                                ISNULL(TRY_CONVERT(VARCHAR(50), SRC.[D3014_Manufacturer_Meter_Serial_Number]), ''),
                                ISNULL(TRY_CONVERT(DATE, SRC.[D4006_Effective_From_Date]), '1900-01-01'),
                                ISNULL(TRY_CONVERT(TINYINT, FREQ.[METER_READ_MIN_FREQUENCY_ID]), 0),
                                ISNULL(TRY_CONVERT(SMALLINT, SRC.[D3003_Physical_Meter_Size]), 0),
                                ISNULL(TRY_CONVERT(BIT, SRC.[D3015_Datalogger_Wholesaler]), 0),
                                ISNULL(TRY_CONVERT(BIT, SRC.[D3016_Datalogger_NonWholesaler]), 0),
                                ISNULL(TRY_CONVERT(NUMERIC(8,1), SRC.[D3017_GISX]), 0.0),
                                ISNULL(TRY_CONVERT(NUMERIC(8,1), SRC.[D3018_GISY]), 0.0),
                                ISNULL(TRY_CONVERT(TINYINT, LOCA.[METER_LOCATION_ID]), 0),
                                ISNULL(TRY_CONVERT(NUMERIC(8,1), SRC.[D3030_Meter_Outreader_GISX]), 0.0),
                                ISNULL(TRY_CONVERT(NUMERIC(8,1), SRC.[D3031_Meter_Outreader_GISY]), 0.0),
                                ISNULL(TRY_CONVERT(TINYINT, OUT.[METER_LOCATION_ID]), 0),
                                ISNULL(TRY_CONVERT(BIT, SRC.[D3034_Combi_Meter_Flag]), 0),
                                ISNULL(TRY_CONVERT(BIT, SRC.[D3037_Remote_Read_Flag]), 0),
                                ISNULL(TRY_CONVERT(TINYINT, REMOTE.REMOTE_READ_ID), 0),
                                ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[D3039_Outreader_ID]), ''),
                                ISNULL(TRY_CONVERT(VARCHAR(512), SRC.[D3040_Outreader_Protocol]), ''),
                                ISNULL(TRY_CONVERT(VARCHAR(512), SRC.[D4003_Text_Comment_Field]), ''),
                                ISNULL(TRY_CONVERT(VARCHAR(128), SRC.[D5001_Free_Descriptor]), ''),
                                ISNULL(TRY_CONVERT(VARCHAR(128), SRC.[D5003_Primary_Addressable_Object]), ''),
                                ISNULL(TRY_CONVERT(VARCHAR(128), SRC.[D5002_Secondary_Addressable_Object]), ''),
                                ISNULL(TRY_CONVERT(VARCHAR(128), SRC.[D5004_Address_Line_1]), ''),
                                ISNULL(TRY_CONVERT(VARCHAR(64), SRC.[D5005_Address_Line_2]), ''),
                                ISNULL(TRY_CONVERT(VARCHAR(64), SRC.[D5006_Address_Line_3]), ''),
                                ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[D5007_Address_Line_4]), ''),
                                ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[D5008_Address_Line_5]), ''),
                                ISNULL(TRY_CONVERT(VARCHAR(16), SRC.[D5009_Postcode]), ''),
                                ISNULL(TRY_CONVERT(INT, SRC.[D5011_PAF_Address_Key]), 0),
                                ISNULL(TRY_CONVERT(DATE, SRC.[CreatedOn]), '1900-01-01'),
                                ISNULL(TRY_CONVERT(DATETIME2(3), SRC.[LastUpdatedOn]), '1900-01-01 00:00:00.000'),
                                ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[Transaction_Unique_ID]), ''),
                                ISNULL(TRY_CONVERT(TINYINT, TRANSACT.[TRANSACTION_STATUS_ID]), 0),
                                ISNULL(TRY_CONVERT(TINYINT, MOSL.[MOSL_MESSAGE_ID]), 0)
									))
									AS [HASH_VALUE]
    FROM [STG].[DMS_TXN_T113W] AS SRC
    INNER JOIN dbo.D_METER_MANUFACTURER AS METER
    ON ISNULL(TRIM(SRC.[D3013_Meter_Manufacturer]), '') = METER.METER_MANUFACTURER_DESCRIPTION
    INNER JOIN DBO.D_METER_READ_MINIMUM_FREQUENCY AS FREQ
    ON ISNULL(TRIM(SRC.[D3011_Meter_Read_Minimum_Frequency]), '') = FREQ.METER_READ_MIN_FREQUENCY_CODE
    INNER JOIN DBO.D_METER_LOCATION_CODE AS LOCA
    ON ISNULL(TRIM(SRC.[D3025_Meter_Location_Code]), '') = LOCA.METER_LOCATION_CODE
    INNER JOIN DBO.D_METER_LOCATION_CODE AS OUT
    ON ISNULL(TRIM(SRC.[D3033_Meter_Outreader_Location_Code]), '') = OUT.METER_LOCATION_CODE 
    INNER JOIN DBO.D_REMOTE_READ_TYPE AS REMOTE
    ON ISNULL(TRIM(SRC.[D3038_Remote_Read_Type]), '') = REMOTE.REMOTE_READ_CODE
    INNER JOIN DBO.D_MOSL_MESSAGE AS MOSL
	ON ISNULL(TRIM(SRC.[MOSL_Message]), '') = MOSL.MOSL_MESSAGE_CODE
    INNER JOIN DBO.D_TRANSACTION_STATUS AS TRANSACT
    ON ISNULL(TRIM(SRC.[Transaction_Status]), '') = TRANSACT.TRANSACTION_STATUS;

------------------------------------------------------------------------------------------------------------------------------
	UPDATE DBO
	SET 
    DBO.FK_METER_MANUFACTURER_ID = PRO.FK_METER_MANUFACTURER_ID,
    DBO.MANUFACTURER_METER_SERIAL_NUMBER = PRO.MANUFACTURER_METER_SERIAL_NUMBER,
    DBO.EFFECTIVE_FROM_DATE = PRO.EFFECTIVE_FROM_DATE,
    DBO.FK_METER_READ_MINIMUM_FREQUENCY_ID = PRO.FK_METER_READ_MINIMUM_FREQUENCY_ID,
    DBO.PHYSICAL_METER_SIZE_MM = PRO.PHYSICAL_METER_SIZE_MM,
    DBO.FLG_DATALOGGER_WHOLESALER = PRO.FLG_DATALOGGER_WHOLESALER,
    DBO.FLG_DATALOGGER_NON_WHOLESALER = PRO.FLG_DATALOGGER_NON_WHOLESALER,
    DBO.GISX = PRO.GISX,
    DBO.GISY = PRO.GISY,
    DBO.FK_METER_LOCATION_ID = PRO.FK_METER_LOCATION_ID,
    DBO.METER_OUTREADER_GISX = PRO.METER_OUTREADER_GISX,
    DBO.METER_OUTREADER_GISY = PRO.METER_OUTREADER_GISY,
    DBO.FK_METER_OUTREADER_LOCATION_ID = PRO.FK_METER_OUTREADER_LOCATION_ID,
    DBO.FLG_COMBI_METER = PRO.FLG_COMBI_METER,
    DBO.FLG_REMOTE_READ = PRO.FLG_REMOTE_READ,
    DBO.FK_REMOTE_READ_TYPE_ID = PRO.FK_REMOTE_READ_TYPE_ID,
    DBO.OUTREADER_ID = PRO.OUTREADER_ID,
    DBO.OUTREADER_PROTOCOL = PRO.OUTREADER_PROTOCOL,
    DBO.TEXT_COMMENT_FIELD = PRO.TEXT_COMMENT_FIELD,
    DBO.FREE_DESCRIPTOR = PRO.FREE_DESCRIPTOR,
    DBO.PRIMARY_ADDRESSABLE_OBJECT = PRO.PRIMARY_ADDRESSABLE_OBJECT,
    DBO.SECONDARY_ADDRESSABLE_OBJECT = PRO.SECONDARY_ADDRESSABLE_OBJECT,
    DBO.ADDRESS_LINE_1 = PRO.ADDRESS_LINE_1,
    DBO.ADDRESS_LINE_2 = PRO.ADDRESS_LINE_2,
    DBO.ADDRESS_LINE_3 = PRO.ADDRESS_LINE_3,
    DBO.ADDRESS_LINE_4 = PRO.ADDRESS_LINE_4,
    DBO.ADDRESS_LINE_5 = PRO.ADDRESS_LINE_5,
    DBO.POSTCODE = PRO.POSTCODE,
    DBO.PAF_ADDRESS_KEY = PRO.PAF_ADDRESS_KEY,
    DBO.CREATED_DATE = PRO.CREATED_DATE,
    DBO.LAST_UPDATED_ON = PRO.LAST_UPDATED_ON,
    DBO.TRANSACTION_UNIQUE_ID = PRO.TRANSACTION_UNIQUE_ID,
    DBO.FK_TRANSACTION_STATUS_ID = PRO.FK_TRANSACTION_STATUS_ID,
    DBO.FK_MOSL_MESSAGE_ID = PRO.FK_MOSL_MESSAGE_ID
	FROM [process].[TXN_T113W] AS PRO
	INNER JOIN [dbo].[E_TXN_T113_WHOLESALER] AS DBO
	ON  ISNULL(DBO.SPID, '') = PRO.SPID
	AND ISNULL(DBO.TRANSACTION_UNIQUE_ID, '') = PRO.TRANSACTION_UNIQUE_ID
	AND ISNULL(DBO.LAST_UPDATED_ON, '1900-01-01 00:00:00.000') = PRO.LAST_UPDATED_ON
	AND ISNULL(DBO.CREATED_DATE, '1900-01-01') = PRO.CREATED_DATE
	AND ISNULL(DBO.REQUEST_ID, '') = PRO.REQUEST_ID
	WHERE PRO.HASH_VALUE <> DBO.HASH_VALUE;

	SET @Updates = @@ROWCOUNT;

------------------------------------------------------------------------------------------------------------------------------
	INSERT INTO [dbo].[E_TXN_T113_WHOLESALER]
           ([SPID]
           ,[FK_METER_MANUFACTURER_ID]
           ,[MANUFACTURER_METER_SERIAL_NUMBER]
           ,[EFFECTIVE_FROM_DATE]
           ,[FK_METER_READ_MINIMUM_FREQUENCY_ID]
           ,[PHYSICAL_METER_SIZE_MM]
           ,[FLG_DATALOGGER_WHOLESALER]
           ,[FLG_DATALOGGER_NON_WHOLESALER]
           ,[GISX]
           ,[GISY]
           ,[FK_METER_LOCATION_ID]
           ,[METER_OUTREADER_GISX]
           ,[METER_OUTREADER_GISY]
           ,[FK_METER_OUTREADER_LOCATION_ID]
           ,[FLG_COMBI_METER]
           ,[FLG_REMOTE_READ]
           ,[FK_REMOTE_READ_TYPE_ID]
           ,[OUTREADER_ID]
           ,[OUTREADER_PROTOCOL]
           ,[TEXT_COMMENT_FIELD]
           ,[FREE_DESCRIPTOR]
           ,[PRIMARY_ADDRESSABLE_OBJECT]
           ,[SECONDARY_ADDRESSABLE_OBJECT]
           ,[ADDRESS_LINE_1]
           ,[ADDRESS_LINE_2]
           ,[ADDRESS_LINE_3]
           ,[ADDRESS_LINE_4]
           ,[ADDRESS_LINE_5]
           ,[POSTCODE]
           ,[PAF_ADDRESS_KEY]
           ,[CREATED_DATE]
           ,[LAST_UPDATED_ON]
           ,[TRANSACTION_UNIQUE_ID]
           ,[FK_TRANSACTION_STATUS_ID]
           ,[FK_MOSL_MESSAGE_ID]
           ,[REQUEST_ID]
           ,[HASH_VALUE]) 
		   
	SELECT 
		    PRO.SPID,
            PRO.FK_METER_MANUFACTURER_ID,
            PRO.MANUFACTURER_METER_SERIAL_NUMBER,
            PRO.EFFECTIVE_FROM_DATE,
            PRO.FK_METER_READ_MINIMUM_FREQUENCY_ID,
            PRO.PHYSICAL_METER_SIZE_MM,
            PRO.FLG_DATALOGGER_WHOLESALER,
            PRO.FLG_DATALOGGER_NON_WHOLESALER,
            PRO.GISX,
            PRO.GISY,
            PRO.FK_METER_LOCATION_ID,
            PRO.METER_OUTREADER_GISX,
            PRO.METER_OUTREADER_GISY,
            PRO.FK_METER_OUTREADER_LOCATION_ID,
            PRO.FLG_COMBI_METER,
            PRO.FLG_REMOTE_READ,
            PRO.FK_REMOTE_READ_TYPE_ID,
            PRO.OUTREADER_ID,
            PRO.OUTREADER_PROTOCOL,
            PRO.TEXT_COMMENT_FIELD,
            PRO.FREE_DESCRIPTOR,
            PRO.PRIMARY_ADDRESSABLE_OBJECT,
            PRO.SECONDARY_ADDRESSABLE_OBJECT,
            PRO.ADDRESS_LINE_1,
            PRO.ADDRESS_LINE_2,
            PRO.ADDRESS_LINE_3,
            PRO.ADDRESS_LINE_4,
            PRO.ADDRESS_LINE_5,
            PRO.POSTCODE,
            PRO.PAF_ADDRESS_KEY,
            PRO.CREATED_DATE,
            PRO.LAST_UPDATED_ON,
            PRO.TRANSACTION_UNIQUE_ID,
            PRO.FK_TRANSACTION_STATUS_ID,
            PRO.FK_MOSL_MESSAGE_ID,
            PRO.REQUEST_ID,
            PRO.HASH_VALUE
			FROM [process].[TXN_T113W] AS PRO
			LEFT JOIN [dbo].[E_TXN_T113_WHOLESALER] AS DBO
			ON  ISNULL(DBO.SPID, '') = PRO.SPID
			AND ISNULL(DBO.TRANSACTION_UNIQUE_ID, '') = PRO.TRANSACTION_UNIQUE_ID
			AND ISNULL(DBO.LAST_UPDATED_ON, '1900-01-01 00:00:00.000') = PRO.LAST_UPDATED_ON
			AND ISNULL(DBO.CREATED_DATE, '1900-01-01') = PRO.CREATED_DATE
			AND ISNULL(DBO.REQUEST_ID, '') = PRO.REQUEST_ID
			WHERE DBO.SPID IS NULL
            AND DBO.TRANSACTION_UNIQUE_ID IS NULL
			AND DBO.LAST_UPDATED_ON IS NULL
			AND DBO.CREATED_DATE IS NULL
			AND DBO.REQUEST_ID IS NULL;
			
			SET @Inserts = @@ROWCOUNT;
------------------------------------------------------------------------------------------------------------------------------
        /* Insert to Audit Table */
        UPDATE [sqlmi-dev-dp-cex-control-db].dbo.Load_Audit
        SET Staged_Rows = @Staged,
            New_Rows = @Inserts,
            Updated_Rows = @Updates,
            Deleted_Rows = @Deletes,
            Error_Rows = @Errors,
            Unchanged_Rows = @Unchanged,
            Load_ErrorMsg = CASE
                                WHEN Load_ErrorMsg = '' THEN
                                    ''
                                ELSE
                                    'Resolved on ' + FORMAT(GETDATE(), 'dd/MM/yyyy a   hh:mmtt') + ' - '
                                    + Load_ErrorMsg
                            END
        WHERE LoadID = @LoadID
        COMMIT TRANSACTION
    END TRY
    BEGIN CATCH
        ROLLBACK;
        /* Insert error message to Audit Table */
        UPDATE [sqlmi-dev-dp-cex-control-db].dbo.Load_Audit
        SET Load_ErrorMsg = ERROR_MESSAGE()
        WHERE LoadID = @LoadID
    END CATCH
    /* Revert entire process if failure */
    IF @@TRANCOUNT > 0
        ROLLBACK;
END
