CREATE OR ALTER     PROCEDURE [stg].[sp_UPDATE_TXN_T117_MARKET_OPERATOR] @LoadID BIGINT
AS
BEGIN
    SET XACT_ABORT ON;
    SET NOCOUNT ON;
    DECLARE @Inserts BIGINT = 0,
            @Updates BIGINT = 0,
            @Errors BIGINT = 0,
            @Unchanged BIGINT = 0,
            @Deletes BIGINT = 0,
            @OriginalRowCount BIGINT = 0,
            @Staged BIGINT = 0,
            @RowsAffected BIGINT = 0,
            @masterRunID VARCHAR(100) = '',
            @TodayDT DATETIME2(3) = GETUTCDATE(),
            @Today DATE = GETUTCDATE(),
            @Yesterday DATE = TRY_CONVERT(DATE, DATEADD(DAY, -1, GETUTCDATE())),
            @EOM INT = DATEPART(DAY, GETUTCDATE()),
            @LoadDate DATE = GETUTCDATE();

    BEGIN TRY
        BEGIN TRANSACTION
------------------------------------------------------------------------------------------------------------------------------		
	TRUNCATE TABLE [process].[TXN_T117M]
	INSERT INTO [process].[TXN_T117M]
           ([SPID]
           ,[FK_METER_MANUFACTURER_OLD_METER_ID]
           ,[MANUFACTURER_METER_SERIAL_NUMBER_OLD_METER]
           ,[METER_READ_OLD_METER]
           ,[METER_READ_DATE_OLD_METER]
           ,[FK_METER_READ_TYPE_OLD_METER_ID]
           ,[FK_METER_READ_METHOD_OLD_METER_ID]
           ,[FLG_ROLLOVER_OLD_METER]
           ,[FK_METER_MANUFACTURER_NEW_METER_ID]
           ,[MANUFACTURER_METER_SERIAL_NUMBER_NEW_METER]
           ,[METER_READ_NEW_METER]
           ,[METER_READ_DATE_NEW_METER]
           ,[FK_METER_READ_TYPE_NEW_METER_ID]
           ,[FK_METER_READ_METHOD_NEW_METER_ID]
           ,[CREATED_DATE]
           ,[LAST_UPDATED_ON]
           ,[TRANSACTION_UNIQUE_ID]
           ,[FK_TRANSACTION_STATUS_ID]
           ,[FLG_DMS_SYNC]
           ,[REQUEST_ID]
           ,[FK_ESTIMATED_READ_REASON_ID]
           ,[HASH_VALUE])

	SELECT
            ISNULL(TRY_CONVERT(VARCHAR(16), SRC.[D2001_SPID]), '') AS [SPID],
            ISNULL(TRY_CONVERT(SMALLINT, MANUF.[METER_MANUFACTURER_ID]), 0) AS [FK_METER_MANUFACTURER_OLD_METER_ID],
            ISNULL(TRY_CONVERT(VARCHAR(50), SRC.[D3014_Manufacturer_Meter_Serial_Number_Old_Meter]), '') AS [MANUFACTURER_METER_SERIAL_NUMBER_OLD_METER],
            ISNULL(TRY_CONVERT(INT, SRC.[D3008_Meter_Read_Old_Meter]), 0) AS [METER_READ_OLD_METER],
            ISNULL(TRY_CONVERT(DATE, SRC.[D3009_Meter_Read_Date_Old_Meter]), '1900-01-01') AS [METER_READ_DATE_OLD_METER],
            ISNULL(TRY_CONVERT(TINYINT, READINGS.[METER_READ_TYPE_ID]), 0) AS [FK_METER_READ_TYPE_OLD_METER_ID],
            ISNULL(TRY_CONVERT(TINYINT, READMETHOD.[STAGING_METER_READ_METHOD_ID]), 0) AS [FK_METER_READ_METHOD_OLD_METER_ID],
            ISNULL(TRY_CONVERT(BIT, SRC.[D3021_Rollover_Flag_Old_Meter]), 0) AS [FLG_ROLLOVER_OLD_METER],
            ISNULL(TRY_CONVERT(SMALLINT, MANU.[METER_MANUFACTURER_ID]), 0) AS [FK_METER_MANUFACTURER_NEW_METER_ID],
            ISNULL(TRY_CONVERT(VARCHAR(50), SRC.[D3014_Manufacturer_Meter_Serial_Number_New_Meter]), '') AS [MANUFACTURER_METER_SERIAL_NUMBER_NEW_METER],
            ISNULL(TRY_CONVERT(INT, SRC.[D3008_Meter_Read_New_Meter]), 0) AS [METER_READ_NEW_METER],
            ISNULL(TRY_CONVERT(DATE, SRC.[D3009_Meter_Read_Date_New_Meter]), '1900-01-01') AS [METER_READ_DATE_NEW_METER],
            ISNULL(TRY_CONVERT(TINYINT, READTYPE.[METER_READ_TYPE_ID]), 0) AS [FK_METER_READ_TYPE_NEW_METER_ID],
            ISNULL(TRY_CONVERT(TINYINT, READMETHODS.[STAGING_METER_READ_METHOD_ID]), 0) AS [FK_METER_READ_METHOD_NEW_METER_ID],
            ISNULL(TRY_CONVERT(DATE, SRC.[CreatedOn]), '1900-01-01') AS [CREATED_DATE],
            ISNULL(TRY_CONVERT(DATETIME2(3), SRC.[LastUpdatedOn]), '1900-01-01 00:00:00.000') AS [LAST_UPDATED_ON],
            ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[Transaction_Unique_ID]), '') AS [TRANSACTION_UNIQUE_ID],
            ISNULL(TRY_CONVERT(TINYINT, TRANSACT.[TRANSACTION_STATUS_ID]), 0) AS [FK_TRANSACTION_STATUS_ID],
            ISNULL(TRY_CONVERT(BIT, CASE 
                WHEN SRC.[DMS_Sync_Flag] = 'Y' THEN 1 
                WHEN SRC.[DMS_Sync_Flag] = 'B' THEN 0 
            END), 0) AS [FLG_DMS_SYNC],
            ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[Request_ID]), '') AS [REQUEST_ID],
            ISNULL(TRY_CONVERT(TINYINT, REASON.[ESTIMATED_READ_REASON_ID]), 0) AS [FK_ESTIMATED_READ_REASON_ID],
		    HASHBYTES(
                        'sha1',
                            CONCAT_WS('|',
                                ISNULL(TRY_CONVERT(SMALLINT, MANUF.[METER_MANUFACTURER_ID]), 0),
            ISNULL(TRY_CONVERT(VARCHAR(50), SRC.[D3014_Manufacturer_Meter_Serial_Number_Old_Meter]), ''),
            ISNULL(TRY_CONVERT(INT, SRC.[D3008_Meter_Read_Old_Meter]), 0),
            ISNULL(TRY_CONVERT(DATE, SRC.[D3009_Meter_Read_Date_Old_Meter]), '1900-01-01'),
            ISNULL(TRY_CONVERT(TINYINT, READINGS.[METER_READ_TYPE_ID]), 0),
            ISNULL(TRY_CONVERT(TINYINT, READMETHOD.[STAGING_METER_READ_METHOD_ID]), 0),
            ISNULL(TRY_CONVERT(BIT, SRC.[D3021_Rollover_Flag_Old_Meter]), 0),
            ISNULL(TRY_CONVERT(SMALLINT, MANU.[METER_MANUFACTURER_ID]), 0),
            ISNULL(TRY_CONVERT(VARCHAR(50), SRC.[D3014_Manufacturer_Meter_Serial_Number_New_Meter]), ''),
            ISNULL(TRY_CONVERT(INT, SRC.[D3008_Meter_Read_New_Meter]), 0),
            ISNULL(TRY_CONVERT(DATE, SRC.[D3009_Meter_Read_Date_New_Meter]), '1900-01-01'),
            ISNULL(TRY_CONVERT(TINYINT, READTYPE.[METER_READ_TYPE_ID]), 0),
            ISNULL(TRY_CONVERT(TINYINT, READMETHODS.[STAGING_METER_READ_METHOD_ID]), 0),
            ISNULL(TRY_CONVERT(DATE, SRC.[CreatedOn]), '1900-01-01'),
            ISNULL(TRY_CONVERT(DATETIME2(3), SRC.[LastUpdatedOn]), '1900-01-01 00:00:00.000'),
            ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[Transaction_Unique_ID]), ''),
            ISNULL(TRY_CONVERT(TINYINT, TRANSACT.[TRANSACTION_STATUS_ID]), 0),
            ISNULL(TRY_CONVERT(BIT, CASE 
                WHEN SRC.[DMS_Sync_Flag] = 'Y' THEN 1 
                WHEN SRC.[DMS_Sync_Flag] = 'B' THEN 0 
            END), 0),
            ISNULL(TRY_CONVERT(TINYINT, REASON.[ESTIMATED_READ_REASON_ID]), 0)
									))
									AS [HASH_VALUE]
    FROM [STG].[DMS_TXN_T117M] AS SRC
    INNER JOIN dbo.D_ESTIMATED_READ_REASON AS REASON
    ON ISNULL(TRIM(SRC.[D3028_Estimated_Read_Reason_Code]), '') = REASON.ESTIMATED_READ_REASON_CODE
    INNER JOIN dbo.D_STAGING_METER_READ_TYPE AS READINGS
    ON ISNULL(TRIM(SRC.[D3010_Meter_Read_Type_Old_Meter]), '') = READINGS.METER_READ_TYPE_CODE
    INNER JOIN dbo.D_STAGING_METER_READ_METHOD AS READMETHOD
    ON ISNULL(TRIM(SRC.[D3044_Meter_Read_Method_Old_Meter]), '') = READMETHOD.METER_READ_METHOD_DESCRIPTION
    INNER JOIN dbo.D_METER_MANUFACTURER AS MANU
    ON ISNULL(TRIM(SRC.[D3013_Meter_Manufacturer_New_Meter]), '') = MANU.METER_MANUFACTURER_DESCRIPTION
    INNER JOIN dbo.D_STAGING_METER_READ_TYPE AS READTYPE
    ON ISNULL(TRIM(SRC.[D3010_Meter_Read_Type_New_Meter]), '') = READTYPE.METER_READ_TYPE_CODE
    INNER JOIN dbo.D_STAGING_METER_READ_METHOD AS READMETHODS
    ON ISNULL(TRIM(SRC.[D3044_Meter_Read_Method_New_Meter]), '') = READMETHODS.METER_READ_METHOD_DESCRIPTION
    INNER JOIN dbo.D_METER_MANUFACTURER AS MANUF
    ON ISNULL(TRIM(SRC.[D3013_Meter_Manufacturer_Old_Meter]), '') = MANUF.METER_MANUFACTURER_DESCRIPTION
    INNER JOIN DBO.D_TRANSACTION_STATUS AS TRANSACT
    ON ISNULL(TRIM(SRC.[Transaction_Status]), '') = TRANSACT.TRANSACTION_STATUS;

------------------------------------------------------------------------------------------------------------------------------
	UPDATE DBO
	SET 
    DBO.FK_METER_MANUFACTURER_OLD_METER_ID = PRO.FK_METER_MANUFACTURER_OLD_METER_ID,
    DBO.MANUFACTURER_METER_SERIAL_NUMBER_OLD_METER = PRO.MANUFACTURER_METER_SERIAL_NUMBER_OLD_METER,
    DBO.METER_READ_OLD_METER = PRO.METER_READ_OLD_METER,
    DBO.METER_READ_DATE_OLD_METER = PRO.METER_READ_DATE_OLD_METER,
    DBO.FK_METER_READ_TYPE_OLD_METER_ID = PRO.FK_METER_READ_TYPE_OLD_METER_ID,
    DBO.FK_METER_READ_METHOD_OLD_METER_ID = PRO.FK_METER_READ_METHOD_OLD_METER_ID,
    DBO.FLG_ROLLOVER_OLD_METER = PRO.FLG_ROLLOVER_OLD_METER,
    DBO.FK_METER_MANUFACTURER_NEW_METER_ID = PRO.FK_METER_MANUFACTURER_NEW_METER_ID,
    DBO.MANUFACTURER_METER_SERIAL_NUMBER_NEW_METER = PRO.MANUFACTURER_METER_SERIAL_NUMBER_NEW_METER,
    DBO.METER_READ_NEW_METER = PRO.METER_READ_NEW_METER,
    DBO.METER_READ_DATE_NEW_METER = PRO.METER_READ_DATE_NEW_METER,
    DBO.FK_METER_READ_TYPE_NEW_METER_ID = PRO.FK_METER_READ_TYPE_NEW_METER_ID,
    DBO.FK_METER_READ_METHOD_NEW_METER_ID = PRO.FK_METER_READ_METHOD_NEW_METER_ID,
    DBO.CREATED_DATE = PRO.CREATED_DATE,
    DBO.LAST_UPDATED_ON = PRO.LAST_UPDATED_ON,
    DBO.TRANSACTION_UNIQUE_ID = PRO.TRANSACTION_UNIQUE_ID,
    DBO.FK_TRANSACTION_STATUS_ID = PRO.FK_TRANSACTION_STATUS_ID,
    DBO.FLG_DMS_SYNC = PRO.FLG_DMS_SYNC,
    DBO.FK_ESTIMATED_READ_REASON_ID = PRO.FK_ESTIMATED_READ_REASON_ID
	FROM [process].[TXN_T117M] AS PRO
	INNER JOIN [dbo].[E_TXN_T117_MARKET_OPERATOR] AS DBO
	ON  ISNULL(DBO.SPID, '') = PRO.SPID
	AND ISNULL(DBO.TRANSACTION_UNIQUE_ID, '') = PRO.TRANSACTION_UNIQUE_ID
	AND ISNULL(DBO.LAST_UPDATED_ON, '1900-01-01 00:00:00.000') = PRO.LAST_UPDATED_ON
	AND ISNULL(DBO.REQUEST_ID, '') = PRO.REQUEST_ID
	WHERE PRO.HASH_VALUE <> DBO.HASH_VALUE;

	SET @Updates = @@ROWCOUNT;
------------------------------------------------------------------------------------------------------------------------------
	INSERT INTO [dbo].[E_TXN_T117_MARKET_OPERATOR]
           ([SPID]
           ,[FK_METER_MANUFACTURER_OLD_METER_ID]
           ,[MANUFACTURER_METER_SERIAL_NUMBER_OLD_METER]
           ,[METER_READ_OLD_METER]
           ,[METER_READ_DATE_OLD_METER]
           ,[FK_METER_READ_TYPE_OLD_METER_ID]
           ,[FK_METER_READ_METHOD_OLD_METER_ID]
           ,[FLG_ROLLOVER_OLD_METER]
           ,[FK_METER_MANUFACTURER_NEW_METER_ID]
           ,[MANUFACTURER_METER_SERIAL_NUMBER_NEW_METER]
           ,[METER_READ_NEW_METER]
           ,[METER_READ_DATE_NEW_METER]
           ,[FK_METER_READ_TYPE_NEW_METER_ID]
           ,[FK_METER_READ_METHOD_NEW_METER_ID]
           ,[CREATED_DATE]
           ,[LAST_UPDATED_ON]
           ,[TRANSACTION_UNIQUE_ID]
           ,[FK_TRANSACTION_STATUS_ID]
           ,[FLG_DMS_SYNC]
           ,[REQUEST_ID]
           ,[FK_ESTIMATED_READ_REASON_ID]
           ,[HASH_VALUE])
		   
	SELECT 
		    PRO.SPID,
            PRO.FK_METER_MANUFACTURER_OLD_METER_ID,
            PRO.MANUFACTURER_METER_SERIAL_NUMBER_OLD_METER,
            PRO.METER_READ_OLD_METER,
            PRO.METER_READ_DATE_OLD_METER,
            PRO.FK_METER_READ_TYPE_OLD_METER_ID,
            PRO.FK_METER_READ_METHOD_OLD_METER_ID,
            PRO.FLG_ROLLOVER_OLD_METER,
            PRO.FK_METER_MANUFACTURER_NEW_METER_ID,
            PRO.MANUFACTURER_METER_SERIAL_NUMBER_NEW_METER,
            PRO.METER_READ_NEW_METER,
            PRO.METER_READ_DATE_NEW_METER,
            PRO.FK_METER_READ_TYPE_NEW_METER_ID,
            PRO.FK_METER_READ_METHOD_NEW_METER_ID,
            PRO.CREATED_DATE,
            PRO.LAST_UPDATED_ON,
            PRO.TRANSACTION_UNIQUE_ID,
            PRO.FK_TRANSACTION_STATUS_ID,
            PRO.FLG_DMS_SYNC,
            PRO.REQUEST_ID,
            PRO.FK_ESTIMATED_READ_REASON_ID,
            PRO.HASH_VALUE
			FROM [process].[TXN_T117M] AS PRO
			LEFT JOIN [dbo].[E_TXN_T117_MARKET_OPERATOR] AS DBO
			ON  ISNULL(DBO.SPID, '') = PRO.SPID
			AND ISNULL(DBO.TRANSACTION_UNIQUE_ID, '') = PRO.TRANSACTION_UNIQUE_ID
			AND ISNULL(DBO.LAST_UPDATED_ON, '1900-01-01 00:00:00.000') = PRO.LAST_UPDATED_ON
			AND ISNULL(DBO.REQUEST_ID, '') = PRO.REQUEST_ID
			WHERE DBO.SPID IS NULL
			AND DBO.TRANSACTION_UNIQUE_ID IS NULL
			AND DBO.LAST_UPDATED_ON IS NULL
			AND DBO.REQUEST_ID IS NULL;
			
			SET @Inserts = @@ROWCOUNT;
------------------------------------------------------------------------------------------------------------------------------
        /* Insert to Audit Table */
        UPDATE [sqlmi-dev-dp-cex-control-db].dbo.Load_Audit
        SET Staged_Rows = @Staged,
            New_Rows = @Inserts,
            Updated_Rows = @Updates,
            Deleted_Rows = @Deletes,
            Error_Rows = @Errors,
            Unchanged_Rows = @Unchanged,
            Load_ErrorMsg = CASE
                                WHEN Load_ErrorMsg = '' THEN
                                    ''
                                ELSE
                                    'Resolved on ' + FORMAT(GETDATE(), 'dd/MM/yyyy a   hh:mmtt') + ' - '
                                    + Load_ErrorMsg
                            END
        WHERE LoadID = @LoadID
        COMMIT TRANSACTION
    END TRY
    BEGIN CATCH
        ROLLBACK;
        /* Insert error message to Audit Table */
        UPDATE [sqlmi-dev-dp-cex-control-db].dbo.Load_Audit
        SET Load_ErrorMsg = ERROR_MESSAGE()
        WHERE LoadID = @LoadID
    END CATCH
    /* Revert entire process if failure */
    IF @@TRANCOUNT > 0
        ROLLBACK;
END
