                                ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[Transaction_Unique_ID]), ''),
                                ISNULL(TRY_CONVERT(TINYINT, TRANSACT.[TRANSACTION_STATUS_ID]), 0),
                                ISNULL(TRY_CONVERT(TINYINT, MOSL.[MOSL_MESSAGE_ID]), 0),
                                ISNULL(TRY_CONVERT(BIT, SRC.[D2033_Accredited_Entity_Flag]), 0),
                                ISNULL(TRY_CONVERT(TINYINT, REASON.[ESTIMATED_READ_REASON_ID]), 0)
									))
									AS [HASH_VALUE]
    FROM [STG].[DMS_TXN_T117W] AS SRC
    INNER JOIN DBO.D_MOSL_MESSAGE AS MOSL
	ON ISNULL(TRIM(SRC.[MOSL_Message]), '') = MOSL.MOSL_MESSAGE_CODE
    INNER JOIN dbo.D_ESTIMATED_READ_REASON AS REASON
    ON ISNULL(TRIM(SRC.[D3028_Estimated_Read_Reason_Code]), '') = REASON.ESTIMATED_READ_REASON_CODE
    INNER JOIN dbo.D_STAGING_METER_READ_TYPE AS READINGS
    ON ISNULL(TRIM(SRC.[D3010_Meter_Read_Type_Old_Meter]), '') = READINGS.METER_READ_TYPE_CODE
    INNER JOIN dbo.D_STAGING_METER_READ_METHOD AS READMETHOD
    ON ISNULL(TRIM(SRC.[D3044_Meter_Read_Method_Old_Meter]), '') = READMETHOD.METER_READ_METHOD_DESCRIPTION
    INNER JOIN dbo.D_METER_MANUFACTURER AS MANU
    ON ISNULL(TRIM(SRC.[D3013_Meter_Manufacturer_New_Meter]), '') = MANU.METER_MANUFACTURER_DESCRIPTION
    INNER JOIN dbo.D_STAGING_METER_READ_TYPE AS READTYPE
    ON ISNULL(TRIM(SRC.[D3010_Meter_Read_Type_New_Meter]), '') = READTYPE.METER_READ_TYPE_CODE
    INNER JOIN dbo.D_METER_MANUFACTURER AS MANUF
    ON ISNULL(TRIM(SRC.[D3013_Meter_Manufacturer_Old_Meter]), '') = MANUF.METER_MANUFACTURER_DESCRIPTION
    INNER JOIN dbo.D_STAGING_METER_READ_METHOD AS READMETHODS
    ON ISNULL(TRIM(SRC.[D3044_Meter_Read_Method_New_Meter]), '') = READMETHODS.METER_READ_METHOD_DESCRIPTION
    INNER JOIN DBO.D_TRANSACTION_STATUS AS TRANSACT
    ON ISNULL(TRIM(SRC.[Transaction_Status]), '') = TRANSACT.TRANSACTION_STATUS;

------------------------------------------------------------------------------------------------------------------------------
	UPDATE DBO
	SET 
    DBO.FK_METER_MANUFACTURER_OLD_METER_ID = PRO.FK_METER_MANUFACTURER_OLD_METER_ID,
    DBO.MANUFACTURER_METER_SERIAL_NUMBER_OLD_METER = PRO.MANUFACTURER_METER_SERIAL_NUMBER_OLD_METER,
    DBO.METER_READ_OLD_METER = PRO.METER_READ_OLD_METER,
    DBO.METER_READ_DATE_OLD_METER = PRO.METER_READ_DATE_OLD_METER,
    DBO.FK_METER_READ_TYPE_OLD_METER_ID = PRO.FK_METER_READ_TYPE_OLD_METER_ID,
    DBO.FK_METER_READ_METHOD_OLD_METER_ID = PRO.FK_METER_READ_METHOD_OLD_METER_ID,
    DBO.FLG_ROLLOVER_INDICATOR_OLD_METER = PRO.FLG_ROLLOVER_INDICATOR_OLD_METER,
    DBO.FLG_REREAD_OLD_METER = PRO.FLG_REREAD_OLD_METER,
    DBO.FK_METER_MANUFACTURER_NEW_METER_ID = PRO.FK_METER_MANUFACTURER_NEW_METER_ID,
    DBO.MANUFACTURER_METER_SERIAL_NUMBER_NEW_METER = PRO.MANUFACTURER_METER_SERIAL_NUMBER_NEW_METER,
    DBO.METER_READ_NEW_METER = PRO.METER_READ_NEW_METER,
    DBO.METER_READ_DATE_NEW_METER = PRO.METER_READ_DATE_NEW_METER,
    DBO.FK_METER_READ_TYPE_NEW_METER_ID = PRO.FK_METER_READ_TYPE_NEW_METER_ID,
    DBO.FK_METER_READ_METHOD_NEW_METER_ID = PRO.FK_METER_READ_METHOD_NEW_METER_ID,
    DBO.TEXT_COMMENT_FIELD = PRO.TEXT_COMMENT_FIELD,
    DBO.CREATED_DATE = PRO.CREATED_DATE,
    DBO.LAST_UPDATED_ON = PRO.LAST_UPDATED_ON,
    DBO.TRANSACTION_UNIQUE_ID = PRO.TRANSACTION_UNIQUE_ID,
    DBO.FK_TRANSACTION_STATUS_ID = PRO.FK_TRANSACTION_STATUS_ID,
    DBO.FK_MOSL_MESSAGE_ID = PRO.FK_MOSL_MESSAGE_ID,
    DBO.FLG_ACCREDITED_ENTITY = PRO.FLG_ACCREDITED_ENTITY,
    DBO.FK_ESTIMATED_READ_REASON_ID = PRO.FK_ESTIMATED_READ_REASON_ID
	FROM [process].[TXN_T117W] AS PRO
	INNER JOIN [dbo].[E_TXN_T117_WHOLESALER] AS DBO
	ON  ISNULL(DBO.SPID, '') = PRO.SPID
	AND ISNULL(DBO.TRANSACTION_UNIQUE_ID, '') = PRO.TRANSACTION_UNIQUE_ID
	AND ISNULL(DBO.LAST_UPDATED_ON, '1900-01-01 00:00:00.000') = PRO.LAST_UPDATED_ON
	AND ISNULL(DBO.REQUEST_ID, '') = PRO.REQUEST_ID
	WHERE PRO.HASH_VALUE <> DBO.HASH_VALUE;

	SET @Updates = @@ROWCOUNT;
------------------------------------------------------------------------------------------------------------------------------
	INSERT INTO [dbo].[E_TXN_T117_WHOLESALER]
           ([SPID]
           ,[FK_METER_MANUFACTURER_OLD_METER_ID]
           ,[MANUFACTURER_METER_SERIAL_NUMBER_OLD_METER]
           ,[METER_READ_OLD_METER]
           ,[METER_READ_DATE_OLD_METER]
           ,[FK_METER_READ_TYPE_OLD_METER_ID]
           ,[FK_METER_READ_METHOD_OLD_METER_ID]
           ,[FLG_ROLLOVER_INDICATOR_OLD_METER]
           ,[FLG_REREAD_OLD_METER]
           ,[FK_METER_MANUFACTURER_NEW_METER_ID]
           ,[MANUFACTURER_METER_SERIAL_NUMBER_NEW_METER]
           ,[METER_READ_NEW_METER]
           ,[METER_READ_DATE_NEW_METER]
           ,[FK_METER_READ_TYPE_NEW_METER_ID]
           ,[FK_METER_READ_METHOD_NEW_METER_ID]
           ,[TEXT_COMMENT_FIELD]
           ,[CREATED_DATE]
           ,[LAST_UPDATED_ON]
           ,[TRANSACTION_UNIQUE_ID]
           ,[FK_TRANSACTION_STATUS_ID]
           ,[FK_MOSL_MESSAGE_ID]
           ,[REQUEST_ID]
           ,[FLG_ACCREDITED_ENTITY]
           ,[FK_ESTIMATED_READ_REASON_ID]
           ,[HASH_VALUE])
		   
	SELECT 
		    PRO.SPID,
            PRO.FK_METER_MANUFACTURER_OLD_METER_ID,
            PRO.MANUFACTURER_METER_SERIAL_NUMBER_OLD_METER,
            PRO.METER_READ_OLD_METER,
            PRO.METER_READ_DATE_OLD_METER,
            PRO.FK_METER_READ_TYPE_OLD_METER_ID,
            PRO.FK_METER_READ_METHOD_OLD_METER_ID,
            PRO.FLG_ROLLOVER_INDICATOR_OLD_METER,
            PRO.FLG_REREAD_OLD_METER,
            PRO.FK_METER_MANUFACTURER_NEW_METER_ID,
            PRO.MANUFACTURER_METER_SERIAL_NUMBER_NEW_METER,
            PRO.METER_READ_NEW_METER,
            PRO.METER_READ_DATE_NEW_METER,
            PRO.FK_METER_READ_TYPE_NEW_METER_ID,
            PRO.FK_METER_READ_METHOD_NEW_METER_ID,
            PRO.TEXT_COMMENT_FIELD,
            PRO.CREATED_DATE,
            PRO.LAST_UPDATED_ON,
            PRO.TRANSACTION_UNIQUE_ID,
            PRO.FK_TRANSACTION_STATUS_ID,
            PRO.FK_MOSL_MESSAGE_ID,
            PRO.REQUEST_ID,
            PRO.FLG_ACCREDITED_ENTITY,
            PRO.FK_ESTIMATED_READ_REASON_ID,
            PRO.HASH_VALUE
			FROM [process].[TXN_T117W] AS PRO
			LEFT JOIN [dbo].[E_TXN_T117_WHOLESALER] AS DBO
			ON  ISNULL(DBO.SPID, '') = PRO.SPID
			AND ISNULL(DBO.TRANSACTION_UNIQUE_ID, '') = PRO.TRANSACTION_UNIQUE_ID
			AND ISNULL(DBO.LAST_UPDATED_ON, '1900-01-01 00:00:00.000') = PRO.LAST_UPDATED_ON
			AND ISNULL(DBO.REQUEST_ID, '') = PRO.REQUEST_ID
			WHERE DBO.SPID IS NULL
			AND DBO.TRANSACTION_UNIQUE_ID IS NULL
			AND DBO.LAST_UPDATED_ON IS NULL
			AND DBO.REQUEST_ID IS NULL;
			
			SET @Inserts = @@ROWCOUNT;
------------------------------------------------------------------------------------------------------------------------------
        /* Insert to Audit Table */
        UPDATE [sqlmi-dev-dp-cex-control-db].dbo.Load_Audit
        SET Staged_Rows = @Staged,
            New_Rows = @Inserts,
            Updated_Rows = @Updates,
            Deleted_Rows = @Deletes,
            Error_Rows = @Errors,
            Unchanged_Rows = @Unchanged,
            Load_ErrorMsg = CASE
                                WHEN Load_ErrorMsg = '' THEN
                                    ''
                                ELSE
                                    'Resolved on ' + FORMAT(GETDATE(), 'dd/MM/yyyy a   hh:mmtt') + ' - '
                                    + Load_ErrorMsg
                            END
        WHERE LoadID = @LoadID
        COMMIT TRANSACTION
    END TRY
    BEGIN CATCH
        ROLLBACK;
        /* Insert error message to Audit Table */
        UPDATE [sqlmi-dev-dp-cex-control-db].dbo.Load_Audit
        SET Load_ErrorMsg = ERROR_MESSAGE()
        WHERE LoadID = @LoadID
    END CATCH
    /* Revert entire process if failure */
    IF @@TRANCOUNT > 0
        ROLLBACK;
END
GO
