CREATE OR ALTER   PROCEDURE [stg].[sp_UPDATE_TXN_T121_WHOLESALER] @LoadID BIGINT
AS
BEGIN
    SET XACT_ABORT ON;
    SET NOCOUNT ON;
    DECLARE @Inserts BIGINT = 0,
            @Updates BIGINT = 0,
            @Errors BIGINT = 0,
            @Unchanged BIGINT = 0,
            @Deletes BIGINT = 0,
            @OriginalRowCount BIGINT = 0,
            @Staged BIGINT = 0,
            @RowsAffected BIGINT = 0,
            @masterRunID VARCHAR(100) = '',
            @TodayDT DATETIME2(3) = GETUTCDATE(),
            @Today DATE = GETUTCDATE(),
            @Yesterday DATE = TRY_CONVERT(DATE, DATEADD(DAY, -1, GETUTCDATE())),
            @EOM INT = DATEPART(DAY, GETUTCDATE()),
            @LoadDate DATE = GETUTCDATE();

    BEGIN TRY
        BEGIN TRANSACTION
------------------------------------------------------------------------------------------------------------------------------		
	TRUNCATE TABLE [process].[TXN_T121W]
	INSERT INTO [process].[TXN_T121W]
           ([SPID]
           ,[DPID]
           ,[EFFECTIVE_FROM_DATE]
           ,[FK_TRADE_EFFLUENT_TARIFF_ID]
           ,[CHARGEABLE_DAILY_VOLUME]
           ,[CHARGEABLE_CHEMICAL_OXYGEN_DEMAND_LOAD]
           ,[CHARGEABLE_SUSPENDED_SOLIDS_LOAD]
           ,[CHEMICAL_OXYGEN_DEMAND]
           ,[SUSPENDED_SOLIDS]
           ,[CHARGEABLE_AMMONIACAL_NITROGEN_LOAD]
           ,[DOMESTIC_ALLOWANCE]
           ,[SEASONAL_FACTOR]
           ,[TRADE_EFFLUENT_AMMONIACAL_NITROGEN_CONTENT]
           ,[TRADE_EFFLUENT_COMPONENT_X_CONTENT]
           ,[TRADE_EFFLUENT_COMPONENT_Y_CONTENT]
           ,[TRADE_EFFLUENT_COMPONENT_Z_CONTENT]
           ,[PERCENTAGE_ALLOWANCE]
           ,[FIXED_ALLOWANCE]
           ,[FLG_RECEPTION_TREATMENT_INDICATOR]
           ,[FLG_PRIMARY_TREATMENT_INDICATOR]
           ,[FLG_MARINE_TREATMENT_INDICATOR]
           ,[FLG_BIOLOGICAL_TREATMENT_INDICATOR]
           ,[FLG_SLUDGE_TREATMENT_INDICATOR]
           ,[FLG_AMMONIA_TREATMENT_INDICATOR]
           ,[FLG_TRADE_EFFLUENT_COMPONENT_X_TREATMENT_INDICATOR]
           ,[FLG_TRADE_EFFLUENT_COMPONENT_Y_TREATMENT_INDICATOR]
           ,[FLG_TRADE_EFFLUENT_COMPONENT_Z_TREATMENT_INDICATOR]
           ,[TRADE_EFFLUENT_COMPONENT_X_DEMAND_LOAD]
           ,[TRADE_EFFLUENT_COMPONENT_Y_DEMAND_LOAD]
           ,[TRADE_EFFLUENT_COMPONENT_Z_DEMAND_LOAD]
           ,[TRADE_EFFLUENT_TARIFF_BAND]
           ,[FK_SEWERAGE_VOLUME_ADJUSTMENT_METHOD_ID]
           ,[FREE_DESCRIPTOR]
           ,[PRIMARY_ADDRESSABLE_OBJECT]
           ,[SECONDARY_ADDRESSABLE_OBJECT]
           ,[ADDRESS_LINE_1]
           ,[ADDRESS_LINE_2]
           ,[ADDRESS_LINE_3]
           ,[ADDRESS_LINE_4]
           ,[ADDRESS_LINE_5]
           ,[POSTCODE]
           ,[PAF_ADDRESS_KEY]
           ,[FK_CHARGING_METHOD_ID]
           ,[TEXT_COMMENT_FIELD]
           ,[CREATED_DATE]
           ,[LAST_UPDATED_ON]
           ,[TRANSACTION_UNIQUE_ID]
           ,[FK_TRANSACTION_STATUS_ID]
           ,[FK_MOSL_MESSAGE_ID]
           ,[REQUEST_ID]
           ,[HASH_VALUE])

SELECT
            ISNULL(TRY_CONVERT(VARCHAR(16), SRC.[D2001_SPID]), '') AS [SPID],
            ISNULL(TRY_CONVERT(VARCHAR(16), SRC.[D6001_DPID]), '') AS [DPID],
            ISNULL(TRY_CONVERT(DATE, SRC.[D4006_Effective_From_Date]), '1900-01-01') AS [EFFECTIVE_FROM_DATE],
            ISNULL(TRY_CONVERT(TINYINT, TRADE.[TRADE_EFFLUENT_TARIFF_ID]), 0) AS [FK_TRADE_EFFLUENT_TARIFF_ID],
            ISNULL(TRY_CONVERT(INT, SRC.[D6003_Chargeable_Daily_Volume]), 0) AS [CHARGEABLE_DAILY_VOLUME],
            ISNULL(TRY_CONVERT(INT, SRC.[D6004_cCODl]), 0) AS [CHARGEABLE_CHEMICAL_OXYGEN_DEMAND_LOAD],
            ISNULL(TRY_CONVERT(INT, SRC.[D6005_cSSl]), 0) AS [CHARGEABLE_SUSPENDED_SOLIDS_LOAD],
            ISNULL(TRY_CONVERT(SMALLINT, SRC.[D6006_Ot]), 0) AS [CHEMICAL_OXYGEN_DEMAND],
            ISNULL(TRY_CONVERT(INT, SRC.[D6007_St]), 0) AS [SUSPENDED_SOLIDS],
            ISNULL(TRY_CONVERT(INT, SRC.[D6002_cANl]), 0) AS [CHARGEABLE_AMMONIACAL_NITROGEN_LOAD],
            ISNULL(TRY_CONVERT(NUMERIC(5,2), SRC.[D6009_Domestic_Allowance]), 0.00) AS [DOMESTIC_ALLOWANCE],
            ISNULL(TRY_CONVERT(NUMERIC(5,2), SRC.[D6010_Seasonal_Factor]), 0.00) AS [SEASONAL_FACTOR],
            ISNULL(TRY_CONVERT(SMALLINT, SRC.[D6011_At]), 0) AS [TRADE_EFFLUENT_AMMONIACAL_NITROGEN_CONTENT],
            ISNULL(TRY_CONVERT(INT, SRC.[D6026_Xt]), 0) AS [TRADE_EFFLUENT_COMPONENT_X_CONTENT],
            ISNULL(TRY_CONVERT(INT, SRC.[D6027_Yt]), 0) AS [TRADE_EFFLUENT_COMPONENT_Y_CONTENT],
            ISNULL(TRY_CONVERT(INT, SRC.[D6028_Zt]), 0) AS [TRADE_EFFLUENT_COMPONENT_Z_CONTENT],
            ISNULL(TRY_CONVERT(NUMERIC(5,2), SRC.[D6012_Percentage_Allowance]), 0.00) AS [PERCENTAGE_ALLOWANCE],
            ISNULL(TRY_CONVERT(NUMERIC(5,2), SRC.[D6013_Fixed_Allowance]), 0.00) AS [FIXED_ALLOWANCE],
            ISNULL(TRY_CONVERT(BIT, SRC.[D6014_Reception_Treatment_Indicator]), 0) AS [FLG_RECEPTION_TREATMENT_INDICATOR],
            ISNULL(TRY_CONVERT(BIT, SRC.[D6015_Primary_Treatment_Indicator]), 0) AS [FLG_PRIMARY_TREATMENT_INDICATOR],
            ISNULL(TRY_CONVERT(BIT, SRC.[D6016_Marine_Treatment_Indicator]), 0) AS [FLG_MARINE_TREATMENT_INDICATOR],
            ISNULL(TRY_CONVERT(BIT, SRC.[D6017_Biological_Treatment_Indicator]), 0) AS [FLG_BIOLOGICAL_TREATMENT_INDICATOR],
            ISNULL(TRY_CONVERT(BIT, SRC.[D6018_Sludge_Treatment_Indicator]), 0) AS [FLG_SLUDGE_TREATMENT_INDICATOR],
            ISNULL(TRY_CONVERT(BIT, SRC.[D6019_Ammonia_Treatment_Indicator]), 0) AS [FLG_AMMONIA_TREATMENT_INDICATOR],
            ISNULL(TRY_CONVERT(BIT, SRC.[D6029_Trade_Effluent_Component_X_Treatment_Indicator]), 0) AS [FLG_TRADE_EFFLUENT_COMPONENT_X_TREATMENT_INDICATOR],
            ISNULL(TRY_CONVERT(BIT, SRC.[D6030_Trade_Effluent_Component_Y_Treatment_Indicator]), 0) AS [FLG_TRADE_EFFLUENT_COMPONENT_Y_TREATMENT_INDICATOR],
            ISNULL(TRY_CONVERT(BIT, SRC.[D6031_Trade_Effluent_Component_Z_Treatment_Indicator]), 0) AS [FLG_TRADE_EFFLUENT_COMPONENT_Z_TREATMENT_INDICATOR],
            ISNULL(TRY_CONVERT(INT, SRC.[D6032_cXl]), 0) AS [TRADE_EFFLUENT_COMPONENT_X_DEMAND_LOAD],
            ISNULL(TRY_CONVERT(INT, SRC.[D6033_cYl]), 0) AS [TRADE_EFFLUENT_COMPONENT_Y_DEMAND_LOAD],
            ISNULL(TRY_CONVERT(INT, SRC.[D6034_cZl]), 0) AS [TRADE_EFFLUENT_COMPONENT_Z_DEMAND_LOAD],
            ISNULL(TRY_CONVERT(TINYINT, SRC.[D6024_Trade_Effluent_Tariff_Band]), 0) AS [TRADE_EFFLUENT_TARIFF_BAND],
            ISNULL(TRY_CONVERT(TINYINT, ADJUST.SEWERAGE_ADJUSTMENT_ID), 0) AS [FK_SEWERAGE_VOLUME_ADJUSTMENT_METHOD_ID],
            ISNULL(TRY_CONVERT(VARCHAR(128), SRC.[D5001_Free_Descriptor]), '') AS [FREE_DESCRIPTOR],
            ISNULL(TRY_CONVERT(VARCHAR(128), SRC.[D5003_Primary_Addressable_Object]), '') AS [PRIMARY_ADDRESSABLE_OBJECT],
            ISNULL(TRY_CONVERT(VARCHAR(128), SRC.[D5002_Secondary_Addressable_Object]), '') AS [SECONDARY_ADDRESSABLE_OBJECT],
            ISNULL(TRY_CONVERT(VARCHAR(128), SRC.[D5004_Address_Line_1]), '') AS [ADDRESS_LINE_1],
            ISNULL(TRY_CONVERT(VARCHAR(64), SRC.[D5005_Address_Line_2]), '') AS [ADDRESS_LINE_2],
            ISNULL(TRY_CONVERT(VARCHAR(64), SRC.[D5006_Address_Line_3]), '') AS [ADDRESS_LINE_3],
            ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[D5007_Address_Line_4]), '') AS [ADDRESS_LINE_4],
            ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[D5008_Address_Line_5]), '') AS [ADDRESS_LINE_5],
            ISNULL(TRY_CONVERT(VARCHAR(16), SRC.[D5009_Postcode]), '') AS [POSTCODE],
            ISNULL(TRY_CONVERT(INT, SRC.[D5011_PAF_Address_Key]), 0) AS [PAF_ADDRESS_KEY],
            ISNULL(TRY_CONVERT(TINYINT, CHARGE.CHARGING_METHOD_ID), 0) AS [FK_CHARGING_METHOD_ID],
            ISNULL(TRY_CONVERT(VARCHAR(512), SRC.[D4003_Text_Comment_Field]), '') AS [TEXT_COMMENT_FIELD],
            ISNULL(TRY_CONVERT(DATE, SRC.[CreatedOn]), '1900-01-01') AS [CREATED_DATE],
            ISNULL(TRY_CONVERT(DATETIME2(2), SRC.[LastUpdatedOn]), '1900-01-01 00:00:00.00') AS [LAST_UPDATED_ON],
            ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[Transaction_Unique_ID]), '') AS [TRANSACTION_UNIQUE_ID],
            ISNULL(TRY_CONVERT(TINYINT, TRANSACT.[TRANSACTION_STATUS_ID]), 0) AS [FK_TRANSACTION_STATUS_ID],
            ISNULL(TRY_CONVERT(TINYINT, MOSL.[MOSL_MESSAGE_ID]), 0) AS [FK_MOSL_MESSAGE_ID],
            ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[Request_ID]), '') AS [REQUEST_ID],
		    HASHBYTES(
                        'sha1',
                            CONCAT_WS('|',
                                ISNULL(TRY_CONVERT(VARCHAR(16), SRC.[D6001_DPID]), ''),
                                ISNULL(TRY_CONVERT(DATE, SRC.[D4006_Effective_From_Date]), '1900-01-01'),
                                ISNULL(TRY_CONVERT(TINYINT, TRADE.[TRADE_EFFLUENT_TARIFF_ID]), 0),
                                ISNULL(TRY_CONVERT(INT, SRC.[D6003_Chargeable_Daily_Volume]), 0),
                                ISNULL(TRY_CONVERT(INT, SRC.[D6004_cCODl]), 0),
                                ISNULL(TRY_CONVERT(INT, SRC.[D6005_cSSl]), 0),
                                ISNULL(TRY_CONVERT(SMALLINT, SRC.[D6006_Ot]), 0),
                                ISNULL(TRY_CONVERT(INT, SRC.[D6007_St]), 0),
                                ISNULL(TRY_CONVERT(INT, SRC.[D6002_cANl]), 0),
                                ISNULL(TRY_CONVERT(NUMERIC(5,2), SRC.[D6009_Domestic_Allowance]), 0.00),
                                ISNULL(TRY_CONVERT(NUMERIC(5,2), SRC.[D6010_Seasonal_Factor]), 0.00),
                                ISNULL(TRY_CONVERT(SMALLINT, SRC.[D6011_At]), 0),
                                ISNULL(TRY_CONVERT(INT, SRC.[D6026_Xt]), 0),
                                ISNULL(TRY_CONVERT(INT, SRC.[D6027_Yt]), 0),
                                ISNULL(TRY_CONVERT(INT, SRC.[D6028_Zt]), 0),
                                ISNULL(TRY_CONVERT(NUMERIC(5,2), SRC.[D6012_Percentage_Allowance]), 0.00),
                                ISNULL(TRY_CONVERT(NUMERIC(5,2), SRC.[D6013_Fixed_Allowance]), 0.00),
                                ISNULL(TRY_CONVERT(BIT, SRC.[D6014_Reception_Treatment_Indicator]), 0),
                                ISNULL(TRY_CONVERT(BIT, SRC.[D6015_Primary_Treatment_Indicator]), 0),
                                ISNULL(TRY_CONVERT(BIT, SRC.[D6016_Marine_Treatment_Indicator]), 0),
                                ISNULL(TRY_CONVERT(BIT, SRC.[D6017_Biological_Treatment_Indicator]), 0),
                                ISNULL(TRY_CONVERT(BIT, SRC.[D6018_Sludge_Treatment_Indicator]), 0),
                                ISNULL(TRY_CONVERT(BIT, SRC.[D6019_Ammonia_Treatment_Indicator]), 0),
                                ISNULL(TRY_CONVERT(BIT, SRC.[D6029_Trade_Effluent_Component_X_Treatment_Indicator]), 0),
                                ISNULL(TRY_CONVERT(BIT, SRC.[D6030_Trade_Effluent_Component_Y_Treatment_Indicator]), 0),
                                ISNULL(TRY_CONVERT(BIT, SRC.[D6031_Trade_Effluent_Component_Z_Treatment_Indicator]), 0),
                                ISNULL(TRY_CONVERT(INT, SRC.[D6032_cXl]), 0),
                                ISNULL(TRY_CONVERT(INT, SRC.[D6033_cYl]), 0),
                                ISNULL(TRY_CONVERT(INT, SRC.[D6034_cZl]), 0),
                                ISNULL(TRY_CONVERT(TINYINT, SRC.[D6024_Trade_Effluent_Tariff_Band]), 0),
                                ISNULL(TRY_CONVERT(TINYINT, ADJUST.SEWERAGE_ADJUSTMENT_ID), 0),
                                ISNULL(TRY_CONVERT(VARCHAR(128), SRC.[D5001_Free_Descriptor]), ''),
                                ISNULL(TRY_CONVERT(VARCHAR(128), SRC.[D5003_Primary_Addressable_Object]), ''),
                                ISNULL(TRY_CONVERT(VARCHAR(128), SRC.[D5002_Secondary_Addressable_Object]), ''),
                                ISNULL(TRY_CONVERT(VARCHAR(128), SRC.[D5004_Address_Line_1]), ''),
                                ISNULL(TRY_CONVERT(VARCHAR(64), SRC.[D5005_Address_Line_2]), ''),
                                ISNULL(TRY_CONVERT(VARCHAR(64), SRC.[D5006_Address_Line_3]), ''),
                                ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[D5007_Address_Line_4]), ''),
                                ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[D5008_Address_Line_5]), ''),
                                ISNULL(TRY_CONVERT(VARCHAR(16), SRC.[D5009_Postcode]), ''),
                                ISNULL(TRY_CONVERT(INT, SRC.[D5011_PAF_Address_Key]), 0),
                                ISNULL(TRY_CONVERT(TINYINT, CHARGE.CHARGING_METHOD_ID), 0),
                                ISNULL(TRY_CONVERT(VARCHAR(512), SRC.[D4003_Text_Comment_Field]), ''),
                                ISNULL(TRY_CONVERT(DATE, SRC.[CreatedOn]), '1900-01-01'),
                                ISNULL(TRY_CONVERT(DATETIME2(2), SRC.[LastUpdatedOn]), '1900-01-01 00:00:00.00'),
                                ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[Transaction_Unique_ID]), ''),
                                ISNULL(TRY_CONVERT(TINYINT, TRANSACT.[TRANSACTION_STATUS_ID]), 0),
                                ISNULL(TRY_CONVERT(TINYINT, MOSL.[MOSL_MESSAGE_ID]), 0)
									))
									AS [HASH_VALUE]
    FROM [STG].[DMS_TXN_T121W] AS SRC
    INNER JOIN dbo.D_SEWERAGE_VOLUME_ADJUSTMENT_METHOD AS ADJUST
    ON ISNULL(TRIM(SRC.[D6035_Sewerage_Volume_Adjustment_Method]), '') = ADJUST.SEWERAGE_ADJUSTMENT_CODE
    INNER JOIN dbo.D_CHARGING_METHOD AS CHARGE
    ON ISNULL(TRIM(SRC.[D6036_Charging_Strength_Methodology]), '') = CHARGE.CHARGING_METHOD_CODE
