            @EOM INT = DATEPART(DAY, GETUTCDATE()),
            @LoadDate DATE = GETUTCDATE();

    BEGIN TRY
        BEGIN TRANSACTION
------------------------------------------------------------------------------------------------------------------------------		
	TRUNCATE TABLE [process].[TXN_T122W]
	INSERT INTO [process].[TXN_T122W]
           ([SPID]
           ,[DPID]
           ,[EFFECTIVE_FROM_DATE]
           ,[CHEMICAL_OXYGEN_DEMAND]
           ,[SUSPENDED_SOLIDS]
           ,[TRADE_EFFLUENT_AMMONIACAL_NITROGEN_CONTENT]
