            ISNULL(TRY_CONVERT(DATE, SRC.[D4006_Effective_From_Date]), '1900-01-01') AS [EFFECTIVE_FROM_DATE],
            ISNULL(TRY_CONVERT(DATE, SRC.[D4024_Effective_To_Date]), '1900-01-01') AS [EFFECTIVE_TO_DATE],
