            ISNULL(TRY_CONVERT(TINYINT, CUSTOMER.[SENSITIVE_CUSTOMER_ID]), 0) AS [FK_CUSTOMER_CLASSIFICATION_SENSITIVE_CUSTOMER_ID],
            ISNULL(TRY_CONVERT(VARCHAR(10), SRC.[D2008_Standard_Industrial_Classification_Code]), '') AS [STANDARD_INDUSTRIAL_CLASSIFICATION_CODE],
            ISNULL(TRY_CONVERT(SMALLINT, WTR.[INDUSTRIAL_CLASSIFICATION_ID]), 0) AS [FK_STANDARD_INDUSTRIAL_CLASSIFICATION_CODE_TYPE_ID],
