            @Unchanged BIGINT = 0,
            @Deletes BIGINT = 0,
            @OriginalRowCount BIGINT = 0,
            @Staged BIGINT = 0,
            @RowsAffected BIGINT = 0,
            @masterRunID VARCHAR(100) = '',
            @TodayDT DATETIME2(3) = GETUTCDATE(),
            @Today DATE = GETUTCDATE(),
            @Yesterday DATE = TRY_CONVERT(DATE, DATEADD(DAY, -1, GETUTCDATE())),
            @EOM INT = DATEPART(DAY, GETUTCDATE()),
            @LoadDate DATE = GETUTCDATE();

    BEGIN TRY
        BEGIN TRANSACTION
------------------------------------------------------------------------------------------------------------------------------		
	TRUNCATE TABLE [process].[TXN_T138W]
	INSERT INTO [process].[TXN_T138W]
           ([SPID]
           ,[FK_SERVICE_COMPONENT_TYPE_ID]
           ,[FK_VOLUMETRIC_ADJUSTMENT_TYPE_ID]
           ,[VOLUMETRIC_ADJUSTMENT_UNIQUE_REFERENCE]
           ,[EFFECTIVE_FROM_DATE]
           ,[EFFECTIVE_TO_DATE]
           ,[ADJUSTMENT_VOLUME]
           ,[TEXT_COMMENT_FIELD]
           ,[CREATED_DATE]
           ,[LAST_UPDATED_ON]
           ,[TRANSACTION_UNIQUE_ID]
           ,[FK_TRANSACTION_STATUS_ID]
           ,[FK_MOSL_MESSAGE_ID]
           ,[REQUEST_ID]
           ,[HASH_VALUE])

	SELECT
            ISNULL(TRY_CONVERT(VARCHAR(16), SRC.[D2001_SPID]), '') AS [SPID],
            ISNULL(TRY_CONVERT(TINYINT, SERV.[SC_RESTRICTION_ID]), 0) AS [FK_SERVICE_COMPONENT_TYPE_ID],
            ISNULL(TRY_CONVERT(TINYINT, WTR.[VOLUMETRIC_ADJUSTMENT_TYPE_ID]), 0) AS [FK_VOLUMETRIC_ADJUSTMENT_TYPE_ID],
            ISNULL(TRY_CONVERT(VARCHAR(64), SRC.[D2045_Volumetric_Adjustment_Unique_Reference]), '') AS [VOLUMETRIC_ADJUSTMENT_UNIQUE_REFERENCE],
            ISNULL(TRY_CONVERT(DATE, SRC.[D4006_Effective_From_Date]), '1900-01-01') AS [EFFECTIVE_FROM_DATE],
            ISNULL(TRY_CONVERT(DATE, SRC.[D4024_Effective_To_Date]), '1900-01-01') AS [EFFECTIVE_TO_DATE],
            ISNULL(TRY_CONVERT(SMALLINT, SRC.[D2047_Adjustment_Volume]), 0) AS [ADJUSTMENT_VOLUME],
            ISNULL(TRY_CONVERT(VARCHAR(512), SRC.[D4003_Text_Comment_Field]), '') AS [TEXT_COMMENT_FIELD],
            ISNULL(TRY_CONVERT(DATE, SRC.[CreatedOn]), '1900-01-01') AS [CREATED_DATE],
            ISNULL(TRY_CONVERT(DATETIME2(3), SRC.[LastUpdatedOn]), '1900-01-01 00:00:00.000') AS [LAST_UPDATED_ON],
            ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[Transaction_Unique_ID]), '') AS [TRANSACTION_UNIQUE_ID],
            ISNULL(TRY_CONVERT(TINYINT, TRANSACT.[TRANSACTION_STATUS_ID]), 0) AS [FK_TRANSACTION_STATUS_ID],
            ISNULL(TRY_CONVERT(TINYINT, MOSL.[MOSL_MESSAGE_ID]), 0) AS [FK_MOSL_MESSAGE_ID],
            ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[Request_ID]), '') AS [REQUEST_ID],
		    HASHBYTES(
                        'sha1',
                            CONCAT_WS('|',
                                ISNULL(TRY_CONVERT(TINYINT, SERV.[SC_RESTRICTION_ID]), 0),
                                ISNULL(TRY_CONVERT(TINYINT, WTR.[VOLUMETRIC_ADJUSTMENT_TYPE_ID]), 0),
                                ISNULL(TRY_CONVERT(VARCHAR(64), SRC.[D2045_Volumetric_Adjustment_Unique_Reference]), ''),
                                ISNULL(TRY_CONVERT(DATE, SRC.[D4006_Effective_From_Date]), '1900-01-01'),
                                ISNULL(TRY_CONVERT(DATE, SRC.[D4024_Effective_To_Date]), '1900-01-01'),
                                ISNULL(TRY_CONVERT(SMALLINT, SRC.[D2047_Adjustment_Volume]), 0),
                                ISNULL(TRY_CONVERT(VARCHAR(512), SRC.[D4003_Text_Comment_Field]), ''),
                                ISNULL(TRY_CONVERT(DATE, SRC.[CreatedOn]), '1900-01-01'),
                                ISNULL(TRY_CONVERT(DATETIME2(3), SRC.[LastUpdatedOn]), '1900-01-01 00:00:00.000'),
                                ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[Transaction_Unique_ID]), ''),
                                ISNULL(TRY_CONVERT(TINYINT, TRANSACT.[TRANSACTION_STATUS_ID]), 0),
                                ISNULL(TRY_CONVERT(TINYINT, MOSL.[MOSL_MESSAGE_ID]), 0)
									))
									AS [HASH_VALUE]
    FROM [STG].[DMS_TXN_T138W] AS SRC
    INNER JOIN dbo.D_SERVICE_COMPONENT_RESTRICTION AS SERV
    ON ISNULL(TRIM(SRC.[D2043_Service_Component_Type]), '') = SERV.SC_RESTRICTION_CODE
    INNER JOIN dbo.D_VOLUMETRIC_ADJUSTMENT_TYPE AS WTR
    ON ISNULL(TRIM(SRC.[D2044_Volumetric_Adjustment_Type]), '') = WTR.VOLUMETRIC_ADJUSTMENT_TYPE_CODE
    INNER JOIN DBO.D_MOSL_MESSAGE AS MOSL
	ON ISNULL(TRIM(SRC.[MOSL_Message]), '') = MOSL.MOSL_MESSAGE_CODE
    INNER JOIN DBO.D_TRANSACTION_STATUS AS TRANSACT
    ON ISNULL(TRIM(SRC.[Transaction_Status]), '') = TRANSACT.TRANSACTION_STATUS;

------------------------------------------------------------------------------------------------------------------------------
	UPDATE DBO
	SET 
    DBO.FK_SERVICE_COMPONENT_TYPE_ID = PRO.FK_SERVICE_COMPONENT_TYPE_ID,
    DBO.FK_VOLUMETRIC_ADJUSTMENT_TYPE_ID = PRO.FK_VOLUMETRIC_ADJUSTMENT_TYPE_ID,
    DBO.VOLUMETRIC_ADJUSTMENT_UNIQUE_REFERENCE = PRO.VOLUMETRIC_ADJUSTMENT_UNIQUE_REFERENCE,
    DBO.EFFECTIVE_FROM_DATE = PRO.EFFECTIVE_FROM_DATE,
    DBO.EFFECTIVE_TO_DATE = PRO.EFFECTIVE_TO_DATE,
    DBO.ADJUSTMENT_VOLUME = PRO.ADJUSTMENT_VOLUME,
    DBO.TEXT_COMMENT_FIELD = PRO.TEXT_COMMENT_FIELD,
    DBO.CREATED_DATE = PRO.CREATED_DATE,
    DBO.LAST_UPDATED_ON = PRO.LAST_UPDATED_ON,
    DBO.TRANSACTION_UNIQUE_ID = PRO.TRANSACTION_UNIQUE_ID,
    DBO.FK_TRANSACTION_STATUS_ID = PRO.FK_TRANSACTION_STATUS_ID,
    DBO.FK_MOSL_MESSAGE_ID = PRO.FK_MOSL_MESSAGE_ID
	FROM [process].[TXN_T138W] AS PRO
	INNER JOIN [dbo].[E_TXN_T138_WHOLESALER] AS DBO
	ON  ISNULL(DBO.SPID, '') = PRO.SPID
	AND ISNULL(DBO.TRANSACTION_UNIQUE_ID, '') = PRO.TRANSACTION_UNIQUE_ID
	AND ISNULL(DBO.LAST_UPDATED_ON, '1900-01-01 00:00:00.000') = PRO.LAST_UPDATED_ON
	AND ISNULL(DBO.REQUEST_ID, '') = PRO.REQUEST_ID
	WHERE PRO.HASH_VALUE <> DBO.HASH_VALUE;

	SET @Updates = @@ROWCOUNT;
------------------------------------------------------------------------------------------------------------------------------
	INSERT INTO [dbo].[E_TXN_T138_WHOLESALER]
           ([SPID]
           ,[FK_SERVICE_COMPONENT_TYPE_ID]
           ,[FK_VOLUMETRIC_ADJUSTMENT_TYPE_ID]
           ,[VOLUMETRIC_ADJUSTMENT_UNIQUE_REFERENCE]
           ,[EFFECTIVE_FROM_DATE]
           ,[EFFECTIVE_TO_DATE]
           ,[ADJUSTMENT_VOLUME]
           ,[TEXT_COMMENT_FIELD]
           ,[CREATED_DATE]
           ,[LAST_UPDATED_ON]
           ,[TRANSACTION_UNIQUE_ID]
           ,[FK_TRANSACTION_STATUS_ID]
           ,[FK_MOSL_MESSAGE_ID]
           ,[REQUEST_ID]
           ,[HASH_VALUE])
		   
	SELECT 
		    PRO.SPID,
            PRO.FK_SERVICE_COMPONENT_TYPE_ID,
            PRO.FK_VOLUMETRIC_ADJUSTMENT_TYPE_ID,
            PRO.VOLUMETRIC_ADJUSTMENT_UNIQUE_REFERENCE,
            PRO.EFFECTIVE_FROM_DATE,
            PRO.EFFECTIVE_TO_DATE,
            PRO.ADJUSTMENT_VOLUME,
            PRO.TEXT_COMMENT_FIELD,
            PRO.CREATED_DATE,
            PRO.LAST_UPDATED_ON,
            PRO.TRANSACTION_UNIQUE_ID,
            PRO.FK_TRANSACTION_STATUS_ID,
            PRO.FK_MOSL_MESSAGE_ID,
            PRO.REQUEST_ID,
			PRO.HASH_VALUE
			FROM [process].[TXN_T138W] AS PRO
			LEFT JOIN [dbo].[E_TXN_T138_WHOLESALER] AS DBO
			ON  ISNULL(DBO.SPID, '') = PRO.SPID
			AND ISNULL(DBO.TRANSACTION_UNIQUE_ID, '') = PRO.TRANSACTION_UNIQUE_ID
			AND ISNULL(DBO.LAST_UPDATED_ON, '1900-01-01 00:00:00.000') = PRO.LAST_UPDATED_ON
			AND ISNULL(DBO.REQUEST_ID, '') = PRO.REQUEST_ID
			WHERE DBO.SPID IS NULL
			AND DBO.TRANSACTION_UNIQUE_ID IS NULL
			AND DBO.LAST_UPDATED_ON IS NULL
			AND DBO.REQUEST_ID IS NULL;
			
			SET @Inserts = @@ROWCOUNT;
------------------------------------------------------------------------------------------------------------------------------
        /* Insert to Audit Table */
        UPDATE [sqlmi-dev-dp-cex-control-db].dbo.Load_Audit
        SET Staged_Rows = @Staged,
            New_Rows = @Inserts,
            Updated_Rows = @Updates,
            Deleted_Rows = @Deletes,
            Error_Rows = @Errors,
            Unchanged_Rows = @Unchanged,
            Load_ErrorMsg = CASE
                                WHEN Load_ErrorMsg = '' THEN
                                    ''
                                ELSE
                                    'Resolved on ' + FORMAT(GETDATE(), 'dd/MM/yyyy a   hh:mmtt') + ' - '
                                    + Load_ErrorMsg
                            END
        WHERE LoadID = @LoadID
        COMMIT TRANSACTION
    END TRY
    BEGIN CATCH
        ROLLBACK;
        /* Insert error message to Audit Table */
        UPDATE [sqlmi-dev-dp-cex-control-db].dbo.Load_Audit
        SET Load_ErrorMsg = ERROR_MESSAGE()
        WHERE LoadID = @LoadID
    END CATCH
    /* Revert entire process if failure */
    IF @@TRANCOUNT > 0
        ROLLBACK;
END
