    ON ISNULL(TRIM(SRC.[D2056_Metered_Potable_Water_Tariff_Code]), '') = POT.WATER_TARIFF_CODE
    INNER JOIN dbo.D_UNMEASURED_TARIFF AS UNM
    ON ISNULL(TRIM(SRC.[D2067_Unmeasured_Tariff_Code]), '') = UNM.UNMEASURED_TARIFF_CODE
    INNER JOIN DBO.D_MOSL_MESSAGE AS MOSL
	ON ISNULL(TRIM(SRC.[MOSL_Message]), '') = MOSL.MOSL_MESSAGE_CODE
    INNER JOIN DBO.D_TRANSACTION_STATUS AS TRANSACT
    ON ISNULL(TRIM(SRC.[Transaction_Status]), '') = TRANSACT.TRANSACTION_STATUS;

------------------------------------------------------------------------------------------------------------------------------
	UPDATE DBO
	SET 
    DBO.FK_METERED_POTABLE_WATER_TARIFF_ID = PRO.FK_METERED_POTABLE_WATER_TARIFF_ID,
    DBO.METERED_NON_POTABLE_WATER_TARIFF_CODE = PRO.METERED_NON_POTABLE_WATER_TARIFF_CODE,
    DBO.FK_ASSESSED_TARIFF_ID = PRO.FK_ASSESSED_TARIFF_ID,
    DBO.FK_UNMEASURED_TARIFF_ID = PRO.FK_UNMEASURED_TARIFF_ID,
    DBO.CHARGE_ADJUSTMENT_TARIFF_CODE = PRO.CHARGE_ADJUSTMENT_TARIFF_CODE,
    DBO.TEXT_COMMENT_FIELD = PRO.TEXT_COMMENT_FIELD,
    DBO.CREATED_DATE = PRO.CREATED_DATE,
    DBO.LAST_UPDATED_ON = PRO.LAST_UPDATED_ON,
    DBO.TRANSACTION_UNIQUE_ID = PRO.TRANSACTION_UNIQUE_ID,
    DBO.FK_TRANSACTION_STATUS_ID = PRO.FK_TRANSACTION_STATUS_ID,
    DBO.FK_MOSL_MESSAGE_ID = PRO.FK_MOSL_MESSAGE_ID
	FROM [process].[TXN_T139W] AS PRO
	INNER JOIN [dbo].[E_TXN_T139_WHOLESALER] AS DBO
	ON  ISNULL(DBO.SPID, '') = PRO.SPID
	AND ISNULL(DBO.TRANSACTION_UNIQUE_ID, '') = PRO.TRANSACTION_UNIQUE_ID
	AND ISNULL(DBO.LAST_UPDATED_ON, '1900-01-01 00:00:00.000') = PRO.LAST_UPDATED_ON
	AND ISNULL(DBO.REQUEST_ID, '') = PRO.REQUEST_ID
	WHERE PRO.HASH_VALUE <> DBO.HASH_VALUE;

	SET @Updates = @@ROWCOUNT;
------------------------------------------------------------------------------------------------------------------------------
	INSERT INTO [dbo].[E_TXN_T139_WHOLESALER]
           ([SPID]
           ,[FK_METERED_POTABLE_WATER_TARIFF_ID]
           ,[METERED_NON_POTABLE_WATER_TARIFF_CODE]
           ,[FK_ASSESSED_TARIFF_ID]
           ,[FK_UNMEASURED_TARIFF_ID]
           ,[CHARGE_ADJUSTMENT_TARIFF_CODE]
           ,[TEXT_COMMENT_FIELD]
           ,[CREATED_DATE]
           ,[LAST_UPDATED_ON]
           ,[TRANSACTION_UNIQUE_ID]
           ,[FK_TRANSACTION_STATUS_ID]
           ,[FK_MOSL_MESSAGE_ID]
           ,[REQUEST_ID]
           ,[HASH_VALUE])
		   
	SELECT 
		    PRO.SPID,
            PRO.FK_METERED_POTABLE_WATER_TARIFF_ID,
            PRO.METERED_NON_POTABLE_WATER_TARIFF_CODE,
            PRO.FK_ASSESSED_TARIFF_ID,
            PRO.FK_UNMEASURED_TARIFF_ID,
            PRO.CHARGE_ADJUSTMENT_TARIFF_CODE,
            PRO.TEXT_COMMENT_FIELD,
            PRO.CREATED_DATE,
            PRO.LAST_UPDATED_ON,
            PRO.TRANSACTION_UNIQUE_ID,
            PRO.FK_TRANSACTION_STATUS_ID,
            PRO.FK_MOSL_MESSAGE_ID,
            PRO.REQUEST_ID,
			PRO.HASH_VALUE
			FROM [process].[TXN_T139W] AS PRO
			LEFT JOIN [dbo].[E_TXN_T139_WHOLESALER] AS DBO
			ON  ISNULL(DBO.SPID, '') = PRO.SPID
			AND ISNULL(DBO.TRANSACTION_UNIQUE_ID, '') = PRO.TRANSACTION_UNIQUE_ID
			AND ISNULL(DBO.LAST_UPDATED_ON, '1900-01-01 00:00:00.000') = PRO.LAST_UPDATED_ON
			AND ISNULL(DBO.REQUEST_ID, '') = PRO.REQUEST_ID
			WHERE DBO.SPID IS NULL
			AND DBO.TRANSACTION_UNIQUE_ID IS NULL
			AND DBO.LAST_UPDATED_ON IS NULL
			AND DBO.REQUEST_ID IS NULL;
			
			SET @Inserts = @@ROWCOUNT;
------------------------------------------------------------------------------------------------------------------------------
        /* Insert to Audit Table */
        UPDATE [sqlmi-dev-dp-cex-control-db].dbo.Load_Audit
        SET Staged_Rows = @Staged,
            New_Rows = @Inserts,
            Updated_Rows = @Updates,
            Deleted_Rows = @Deletes,
            Error_Rows = @Errors,
            Unchanged_Rows = @Unchanged,
            Load_ErrorMsg = CASE
                                WHEN Load_ErrorMsg = '' THEN
                                    ''
                                ELSE
                                    'Resolved on ' + FORMAT(GETDATE(), 'dd/MM/yyyy a   hh:mmtt') + ' - '
                                    + Load_ErrorMsg
                            END
        WHERE LoadID = @LoadID
        COMMIT TRANSACTION
    END TRY
    BEGIN CATCH
        ROLLBACK;
        /* Insert error message to Audit Table */
        UPDATE [sqlmi-dev-dp-cex-control-db].dbo.Load_Audit
        SET Load_ErrorMsg = ERROR_MESSAGE()
        WHERE LoadID = @LoadID
    END CATCH
    /* Revert entire process if failure */
    IF @@TRANCOUNT > 0
        ROLLBACK;
END
