        BEGIN TRANSACTION
------------------------------------------------------------------------------------------------------------------------------		
	TRUNCATE TABLE [process].[TXN_T142M]
	INSERT INTO [process].[TXN_T142M]
           ([SPID]
           ,[FLG_ERRONEOUS_TRANSFER_VALID]
           ,[FK_ERRONEOUS_TRANSFER_REJECTION_REASON_ID]
           ,[REGISTRATION_START_DATE]
           ,[TEXT_COMMENT_FIELD]
           ,[CREATED_DATE]
           ,[LAST_UPDATED_ON]
           ,[TRANSACTION_UNIQUE_ID]
           ,[FK_TRANSACTION_STATUS_ID]
           ,[FLG_DMS_SYNC]
           ,[REQUEST_ID]
           ,[HASH_VALUE])

	SELECT
            ISNULL(TRY_CONVERT(VARCHAR(16), SRC.[D2001_SPID]), '') AS [SPID],
            ISNULL(TRY_CONVERT(BIT, SRC.[D2055_Erroneous_Transfer_Valid_Flag]), 0) AS [FLG_ERRONEOUS_TRANSFER_VALID],
            ISNULL(TRY_CONVERT(TINYINT, ERRONEOUS.[ERRONEOUS_TRANSFER_REASON_ID]), 0) AS [FK_ERRONEOUS_TRANSFER_REJECTION_REASON_ID],
            ISNULL(TRY_CONVERT(DATE, SRC.[D4002_Registration_Start_Date]), '1900-01-01') AS [REGISTRATION_START_DATE],
