           ,[TRANSACTION_UNIQUE_ID]
           ,[FK_TRANSACTION_STATUS_ID]
           ,[FLG_DMS_SYNC]
           ,[REQUEST_ID]
           ,[HASH_VALUE]) 

	SELECT
            ISNULL(TRY_CONVERT(VARCHAR(16), SRC.[D2001_SPID]), '') AS [SPID],
            ISNULL(TRY_CONVERT(DATE, SRC.[D4006_Effective_From_Date]), '1900-01-01') AS [EFFECTIVE_FROM_DATE],
            ISNULL(TRY_CONVERT(INT, SRC.[D2018_Unmeasured_Items_Type_A_Count]), 0) AS [UNMEASURED_ITEMS_TYPE_A_COUNT],
            ISNULL(TRY_CONVERT(VARCHAR(256), SRC.[D2058_Unmeasured_Items_Type_A_Description]), '') AS [UNMEASURED_ITEMS_TYPE_A_DESC],
            ISNULL(TRY_CONVERT(INT, SRC.[D2019_Unmeasured_Items_Type_B_Count]), 0) AS [UNMEASURED_ITEMS_TYPE_B_COUNT],
            ISNULL(TRY_CONVERT(VARCHAR(256), SRC.[D2059_Unmeasured_Items_Type_B_Description]), '') AS [UNMEASURED_ITEMS_TYPE_B_DESC],
            ISNULL(TRY_CONVERT(INT, SRC.[D2020_Unmeasured_Items_Type_C_Count]), 0) AS [UNMEASURED_ITEMS_TYPE_C_COUNT],
