            ISNULL(TRY_CONVERT(VARCHAR(256), SRC.[D2069_Unmeasured_Items_Type_H_Description]), '') AS [UNMEASURED_ITEMS_TYPE_H_DESC],
            ISNULL(TRY_CONVERT(SMALLINT, SRC.[D2071_Pipe_Size]), 0) AS [PIPE_SIZE],
            ISNULL(TRY_CONVERT(VARCHAR(512), SRC.[D4003_Text_Comment_Field]), '') AS [TEXT_COMMENT_FIELD],
            ISNULL(TRY_CONVERT(DATE, SRC.[CreatedOn]), '1900-01-01') AS [CREATED_DATE],
            ISNULL(TRY_CONVERT(DATETIME2(3), SRC.[LastUpdatedOn]), '1900-01-01 00:00:00.000') AS [LAST_UPDATED_ON],
            ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[Transaction_Unique_ID]), '') AS [TRANSACTION_UNIQUE_ID],
            ISNULL(TRY_CONVERT(TINYINT, TRANSACT.[TRANSACTION_STATUS_ID]), 0) AS [FK_TRANSACTION_STATUS_ID],
            ISNULL(TRY_CONVERT(BIT, CASE 
                WHEN SRC.[DMS_Sync_Flag] = 'Y' THEN 1 
                WHEN SRC.[DMS_Sync_Flag] = 'B' THEN 0 
            END), 0) AS [FLG_DMS_SYNC],
            ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[Request_ID]), '') AS [REQUEST_ID],
		    HASHBYTES(
                        'sha1',
                            CONCAT_WS('|',
                                ISNULL(TRY_CONVERT(DATE, SRC.[D4006_Effective_From_Date]), '1900-01-01'),
                                ISNULL(TRY_CONVERT(INT, SRC.[D2018_Unmeasured_Items_Type_A_Count]), 0),
                                ISNULL(TRY_CONVERT(VARCHAR(256), SRC.[D2058_Unmeasured_Items_Type_A_Description]), ''),
                                ISNULL(TRY_CONVERT(INT, SRC.[D2019_Unmeasured_Items_Type_B_Count]), 0),
                                ISNULL(TRY_CONVERT(VARCHAR(256), SRC.[D2059_Unmeasured_Items_Type_B_Description]), ''),
                                ISNULL(TRY_CONVERT(INT, SRC.[D2020_Unmeasured_Items_Type_C_Count]), 0),
                                ISNULL(TRY_CONVERT(VARCHAR(256), SRC.[D2060_Unmeasured_Items_Type_C_Description]), ''),
                                ISNULL(TRY_CONVERT(INT, SRC.[D2021_Unmeasured_Items_Type_D_Count]), 0),
                                ISNULL(TRY_CONVERT(VARCHAR(256), SRC.[D2061_Unmeasured_Items_Type_D_Description]), ''),
                                ISNULL(TRY_CONVERT(INT, SRC.[D2022_Unmeasured_Items_Type_E_Count]), 0),
                                ISNULL(TRY_CONVERT(VARCHAR(256), SRC.[D2062_Unmeasured_Items_Type_E_Description]), ''),
                                ISNULL(TRY_CONVERT(INT, SRC.[D2024_Unmeasured_Items_Type_F_Count]), 0),
