    DBO.PIPE_SIZE = PRO.PIPE_SIZE,
    DBO.TEXT_COMMENT_FIELD = PRO.TEXT_COMMENT_FIELD,
    DBO.CREATED_DATE = PRO.CREATED_DATE,
    DBO.LAST_UPDATED_ON = PRO.LAST_UPDATED_ON,
    DBO.TRANSACTION_UNIQUE_ID = PRO.TRANSACTION_UNIQUE_ID,
    DBO.FK_TRANSACTION_STATUS_ID = PRO.FK_TRANSACTION_STATUS_ID,
    DBO.FLG_DMS_SYNC = PRO.FLG_DMS_SYNC
	FROM [process].[TXN_T144M] AS PRO
	INNER JOIN [dbo].[E_TXN_T144_MARKET_OPERATOR] AS DBO
	ON  ISNULL(DBO.SPID, '') = PRO.SPID
	AND ISNULL(DBO.TRANSACTION_UNIQUE_ID, '') = PRO.TRANSACTION_UNIQUE_ID
	AND ISNULL(DBO.LAST_UPDATED_ON, '1900-01-01 00:00:00.000') = PRO.LAST_UPDATED_ON
	AND ISNULL(DBO.REQUEST_ID, '') = PRO.REQUEST_ID
	WHERE PRO.HASH_VALUE <> DBO.HASH_VALUE;

	SET @Updates = @@ROWCOUNT;
------------------------------------------------------------------------------------------------------------------------------
	INSERT INTO [dbo].[E_TXN_T144_MARKET_OPERATOR]
           ([SPID]
           ,[EFFECTIVE_FROM_DATE]
           ,[UNMEASURED_ITEMS_TYPE_A_COUNT]
           ,[UNMEASURED_ITEMS_TYPE_A_DESC]
           ,[UNMEASURED_ITEMS_TYPE_B_COUNT]
           ,[UNMEASURED_ITEMS_TYPE_B_DESC]
           ,[UNMEASURED_ITEMS_TYPE_C_COUNT]
           ,[UNMEASURED_ITEMS_TYPE_C_DESC]
           ,[UNMEASURED_ITEMS_TYPE_D_COUNT]
           ,[UNMEASURED_ITEMS_TYPE_D_DESC]
           ,[UNMEASURED_ITEMS_TYPE_E_COUNT]
           ,[UNMEASURED_ITEMS_TYPE_E_DESC]
           ,[UNMEASURED_ITEMS_TYPE_F_COUNT]
           ,[UNMEASURED_ITEMS_TYPE_F_DESC]
           ,[UNMEASURED_ITEMS_TYPE_G_COUNT]
           ,[UNMEASURED_ITEMS_TYPE_G_DESC]
           ,[UNMEASURED_ITEMS_TYPE_H_COUNT]
           ,[UNMEASURED_ITEMS_TYPE_H_DESC]
           ,[PIPE_SIZE]
           ,[TEXT_COMMENT_FIELD]
           ,[CREATED_DATE]
           ,[LAST_UPDATED_ON]
           ,[TRANSACTION_UNIQUE_ID]
           ,[FK_TRANSACTION_STATUS_ID]
           ,[FLG_DMS_SYNC]
           ,[REQUEST_ID]
           ,[HASH_VALUE])
		   
	SELECT 
		    PRO.SPID,
            PRO.EFFECTIVE_FROM_DATE,
            PRO.UNMEASURED_ITEMS_TYPE_A_COUNT,
            PRO.UNMEASURED_ITEMS_TYPE_A_DESC,
            PRO.UNMEASURED_ITEMS_TYPE_B_COUNT,
            PRO.UNMEASURED_ITEMS_TYPE_B_DESC,
            PRO.UNMEASURED_ITEMS_TYPE_C_COUNT,
            PRO.UNMEASURED_ITEMS_TYPE_C_DESC,
            PRO.UNMEASURED_ITEMS_TYPE_D_COUNT,
            PRO.UNMEASURED_ITEMS_TYPE_D_DESC,
            PRO.UNMEASURED_ITEMS_TYPE_E_COUNT,
            PRO.UNMEASURED_ITEMS_TYPE_E_DESC,
            PRO.UNMEASURED_ITEMS_TYPE_F_COUNT,
            PRO.UNMEASURED_ITEMS_TYPE_F_DESC,
            PRO.UNMEASURED_ITEMS_TYPE_G_COUNT,
            PRO.UNMEASURED_ITEMS_TYPE_G_DESC,
            PRO.UNMEASURED_ITEMS_TYPE_H_COUNT,
            PRO.UNMEASURED_ITEMS_TYPE_H_DESC,
            PRO.PIPE_SIZE,
            PRO.TEXT_COMMENT_FIELD,
            PRO.CREATED_DATE,
            PRO.LAST_UPDATED_ON,
            PRO.TRANSACTION_UNIQUE_ID,
            PRO.FK_TRANSACTION_STATUS_ID,
            PRO.FLG_DMS_SYNC,
            PRO.REQUEST_ID,
			PRO.HASH_VALUE
			FROM [process].[TXN_T144M] AS PRO
			LEFT JOIN [dbo].[E_TXN_T144_MARKET_OPERATOR] AS DBO
			ON  ISNULL(DBO.SPID, '') = PRO.SPID
			AND ISNULL(DBO.TRANSACTION_UNIQUE_ID, '') = PRO.TRANSACTION_UNIQUE_ID
			AND ISNULL(DBO.LAST_UPDATED_ON, '1900-01-01 00:00:00.000') = PRO.LAST_UPDATED_ON
			AND ISNULL(DBO.REQUEST_ID, '') = PRO.REQUEST_ID
			WHERE DBO.SPID IS NULL
			AND DBO.TRANSACTION_UNIQUE_ID IS NULL
			AND DBO.LAST_UPDATED_ON IS NULL
			AND DBO.REQUEST_ID IS NULL;
			
			SET @Inserts = @@ROWCOUNT;
------------------------------------------------------------------------------------------------------------------------------
        /* Insert to Audit Table */
        UPDATE [sqlmi-dev-dp-cex-control-db].dbo.Load_Audit
        SET Staged_Rows = @Staged,
            New_Rows = @Inserts,
            Updated_Rows = @Updates,
            Deleted_Rows = @Deletes,
            Error_Rows = @Errors,
            Unchanged_Rows = @Unchanged,
            Load_ErrorMsg = CASE
                                WHEN Load_ErrorMsg = '' THEN
                                    ''
                                ELSE
                                    'Resolved on ' + FORMAT(GETDATE(), 'dd/MM/yyyy a   hh:mmtt') + ' - '
                                    + Load_ErrorMsg
                            END
        WHERE LoadID = @LoadID
        COMMIT TRANSACTION
    END TRY
    BEGIN CATCH
        ROLLBACK;
        /* Insert error message to Audit Table */
        UPDATE [sqlmi-dev-dp-cex-control-db].dbo.Load_Audit
        SET Load_ErrorMsg = ERROR_MESSAGE()
        WHERE LoadID = @LoadID
    END CATCH
    /* Revert entire process if failure */
    IF @@TRANCOUNT > 0
        ROLLBACK;
END
