            @EOM INT = DATEPART(DAY, GETUTCDATE()),
            @LoadDate DATE = GETUTCDATE();

    BEGIN TRY
        BEGIN TRANSACTION
------------------------------------------------------------------------------------------------------------------------------		
	TRUNCATE TABLE [process].[TXN_T145M]
	INSERT INTO [process].[TXN_T145M]
           ([SPID]
           ,[EFFECTIVE_FROM_DATE]
           ,[ASSESSED_VOLUMETRIC_RATE]
           ,[ASSESSED_CHARGEABLE_METER_SIZE_MM]
           ,[TARIFF_BAND]
           ,[TEXT_COMMENT_FIELD]
           ,[CREATED_DATE]
           ,[LAST_UPDATED_ON]
           ,[TRANSACTION_UNIQUE_ID]
           ,[FK_TRANSACTION_STATUS_ID]
           ,[FLG_DMS_SYNC]
           ,[REQUEST_ID]
           ,[HASH_VALUE])

	SELECT
            ISNULL(TRY_CONVERT(VARCHAR(16), SRC.[D2001_SPID]), '') AS [SPID],
            ISNULL(TRY_CONVERT(DATE, SRC.[D4006_Effective_From_Date]), '1900-01-01') AS [EFFECTIVE_FROM_DATE],
            ISNULL(TRY_CONVERT(SMALLINT, SRC.[D2049_Assessed_Volumetric_Rate]), 0) AS [ASSESSED_VOLUMETRIC_RATE],
            ISNULL(TRY_CONVERT(SMALLINT, SRC.[D2068_Assessed_Chargeable_Meter_Size]), 0) AS [ASSESSED_CHARGEABLE_METER_SIZE_MM],
            ISNULL(TRY_CONVERT(TINYINT, SRC.[D2081_Tariff_Band]), 0) AS [TARIFF_BAND],
            ISNULL(TRY_CONVERT(VARCHAR(512), SRC.[D4003_Text_Comment_Field]), '') AS [TEXT_COMMENT_FIELD],
            ISNULL(TRY_CONVERT(DATE, SRC.[CreatedOn]), '1900-01-01') AS [CREATED_DATE],
