                        'sha1',
                            CONCAT_WS('|',
                                ISNULL(TRY_CONVERT(DATE, SRC.[D4006_Effective_From_Date]), '1900-01-01'),
                                ISNULL(TRY_CONVERT(DATE, SRC.[D4007_Date_of_Evidence]), '1900-01-01'),
                                ISNULL(TRY_CONVERT(TINYINT, ERROR.[ERROR_RETURN_ID]), 0),
                                ISNULL(TRY_CONVERT(VARCHAR(512), SRC.[D4003_Text_Comment_Field]), ''),
                                ISNULL(TRY_CONVERT(VARCHAR(128), SRC.[D4008_Cryptographic_Hash]), ''),
                                ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[D4009_Cryptographic_Hash_Algorithm]), ''),
                                ISNULL(TRY_CONVERT(TINYINT, SRC.[D4010_Vacancy_Change_Grace_Period]), 0),
                                ISNULL(TRY_CONVERT(TINYINT, WATER.[WATER_RETAILER_ID]), 0),
                                ISNULL(TRY_CONVERT(TINYINT, SEWER.[WATER_RETAILER_ID]), 0),
                                ISNULL(TRY_CONVERT(TINYINT, WHOLE.[WHOLESALER_ID]), 0),
                                ISNULL(TRY_CONVERT(TINYINT, OTHER.[WHOLESALER_ID]), 0),
                                ISNULL(TRY_CONVERT(DATE, SRC.[CreatedOn]), '1900-01-01'),
                                ISNULL(TRY_CONVERT(DATETIME2(3), SRC.[LastUpdatedOn]), '1900-01-01 00:00:00.000'),
                                ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[Transaction_Unique_ID]), ''),
                                ISNULL(TRY_CONVERT(TINYINT, TRANSACT.[TRANSACTION_STATUS_ID]), 0),
                                ISNULL(TRY_CONVERT(BIT, CASE 
                                    WHEN SRC.[DMS_Sync_Flag] = 'Y' THEN 1 
                                    WHEN SRC.[DMS_Sync_Flag] = 'B' THEN 0 
                                END), 0)
									))
									AS [HASH_VALUE]
    FROM [STG].[DMS_TXN_T161M] AS SRC
    INNER JOIN dbo.D_ERROR_RETURN AS ERROR
    ON ISNULL(TRIM(SRC.[D4004_Error_Return_Code]), '') = ERROR.ERROR_RETURN_CODE 
    INNER JOIN dbo.D_WATER_RETAILER_ID AS WATER
    ON ISNULL(TRIM(SRC.[D4011_Retailer_ID]), '') = WATER.WATER_RETAILER_CODE 
    INNER JOIN dbo.D_WATER_RETAILER_ID AS SEWER
    ON ISNULL(TRIM(SRC.[D4012_Sewerage_Retailer_ID]), '') = SEWER.WATER_RETAILER_CODE 
    INNER JOIN DBO.D_WHOLESALER AS WHOLE
    ON ISNULL(TRIM(SRC.[D4025_Wholesaler_ID]), '') = WHOLE.WHOLESALER_CODE
    INNER JOIN DBO.D_WHOLESALER AS OTHER
	ON ISNULL(TRIM(SRC.[D4018_Other_Wholesaler_ID]), '') = OTHER.WHOLESALER_CODE
    INNER JOIN DBO.D_TRANSACTION_STATUS AS TRANSACT
    ON ISNULL(TRIM(SRC.[Transaction_Status]), '') = TRANSACT.TRANSACTION_STATUS;

