	INSERT INTO [dbo].[E_CORRECTION_TXN_T113_WHOLESALER]
           ([SPID]
           ,[FK_METER_MANUFACTURER_ID]
           ,[MANUFACTURER_METER_SERIAL_NUMBER]
           ,[EFFECTIVE_FROM_DATE]
           ,[EFFECTIVE_TO_DATE]
