           ,[ADDRESS_LINE_4]
           ,[ADDRESS_LINE_5]
           ,[POSTCODE]
           ,[PAF_ADDRESS_KEY]
           ,[AUTHORISATION_CODE]
           ,[CREATED_DATE]
           ,[LAST_UPDATED_ON]
           ,[TRANSACTION_UNIQUE_ID]
           ,[FK_TRANSACTION_STATUS_ID]
           ,[FK_MOSL_MESSAGE_ID]
           ,[REQUEST_ID]
           ,[HASH_VALUE])
		   
	SELECT 
		    PRO.SPID,
            PRO.FK_METER_MANUFACTURER_ID,
            PRO.MANUFACTURER_METER_SERIAL_NUMBER,
            PRO.EFFECTIVE_FROM_DATE,
            PRO.EFFECTIVE_TO_DATE,
            PRO.FK_METER_READ_MINIMUM_FREQUENCY_ID,
            PRO.PHYSICAL_METER_SIZE_MM,
            PRO.FLG_DATALOGGER_WHOLESALER,
            PRO.FLG_DATALOGGER_NON_WHOLESALER,
            PRO.GISX,
            PRO.GISY,
            PRO.FK_METER_LOCATION_ID,
            PRO.METER_OUTREADER_GISX,
            PRO.METER_OUTREADER_GISY,
            PRO.FK_METER_OUTREADER_LOCATION_ID,
            PRO.FLG_COMBI_METER,
            PRO.FLG_REMOTE_READ,
            PRO.FK_REMOTE_READ_TYPE_ID,
            PRO.OUTREADER_ID,
            PRO.OUTREADER_PROTOCOL,
            PRO.TEXT_COMMENT_FIELD,
            PRO.FREE_DESCRIPTOR,
            PRO.PRIMARY_ADDRESSABLE_OBJECT,
            PRO.SECONDARY_ADDRESSABLE_OBJECT,
            PRO.ADDRESS_LINE_1,
            PRO.ADDRESS_LINE_2,
            PRO.ADDRESS_LINE_3,
            PRO.ADDRESS_LINE_4,
            PRO.ADDRESS_LINE_5,
            PRO.POSTCODE,
            PRO.PAF_ADDRESS_KEY,
            PRO.AUTHORISATION_CODE,
            PRO.CREATED_DATE,
            PRO.LAST_UPDATED_ON,
            PRO.TRANSACTION_UNIQUE_ID,
            PRO.FK_TRANSACTION_STATUS_ID,
            PRO.FK_MOSL_MESSAGE_ID,
            PRO.REQUEST_ID,
			PRO.HASH_VALUE
			FROM [process].[TXN_TCORR113W] AS PRO
			LEFT JOIN [dbo].[E_CORRECTION_TXN_T113_WHOLESALER] AS DBO
			ON  ISNULL(DBO.SPID, '') = PRO.SPID
			AND ISNULL(DBO.TRANSACTION_UNIQUE_ID, '') = PRO.TRANSACTION_UNIQUE_ID
			AND ISNULL(DBO.LAST_UPDATED_ON, '1900-01-01 00:00:00.000') = PRO.LAST_UPDATED_ON
			AND ISNULL(DBO.REQUEST_ID, '') = PRO.REQUEST_ID
			WHERE DBO.SPID IS NULL
            AND DBO.LAST_UPDATED_ON IS NULL
            AND DBO.TRANSACTION_UNIQUE_ID IS NULL
			AND DBO.REQUEST_ID IS NULL;
			
			SET @Inserts = @@ROWCOUNT;
------------------------------------------------------------------------------------------------------------------------------
        /* Insert to Audit Table */
        UPDATE [sqlmi-dev-dp-cex-control-db].dbo.Load_Audit
        SET Staged_Rows = @Staged,
            New_Rows = @Inserts,
            Updated_Rows = @Updates,
            Deleted_Rows = @Deletes,
            Error_Rows = @Errors,
            Unchanged_Rows = @Unchanged,
            Load_ErrorMsg = CASE
                                WHEN Load_ErrorMsg = '' THEN
                                    ''
                                ELSE
                                    'Resolved on ' + FORMAT(GETDATE(), 'dd/MM/yyyy a   hh:mmtt') + ' - '
                                    + Load_ErrorMsg
                            END
        WHERE LoadID = @LoadID
        COMMIT TRANSACTION
    END TRY
    BEGIN CATCH
        ROLLBACK;
        /* Insert error message to Audit Table */
        UPDATE [sqlmi-dev-dp-cex-control-db].dbo.Load_Audit
        SET Load_ErrorMsg = ERROR_MESSAGE()
        WHERE LoadID = @LoadID
    END CATCH
    /* Revert entire process if failure */
    IF @@TRANCOUNT > 0
        ROLLBACK;
END
