    BEGIN TRY
        BEGIN TRANSACTION
------------------------------------------------------------------------------------------------------------------------------		
	TRUNCATE TABLE [process].[TXN_TCORR115M]
	INSERT INTO [process].[TXN_TCORR115M]
           ([SPID]
           ,[FK_DISCONNECTION_RECONNECTION_DEREGISTRATION_ID]
           ,[FK_SPID_STATUS_ID]
