    INNER JOIN dbo.D_REASON_FOR_DISCONNECTION_OF_SERVICE AS DC
    ON ISNULL(TRIM(SRC.[D2025_Disconnection_Reconnection_Deregistration]), '') = DC.REASON_FOR_DISCONNECTION_CODE
    INNER JOIN DBO.D_SPID_STATUS AS WTR
    ON ISNULL(TRIM(SRC.[D2088_SPID_Status]), '') = WTR.SPID_STATUS_CODE
