           ,[AUTHORISATION_CODE]
           ,[TEXT_COMMENT_FIELD]
           ,[CREATED_DATE]
           ,[LAST_UPDATED_ON]
           ,[TRANSACTION_UNIQUE_ID]
           ,[FK_TRANSACTION_STATUS_ID]
           ,[FK_MOSL_MESSAGE_ID]
           ,[REQUEST_ID]
