    BEGIN TRY
        BEGIN TRANSACTION
------------------------------------------------------------------------------------------------------------------------------		
	TRUNCATE TABLE [process].[TXN_TCORR127W]
	INSERT INTO [process].[TXN_TCORR127W]
           ([SPID]
           ,[DPID]
           ,[EFFECTIVE_FROM_DATE]
           ,[CHARGEABLE_DAILY_VOLUME]
           ,[CHARGEABLE_CHEMICAL_OXYGEN_DEMAND_LOAD]
