                                ISNULL(TRY_CONVERT(NUMERIC(5,2), SRC.[D6010_Seasonal_Factor]), 0.00),
                                ISNULL(TRY_CONVERT(NUMERIC(5,2), SRC.[D6012_Percentage_Allowance]), 0.00),
                                ISNULL(TRY_CONVERT(NUMERIC(5,2), SRC.[D6013_Fixed_Allowance]), 0.00),
                                ISNULL(TRY_CONVERT(BIT, SRC.[D6014_Reception_Treatment_Indicator]), 0),
                                ISNULL(TRY_CONVERT(BIT, SRC.[D6015_Primary_Treatment_Indicator]), 0),
                                ISNULL(TRY_CONVERT(BIT, SRC.[D6016_Marine_Treatment_Indicator]), 0),
                                ISNULL(TRY_CONVERT(BIT, SRC.[D6017_Biological_Treatment_Indicator]), 0),
                                ISNULL(TRY_CONVERT(BIT, SRC.[D6018_Sludge_Treatment_Indicator]), 0),
                                ISNULL(TRY_CONVERT(BIT, SRC.[D6019_Ammonia_Treatment_Indicator]), 0),
                                ISNULL(TRY_CONVERT(BIT, SRC.[D6029_Trade_Effluent_Component_X_Treatment_Indicator]), 0),
                                ISNULL(TRY_CONVERT(BIT, SRC.[D6030_Trade_Effluent_Component_Y_Treatment_Indicator]), 0),
                                ISNULL(TRY_CONVERT(BIT, SRC.[D6031_Trade_Effluent_Component_Z_Treatment_Indicator]), 0),
                                ISNULL(TRY_CONVERT(INT, SRC.[D6032_cXl]), 0),
                                ISNULL(TRY_CONVERT(INT, SRC.[D6033_cYl]), 0),
                                ISNULL(TRY_CONVERT(INT, SRC.[D6034_cZl]), 0),
                                ISNULL(TRY_CONVERT(TINYINT, SRC.[D6024_Trade_Effluent_Tariff_Band]), 0),
                                ISNULL(TRY_CONVERT(TINYINT, ADJUST.SEWERAGE_ADJUSTMENT_ID), 0),
