    DBO.FK_MOSL_MESSAGE_ID = PRO.FK_MOSL_MESSAGE_ID
	FROM [process].[TXN_TCORR127W] AS PRO
	INNER JOIN [dbo].[E_CORRECTION_TXN_T127_WHOLESALER] AS DBO
	ON  ISNULL(DBO.SPID, '') = PRO.SPID
