            ISNULL(TRY_CONVERT(VARCHAR(16), SRC.[D2001_SPID_Main_Meter]), '') AS [SPID_MAIN_METER],
            ISNULL(TRY_CONVERT(BIT, SRC.[D3026_Meter_Network_Association]), 0) AS [FLG_METER_NETWORK_ASSOCIATION],
