									AS [HASH_VALUE]
    FROM [STG].[DMS_TXN_TCORR143M] AS SRC
    INNER JOIN dbo.D_SERVICE_COMPONENT_RESTRICTION AS SERV
    ON ISNULL(TRIM(SRC.[D2043_Service_Component_Type]), '') = SERV.SC_RESTRICTION_CODE
    INNER JOIN dbo.D_TARIFF_CODE_APPLICABLE AS WTR
    ON ISNULL(TRIM(SRC.[D2073_Tariff_Code_Applicable]), '') = WTR.TARIFF_CODE_APPLICABLE_CODE
    INNER JOIN DBO.D_TRANSACTION_STATUS AS TRANSACT
    ON ISNULL(TRIM(SRC.[Transaction_Status]), '') = TRANSACT.TRANSACTION_STATUS;

------------------------------------------------------------------------------------------------------------------------------
	UPDATE DBO
	SET 
    DBO.FK_SERVICE_COMPONENT_TYPE_ID = PRO.FK_SERVICE_COMPONENT_TYPE_ID,
    DBO.FLG_SERVICE_COMPONENT_ENABLED = PRO.FLG_SERVICE_COMPONENT_ENABLED,
    DBO.FK_TARIFF_CODE_APPLICABLE_ID = PRO.FK_TARIFF_CODE_APPLICABLE_ID,
    DBO.EFFECTIVE_FROM_DATE = PRO.EFFECTIVE_FROM_DATE,
    DBO.TEXT_COMMENT_FIELD = PRO.TEXT_COMMENT_FIELD,
    DBO.EFFECTIVE_TO_DATE = PRO.EFFECTIVE_TO_DATE,
    DBO.AUTHORISATION_CODE = PRO.AUTHORISATION_CODE,
    DBO.CREATED_DATE = PRO.CREATED_DATE,
    DBO.LAST_UPDATED_ON = PRO.LAST_UPDATED_ON,
    DBO.TRANSACTION_UNIQUE_ID = PRO.TRANSACTION_UNIQUE_ID,
    DBO.FK_TRANSACTION_STATUS_ID = PRO.FK_TRANSACTION_STATUS_ID,
    DBO.FLG_DMS_SYNC = PRO.FLG_DMS_SYNC
	FROM [process].[TXN_TCORR143M] AS PRO
	INNER JOIN [dbo].[E_CORRECTION_TXN_T143_MARKET_OPERATOR] AS DBO
	ON  ISNULL(DBO.SPID, '') = PRO.SPID
	AND ISNULL(DBO.TRANSACTION_UNIQUE_ID, '') = PRO.TRANSACTION_UNIQUE_ID
	AND ISNULL(DBO.LAST_UPDATED_ON, '1900-01-01 00:00:00.000') = PRO.LAST_UPDATED_ON
	AND ISNULL(DBO.REQUEST_ID, '') = PRO.REQUEST_ID
	WHERE PRO.HASH_VALUE <> DBO.HASH_VALUE;

	SET @Updates = @@ROWCOUNT;
------------------------------------------------------------------------------------------------------------------------------
	INSERT INTO [dbo].[E_CORRECTION_TXN_T143_MARKET_OPERATOR]
           ([SPID]
           ,[FK_SERVICE_COMPONENT_TYPE_ID]
           ,[FLG_SERVICE_COMPONENT_ENABLED]
           ,[FK_TARIFF_CODE_APPLICABLE_ID]
           ,[EFFECTIVE_FROM_DATE]
           ,[TEXT_COMMENT_FIELD]
           ,[EFFECTIVE_TO_DATE]
           ,[AUTHORISATION_CODE]
           ,[CREATED_DATE]
           ,[LAST_UPDATED_ON]
           ,[TRANSACTION_UNIQUE_ID]
           ,[FK_TRANSACTION_STATUS_ID]
           ,[FLG_DMS_SYNC]
           ,[REQUEST_ID]
           ,[HASH_VALUE])
		   
	SELECT 
		    PRO.SPID,
            PRO.FK_SERVICE_COMPONENT_TYPE_ID,
            PRO.FLG_SERVICE_COMPONENT_ENABLED,
            PRO.FK_TARIFF_CODE_APPLICABLE_ID,
            PRO.EFFECTIVE_FROM_DATE,
            PRO.TEXT_COMMENT_FIELD,
            PRO.EFFECTIVE_TO_DATE,
            PRO.AUTHORISATION_CODE,
            PRO.CREATED_DATE,
            PRO.LAST_UPDATED_ON,
            PRO.TRANSACTION_UNIQUE_ID,
            PRO.FK_TRANSACTION_STATUS_ID,
            PRO.FLG_DMS_SYNC,
            PRO.REQUEST_ID,
			PRO.HASH_VALUE
			FROM [process].[TXN_TCORR143M] AS PRO
			LEFT JOIN [dbo].[E_CORRECTION_TXN_T143_MARKET_OPERATOR] AS DBO
			ON  ISNULL(DBO.SPID, '') = PRO.SPID
			AND ISNULL(DBO.TRANSACTION_UNIQUE_ID, '') = PRO.TRANSACTION_UNIQUE_ID
			AND ISNULL(DBO.LAST_UPDATED_ON, '1900-01-01 00:00:00.000') = PRO.LAST_UPDATED_ON
			AND ISNULL(DBO.REQUEST_ID, '') = PRO.REQUEST_ID
			WHERE DBO.SPID IS NULL
			AND DBO.TRANSACTION_UNIQUE_ID IS NULL
			AND DBO.LAST_UPDATED_ON IS NULL
			AND DBO.REQUEST_ID IS NULL;
			
			SET @Inserts = @@ROWCOUNT;
------------------------------------------------------------------------------------------------------------------------------
        /* Insert to Audit Table */
        UPDATE [sqlmi-dev-dp-cex-control-db].dbo.Load_Audit
        SET Staged_Rows = @Staged,
            New_Rows = @Inserts,
            Updated_Rows = @Updates,
            Deleted_Rows = @Deletes,
            Error_Rows = @Errors,
            Unchanged_Rows = @Unchanged,
            Load_ErrorMsg = CASE
                                WHEN Load_ErrorMsg = '' THEN
                                    ''
                                ELSE
                                    'Resolved on ' + FORMAT(GETDATE(), 'dd/MM/yyyy a   hh:mmtt') + ' - '
                                    + Load_ErrorMsg
                            END
        WHERE LoadID = @LoadID
        COMMIT TRANSACTION
    END TRY
    BEGIN CATCH
        ROLLBACK;
        /* Insert error message to Audit Table */
        UPDATE [sqlmi-dev-dp-cex-control-db].dbo.Load_Audit
        SET Load_ErrorMsg = ERROR_MESSAGE()
        WHERE LoadID = @LoadID
    END CATCH
    /* Revert entire process if failure */
    IF @@TRANCOUNT > 0
        ROLLBACK;
END
