            @LoadDate DATE = GETUTCDATE();

    BEGIN TRY
        BEGIN TRANSACTION
------------------------------------------------------------------------------------------------------------------------------		
	TRUNCATE TABLE [process].[TXN_TCORR144W]
	INSERT INTO [process].[TXN_TCORR144W]
           ([SPID]
           ,[EFFECTIVE_FROM_DATE]
           ,[UNMEASURED_ITEMS_TYPE_A_COUNT]
           ,[UNMEASURED_ITEMS_TYPE_A_DESC]
