           ,[UNMEASURED_ITEMS_TYPE_B_DESC]
           ,[UNMEASURED_ITEMS_TYPE_C_COUNT]
           ,[UNMEASURED_ITEMS_TYPE_C_DESC]
           ,[UNMEASURED_ITEMS_TYPE_D_COUNT]
           ,[UNMEASURED_ITEMS_TYPE_D_DESC]
           ,[UNMEASURED_ITEMS_TYPE_E_COUNT]
           ,[UNMEASURED_ITEMS_TYPE_E_DESC]
           ,[UNMEASURED_ITEMS_TYPE_F_COUNT]
           ,[UNMEASURED_ITEMS_TYPE_F_DESC]
           ,[UNMEASURED_ITEMS_TYPE_G_COUNT]
