AS
BEGIN
    SET XACT_ABORT ON;
    SET NOCOUNT ON;
    DECLARE @Inserts BIGINT = 0,
            @Updates BIGINT = 0,
            @Errors BIGINT = 0,
            @Unchanged BIGINT = 0,
            @Deletes BIGINT = 0,
            @OriginalRowCount BIGINT = 0,
            @Staged BIGINT = 0,
            @RowsAffected BIGINT = 0,
            @masterRunID VARCHAR(100) = '',
            @TodayDT DATETIME2(3) = GETUTCDATE(),
            @Today DATE = GETUTCDATE(),
            @Yesterday DATE = TRY_CONVERT(DATE, DATEADD(DAY, -1, GETUTCDATE())),
            @EOM INT = DATEPART(DAY, GETUTCDATE()),
            @LoadDate DATE = GETUTCDATE();

    BEGIN TRY
        BEGIN TRANSACTION
------------------------------------------------------------------------------------------------------------------------------		
	TRUNCATE TABLE [process].[TXN_TCORR173M]
	INSERT INTO [process].[TXN_TCORR173M]
           ([SPID]
           ,[FK_METER_MANUFACTURER_ID]
           ,[MANUFACTURER_METER_SERIAL_NUMBER]
           ,[INITIAL_METER_READ_DATE]
           ,[METER_READ]
           ,[METER_READ_DATE]
           ,[FK_METER_READ_TYPE_ID]
           ,[FK_METER_READ_METHOD_ID]
           ,[FLG_ROLLOVER]
           ,[AUTHORISATION_CODE]
           ,[FK_ESTIMATED_READ_REASON_ID]
           ,[TEXT_COMMENT_FIELD]
           ,[CREATED_DATE]
           ,[LAST_UPDATED_ON]
           ,[TRANSACTION_UNIQUE_ID]
           ,[FK_TRANSACTION_STATUS_ID]
           ,[FLG_DMS_SYNC]
           ,[REQUEST_ID]
           ,[HASH_VALUE])

	SELECT
            ISNULL(TRY_CONVERT(VARCHAR(16), SRC.[D2001_SPID]), '') AS [SPID],
            ISNULL(TRY_CONVERT(SMALLINT, METER.[METER_MANUFACTURER_ID]), 0) AS [FK_METER_MANUFACTURER_ID],
            ISNULL(TRY_CONVERT(VARCHAR(50), SRC.[D3014_Manufacturer_Meter_Serial_Number]), '') AS [MANUFACTURER_METER_SERIAL_NUMBER],
            ISNULL(TRY_CONVERT(DATE, SRC.[D3042_Initial_Meter_Read_Date]), '1900-01-01') AS [INITIAL_METER_READ_DATE],
            ISNULL(TRY_CONVERT(INT, SRC.[D3008_Meter_Read]), 0) AS [METER_READ],
            ISNULL(TRY_CONVERT(DATE, SRC.[D3009_Meter_Read_Date]), '1900-01-01') AS [METER_READ_DATE],
            ISNULL(TRY_CONVERT(TINYINT, TYPE.[METER_READ_TYPE_ID]), 0) AS [FK_METER_READ_TYPE_ID],
            ISNULL(TRY_CONVERT(TINYINT, METHOD.[STAGING_METER_READ_METHOD_ID]), 0) AS [FK_METER_READ_METHOD_ID],
            ISNULL(TRY_CONVERT(BIT, SRC.[D3021_Rollover_Flag]), 0) AS [FLG_ROLLOVER],
            ISNULL(TRY_CONVERT(VARCHAR(256), SRC.[D4031_Authorisation_Code]), '') AS [AUTHORISATION_CODE],
            ISNULL(TRY_CONVERT(TINYINT, REASON.[ESTIMATED_READ_REASON_ID]), 0) AS [FK_ESTIMATED_READ_REASON_ID],
            ISNULL(TRY_CONVERT(VARCHAR(512), SRC.[D4003_Text_Comment_Field]), '') AS [TEXT_COMMENT_FIELD],
            ISNULL(TRY_CONVERT(DATE, SRC.[CreatedOn]), '1900-01-01') AS [CREATED_DATE],
            ISNULL(TRY_CONVERT(DATETIME2(3), SRC.[LastUpdatedOn]), '1900-01-01 00:00:00.000') AS [LAST_UPDATED_ON],
            ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[Transaction_Unique_ID]), '') AS [TRANSACTION_UNIQUE_ID],
            ISNULL(TRY_CONVERT(TINYINT, TRANSACT.[TRANSACTION_STATUS_ID]), 0) AS [FK_TRANSACTION_STATUS_ID],
            ISNULL(TRY_CONVERT(BIT, CASE 
                                        WHEN SRC.[DMS_Sync_Flag] = 'Y' THEN 1 
                                        WHEN SRC.[DMS_Sync_Flag] = 'B' THEN 0 
                                        END), 0) AS [FLG_DMS_SYNC],
            ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[Request_ID]), '') AS [REQUEST_ID],
		    HASHBYTES(
                        'sha1',
                            CONCAT_WS('|',
                                ISNULL(TRY_CONVERT(SMALLINT, METER.[METER_MANUFACTURER_ID]), 0),
                                ISNULL(TRY_CONVERT(VARCHAR(50), SRC.[D3014_Manufacturer_Meter_Serial_Number]), ''),
                                ISNULL(TRY_CONVERT(DATE, SRC.[D3042_Initial_Meter_Read_Date]), '1900-01-01'),
                                ISNULL(TRY_CONVERT(INT, SRC.[D3008_Meter_Read]), 0),
                                ISNULL(TRY_CONVERT(DATE, SRC.[D3009_Meter_Read_Date]), '1900-01-01'),
                                ISNULL(TRY_CONVERT(TINYINT, TYPE.[METER_READ_TYPE_ID]), 0),
                                ISNULL(TRY_CONVERT(TINYINT, METHOD.[STAGING_METER_READ_METHOD_ID]), 0),
                                ISNULL(TRY_CONVERT(BIT, SRC.[D3021_Rollover_Flag]), 0),
                                ISNULL(TRY_CONVERT(VARCHAR(256), SRC.[D4031_Authorisation_Code]), ''),
                                ISNULL(TRY_CONVERT(TINYINT, REASON.[ESTIMATED_READ_REASON_ID]), 0),
                                ISNULL(TRY_CONVERT(VARCHAR(512), SRC.[D4003_Text_Comment_Field]), ''),
                                ISNULL(TRY_CONVERT(DATE, SRC.[CreatedOn]), '1900-01-01'),
                                ISNULL(TRY_CONVERT(DATETIME2(3), SRC.[LastUpdatedOn]), '1900-01-01 00:00:00.000'),
                                ISNULL(TRY_CONVERT(VARCHAR(32), SRC.[Transaction_Unique_ID]), ''),
                                ISNULL(TRY_CONVERT(TINYINT, TRANSACT.[TRANSACTION_STATUS_ID]), 0),
                                ISNULL(TRY_CONVERT(BIT, CASE 
                                                            WHEN SRC.[DMS_Sync_Flag] = 'Y' THEN 1 
                                                            WHEN SRC.[DMS_Sync_Flag] = 'B' THEN 0 
                                                            END), 0)
									))
									AS [HASH_VALUE]
    FROM [STG].[DMS_TXN_TCORR173M] AS SRC
    INNER JOIN dbo.D_METER_MANUFACTURER AS METER
    ON ISNULL(TRIM(SRC.[D3013_Meter_Manufacturer]), '') = METER.METER_MANUFACTURER_DESCRIPTION
    INNER JOIN dbo.D_STAGING_METER_READ_TYPE AS TYPE
    ON ISNULL(TRIM(SRC.[D3010_Meter_Read_Type]), '') = TYPE.METER_READ_TYPE_CODE
    INNER JOIN dbo.D_STAGING_METER_READ_METHOD AS METHOD
    ON ISNULL(TRIM(SRC.[D3044_Meter_Read_Method]), '') = METHOD.METER_READ_METHOD_DESCRIPTION
    INNER JOIN dbo.D_ESTIMATED_READ_REASON AS REASON
    ON ISNULL(TRIM(SRC.[D3028_Estimated_Read_Reason_Code]), '') = REASON.ESTIMATED_READ_REASON_CODE
    INNER JOIN DBO.D_TRANSACTION_STATUS AS TRANSACT
    ON ISNULL(TRIM(SRC.[Transaction_Status]), '') = TRANSACT.TRANSACTION_STATUS;

------------------------------------------------------------------------------------------------------------------------------
	UPDATE DBO
	SET 
    DBO.FK_METER_MANUFACTURER_ID = PRO.FK_METER_MANUFACTURER_ID,
    DBO.MANUFACTURER_METER_SERIAL_NUMBER = PRO.MANUFACTURER_METER_SERIAL_NUMBER,
    DBO.INITIAL_METER_READ_DATE = PRO.INITIAL_METER_READ_DATE,
    DBO.METER_READ = PRO.METER_READ,
    DBO.METER_READ_DATE = PRO.METER_READ_DATE,
    DBO.FK_METER_READ_TYPE_ID = PRO.FK_METER_READ_TYPE_ID,
    DBO.FK_METER_READ_METHOD_ID = PRO.FK_METER_READ_METHOD_ID,
    DBO.FLG_ROLLOVER = PRO.FLG_ROLLOVER,
    DBO.AUTHORISATION_CODE = PRO.AUTHORISATION_CODE,
    DBO.FK_ESTIMATED_READ_REASON_ID = PRO.FK_ESTIMATED_READ_REASON_ID,
    DBO.TEXT_COMMENT_FIELD = PRO.TEXT_COMMENT_FIELD,
    DBO.CREATED_DATE = PRO.CREATED_DATE,
    DBO.LAST_UPDATED_ON = PRO.LAST_UPDATED_ON,
    DBO.TRANSACTION_UNIQUE_ID = PRO.TRANSACTION_UNIQUE_ID,
    DBO.FK_TRANSACTION_STATUS_ID = PRO.FK_TRANSACTION_STATUS_ID,
    DBO.FLG_DMS_SYNC = PRO.FLG_DMS_SYNC
	FROM [process].[TXN_TCORR173M] AS PRO
	INNER JOIN [dbo].[E_CORRECTION_TXN_T173_MARKET_OPERATOR] AS DBO
	ON  ISNULL(DBO.SPID, '') = PRO.SPID
	AND ISNULL(DBO.TRANSACTION_UNIQUE_ID, '') = PRO.TRANSACTION_UNIQUE_ID
	AND ISNULL(DBO.LAST_UPDATED_ON, '1900-01-01 00:00:00.000') = PRO.LAST_UPDATED_ON
	AND ISNULL(DBO.REQUEST_ID, '') = PRO.REQUEST_ID
	WHERE PRO.HASH_VALUE <> DBO.HASH_VALUE;

	SET @Updates = @@ROWCOUNT;
------------------------------------------------------------------------------------------------------------------------------
	INSERT INTO [dbo].[E_CORRECTION_TXN_T173_MARKET_OPERATOR]
           ([SPID]
           ,[FK_METER_MANUFACTURER_ID]
           ,[MANUFACTURER_METER_SERIAL_NUMBER]
           ,[INITIAL_METER_READ_DATE]
           ,[METER_READ]
           ,[METER_READ_DATE]
           ,[FK_METER_READ_TYPE_ID]
           ,[FK_METER_READ_METHOD_ID]
           ,[FLG_ROLLOVER]
           ,[AUTHORISATION_CODE]
           ,[FK_ESTIMATED_READ_REASON_ID]
           ,[TEXT_COMMENT_FIELD]
           ,[CREATED_DATE]
           ,[LAST_UPDATED_ON]
           ,[TRANSACTION_UNIQUE_ID]
           ,[FK_TRANSACTION_STATUS_ID]
           ,[FLG_DMS_SYNC]
           ,[REQUEST_ID]
           ,[HASH_VALUE])
		   
	SELECT 
		    PRO.SPID,
            PRO.FK_METER_MANUFACTURER_ID,
            PRO.MANUFACTURER_METER_SERIAL_NUMBER,
            PRO.INITIAL_METER_READ_DATE,
            PRO.METER_READ,
            PRO.METER_READ_DATE,
            PRO.FK_METER_READ_TYPE_ID,
            PRO.FK_METER_READ_METHOD_ID,
            PRO.FLG_ROLLOVER,
            PRO.AUTHORISATION_CODE,
            PRO.FK_ESTIMATED_READ_REASON_ID,
            PRO.TEXT_COMMENT_FIELD,
            PRO.CREATED_DATE,
            PRO.LAST_UPDATED_ON,
            PRO.TRANSACTION_UNIQUE_ID,
            PRO.FK_TRANSACTION_STATUS_ID,
            PRO.FLG_DMS_SYNC,
            PRO.REQUEST_ID,
			PRO.HASH_VALUE
			FROM [process].[TXN_TCORR173M] AS PRO
			LEFT JOIN [dbo].[E_CORRECTION_TXN_T173_MARKET_OPERATOR] AS DBO
			ON  ISNULL(DBO.SPID, '') = PRO.SPID
			AND ISNULL(DBO.TRANSACTION_UNIQUE_ID, '') = PRO.TRANSACTION_UNIQUE_ID
			AND ISNULL(DBO.LAST_UPDATED_ON, '1900-01-01 00:00:00.000') = PRO.LAST_UPDATED_ON
			AND ISNULL(DBO.REQUEST_ID, '') = PRO.REQUEST_ID
			WHERE DBO.SPID IS NULL
			AND DBO.TRANSACTION_UNIQUE_ID IS NULL
			AND DBO.LAST_UPDATED_ON IS NULL
			AND DBO.REQUEST_ID IS NULL;
			
			SET @Inserts = @@ROWCOUNT;
------------------------------------------------------------------------------------------------------------------------------
        /* Insert to Audit Table */
        UPDATE [sqlmi-dev-dp-cex-control-db].dbo.Load_Audit
        SET Staged_Rows = @Staged,
            New_Rows = @Inserts,
            Updated_Rows = @Updates,
            Deleted_Rows = @Deletes,
            Error_Rows = @Errors,
            Unchanged_Rows = @Unchanged,
            Load_ErrorMsg = CASE
                                WHEN Load_ErrorMsg = '' THEN
                                    ''
                                ELSE
                                    'Resolved on ' + FORMAT(GETDATE(), 'dd/MM/yyyy a   hh:mmtt') + ' - '
                                    + Load_ErrorMsg
                            END
        WHERE LoadID = @LoadID
        COMMIT TRANSACTION
    END TRY
    BEGIN CATCH
        ROLLBACK;
        /* Insert error message to Audit Table */
        UPDATE [sqlmi-dev-dp-cex-control-db].dbo.Load_Audit
        SET Load_ErrorMsg = ERROR_MESSAGE()
        WHERE LoadID = @LoadID
    END CATCH
    /* Revert entire process if failure */
    IF @@TRANCOUNT > 0
        ROLLBACK;
END
GO
--------------------------------------------------------------------------------------------------------------------------------
CREATE OR ALTER   PROCEDURE [stg].[sp_UPDATE_CORRECTION_TXN_T173_WHOLESALER] @LoadID BIGINT
AS
BEGIN
