CREATE OR ALTER     PROCEDURE [stg].[sp_UPDATE_CORRECTION_TXN_T174_MARKET_OPERATOR] @LoadID BIGINT
AS
BEGIN
    SET XACT_ABORT ON;
    SET NOCOUNT ON;
    DECLARE @Inserts BIGINT = 0,
            @Updates BIGINT = 0,
            @Errors BIGINT = 0,
            @Unchanged BIGINT = 0,
            @Deletes BIGINT = 0,
            @OriginalRowCount BIGINT = 0,
            @Staged BIGINT = 0,
            @RowsAffected BIGINT = 0,
            @masterRunID VARCHAR(100) = '',
            @TodayDT DATETIME2(3) = GETUTCDATE(),
