CREATE OR ALTER   PROCEDURE [stg].[sp_UPDATE_TXN_UNMEASURED_POSTCODE_CHANGE_AREA] @LoadID BIGINT
AS
BEGIN
    SET XACT_ABORT ON;
    SET NOCOUNT ON;
    DECLARE @Inserts BIGINT = 0,
            @Updates BIGINT = 0,
            @Errors BIGINT = 0,
            @Unchanged BIGINT = 0,
            @Deletes BIGINT = 0,
            @OriginalRowCount BIGINT = 0,
            @Staged BIGINT = 0,
            @RowsAffected BIGINT = 0,
            @masterRunID VARCHAR(100) = '',
            @TodayDT DATETIME2(3) = GETUTCDATE(),
            @Today DATE = GETUTCDATE(),
            @Yesterday DATE = TRY_CONVERT(DATE, DATEADD(DAY, -1, GETUTCDATE())),
            @EOM INT = DATEPART(DAY, GETUTCDATE()),
            @LoadDate DATE = GETUTCDATE();

    BEGIN TRY
        BEGIN TRANSACTION
------------------------------------------------------------------------------------------------------------------------------		
	TRUNCATE TABLE [process].[TXN_UNMEASURED_POSTCODE_CHANGE_AREA]
	INSERT INTO [process].[TXN_UNMEASURED_POSTCODE_CHANGE_AREA]
           ([POSTCODE]
           ,[UNMEASURED_CHANGE_AREA]
           ,[FLG_AMBIGUOUS_AREA]
           ,[POST_OOD]
           ,[POST_IOD]
           ,[HASH_VALUE]) 

	SELECT
            ISNULL(TRY_CONVERT(VARCHAR(16), SRC.[POSTCODE]), '') AS [POSTCODE],
            ISNULL(TRY_CONVERT(TINYINT, SRC.[UNM_CHG_AREA]), 0) AS [UNMEASURED_CHANGE_AREA],
            ISNULL(TRY_CONVERT(BIT, CASE 
							WHEN SRC.[AMBIGUOUS_AREA] = 'Y' THEN 1 
							WHEN SRC.[AMBIGUOUS_AREA] = 'N' THEN 0 
							END), 0) AS [FLG_AMBIGUOUS_AREA],
            ISNULL(TRY_CONVERT(VARCHAR(8), SRC.[PST_OOD]), '') AS [POST_OOD],
            ISNULL(TRY_CONVERT(VARCHAR(8), SRC.[PST_IOD]), '') AS [POST_IOD],
		    HASHBYTES(
                        'sha1',
                            CONCAT_WS('|',
                                ISNULL(TRY_CONVERT(VARCHAR(16), SRC.[POSTCODE]), ''),
                                ISNULL(TRY_CONVERT(TINYINT, SRC.[UNM_CHG_AREA]), 0),
                                ISNULL(TRY_CONVERT(BIT, CASE 
                                            WHEN SRC.[AMBIGUOUS_AREA] = 'Y' THEN 1 
                                            WHEN SRC.[AMBIGUOUS_AREA] = 'N' THEN 0 
                                            END), 0),
                                ISNULL(TRY_CONVERT(VARCHAR(8), SRC.[PST_OOD]), ''),
                                ISNULL(TRY_CONVERT(VARCHAR(8), SRC.[PST_IOD]), '') 
									))
									AS [HASH_VALUE]
    FROM [STG].[DMS_TXN_UNM_POSTCODE_CHG_AREA] AS SRC;

------------------------------------------------------------------------------------------------------------------------------
	UPDATE DBO
	SET 
	DBO.POSTCODE = PRO.POSTCODE,
    DBO.UNMEASURED_CHANGE_AREA = PRO.UNMEASURED_CHANGE_AREA,
    DBO.FLG_AMBIGUOUS_AREA = PRO.FLG_AMBIGUOUS_AREA,
    DBO.POST_OOD = PRO.POST_OOD,
    DBO.POST_IOD = PRO.POST_IOD
	FROM [process].[TXN_UNMEASURED_POSTCODE_CHANGE_AREA] AS PRO
	INNER JOIN [dbo].[E_TXN_UNMEASURED_POSTCODE_CHANGE_AREA] AS DBO
	ON  ISNULL(DBO.POSTCODE, '') = PRO.POSTCODE
    AND ISNULL(DBO.POST_OOD, '') = PRO.POST_OOD
    AND ISNULL(DBO.UNMEASURED_CHANGE_AREA, 0) = PRO.UNMEASURED_CHANGE_AREA
    AND ISNULL(DBO.POST_IOD, '') = PRO.POST_IOD
	AND ISNULL(DBO.FLG_AMBIGUOUS_AREA, 0) = PRO.FLG_AMBIGUOUS_AREA
	WHERE PRO.HASH_VALUE <> DBO.HASH_VALUE;

	SET @Updates = @@ROWCOUNT;
------------------------------------------------------------------------------------------------------------------------------
	INSERT INTO [dbo].[E_TXN_UNMEASURED_POSTCODE_CHANGE_AREA]
           ([POSTCODE]
           ,[UNMEASURED_CHANGE_AREA]
           ,[FLG_AMBIGUOUS_AREA]
           ,[POST_OOD]
           ,[POST_IOD]
           ,[HASH_VALUE])
		   
	SELECT 
		    PRO.POSTCODE,
            PRO.UNMEASURED_CHANGE_AREA,
            PRO.FLG_AMBIGUOUS_AREA,
            PRO.POST_OOD,
            PRO.POST_IOD,
			PRO.HASH_VALUE
			FROM [process].[TXN_UNMEASURED_POSTCODE_CHANGE_AREA] AS PRO
			LEFT JOIN [dbo].[E_TXN_UNMEASURED_POSTCODE_CHANGE_AREA] AS DBO
			ON  ISNULL(DBO.POSTCODE, '') = PRO.POSTCODE
            AND ISNULL(DBO.POST_OOD, '') = PRO.POST_OOD
            AND ISNULL(DBO.UNMEASURED_CHANGE_AREA, 0) = PRO.UNMEASURED_CHANGE_AREA
            AND ISNULL(DBO.POST_IOD, '') = PRO.POST_IOD
			AND ISNULL(DBO.FLG_AMBIGUOUS_AREA, 0) = PRO.FLG_AMBIGUOUS_AREA
			WHERE DBO.POSTCODE IS NULL
            AND DBO.POST_OOD IS NULL
            AND DBO.UNMEASURED_CHANGE_AREA IS NULL
            AND DBO.POST_IOD IS NULL
			AND DBO.FLG_AMBIGUOUS_AREA IS NULL;
			
			SET @Inserts = @@ROWCOUNT;
------------------------------------------------------------------------------------------------------------------------------
        /* Insert to Audit Table */
        UPDATE [sqlmi-dev-dp-cex-control-db].dbo.Load_Audit
        SET Staged_Rows = @Staged,
            New_Rows = @Inserts,
            Updated_Rows = @Updates,
            Deleted_Rows = @Deletes,
            Error_Rows = @Errors,
            Unchanged_Rows = @Unchanged,
            Load_ErrorMsg = CASE
                                WHEN Load_ErrorMsg = '' THEN
                                    ''
                                ELSE
                                    'Resolved on ' + FORMAT(GETDATE(), 'dd/MM/yyyy a   hh:mmtt') + ' - '
                                    + Load_ErrorMsg
                            END
        WHERE LoadID = @LoadID
        COMMIT TRANSACTION
    END TRY
    BEGIN CATCH
        ROLLBACK;
        /* Insert error message to Audit Table */
        UPDATE [sqlmi-dev-dp-cex-control-db].dbo.Load_Audit
        SET Load_ErrorMsg = ERROR_MESSAGE()
        WHERE LoadID = @LoadID
    END CATCH
    /* Revert entire process if failure */
    IF @@TRANCOUNT > 0
        ROLLBACK;
END
GO
--------------------------------------------------------------------------------------------------------------------------------
CREATE OR ALTER       PROCEDURE [stg].[sp_UPDATE_TXN_AUDIT_CONTROL_ERROR_LOG] @LoadID BIGINT
AS
BEGIN
    SET XACT_ABORT ON;
    SET NOCOUNT ON;
    DECLARE @Inserts BIGINT = 0,
            @Updates BIGINT = 0,
            @Errors BIGINT = 0,
            @Unchanged BIGINT = 0,
            @Deletes BIGINT = 0,
            @OriginalRowCount BIGINT = 0,
            @Staged BIGINT = 0,
            @RowsAffected BIGINT = 0,
            @masterRunID VARCHAR(100) = '',
            @TodayDT DATETIME2(3) = GETUTCDATE(),
            @Today DATE = GETUTCDATE(),
            @Yesterday DATE = TRY_CONVERT(DATE, DATEADD(DAY, -1, GETUTCDATE())),
            @EOM INT = DATEPART(DAY, GETUTCDATE()),
            @LoadDate DATE = GETUTCDATE();

    BEGIN TRY
        BEGIN TRANSACTION
------------------------------------------------------------------------------------------------------------------------------		
	TRUNCATE TABLE [process].[TXN_AUDIT_CONTROL_ERROR_LOG]
	INSERT INTO [process].[TXN_AUDIT_CONTROL_ERROR_LOG]
           ([PK_ERROR_LOG_ID]
           ,[BATCH_SESSION_ID]
           ,[BATCH_RUN_DATE]
           ,[FK_SOURCE_ENTITY_ID]
           ,[FK_SOURCE_ROW_KEY_ID]
           ,[SOURCE_ROW_KEY_VALUE]
           ,[FK_JOB_ID]
           ,[FK_ERROR_CODE_ID]
           ,[FK_ERROR_ID]
           ,[CREATED_DATE]
           ,[FLG_PROCESSED]
           ,[PROCESSED_DATE]
           ,[HASH_VALUE])

	SELECT
            ISNULL(TRY_CONVERT(NUMERIC(9,0), SRC.[Error_Log_Id]), 0) AS [PK_ERROR_LOG_ID],
            ISNULL(TRY_CONVERT(INT, SRC.[Batch_sesion_id]), 0) AS [BATCH_SESSION_ID],
            ISNULL(TRY_CONVERT(DATE, SRC.[Batch_Run_Date]), '1900-01-01') AS [BATCH_RUN_DATE],
            ISNULL(TRY_CONVERT(TINYINT, SOURCE.[SOURCE_ENTITY_ID]), 0) AS [FK_SOURCE_ENTITY_ID],
            ISNULL(TRY_CONVERT(TINYINT, SOURCES.[SOURCE_ROW_KEY_ID]), 0) AS [FK_SOURCE_ROW_KEY_ID],
            ISNULL(TRY_CONVERT(VARCHAR(64), SRC.[Source_Row_Key_Value]), '') AS [SOURCE_ROW_KEY_VALUE],
            ISNULL(TRY_CONVERT(TINYINT, JOBS.[JOB_ID]), 0) AS [FK_JOB_ID],
            ISNULL(TRY_CONVERT(TINYINT, ERROR.[ERROR_CODE_ID]), 0) AS [FK_ERROR_CODE_ID],
            ISNULL(TRY_CONVERT(SMALLINT, ERRORS.[ERROR_ID]), 0) AS [FK_ERROR_ID],
            ISNULL(TRY_CONVERT(DATE, SRC.[CreatedOn]), '1900-01-01') AS [CREATED_DATE],
            ISNULL(TRY_CONVERT(BIT, SRC.[Processed_Flag]), 0) AS [FLG_PROCESSED],
            ISNULL(TRY_CONVERT(DATE, SRC.[Processed_Date]), '1900-01-01') AS [PROCESSED_DATE],
		    HASHBYTES(
                        'sha1',
                            CONCAT_WS('|',
                                ISNULL(TRY_CONVERT(INT, SRC.[Batch_sesion_id]), 0),
                                ISNULL(TRY_CONVERT(DATE, SRC.[Batch_Run_Date]), '1900-01-01'),
                                ISNULL(TRY_CONVERT(TINYINT, SOURCE.[SOURCE_ENTITY_ID]), 0),
                                ISNULL(TRY_CONVERT(TINYINT, SOURCES.[SOURCE_ROW_KEY_ID]), 0),
                                ISNULL(TRY_CONVERT(VARCHAR(64), SRC.[Source_Row_Key_Value]), ''),
                                ISNULL(TRY_CONVERT(TINYINT, JOBS.[JOB_ID]), 0),
                                ISNULL(TRY_CONVERT(TINYINT, ERROR.[ERROR_CODE_ID]), 0),
                                ISNULL(TRY_CONVERT(SMALLINT, ERRORS.[ERROR_ID]), 0),
                                ISNULL(TRY_CONVERT(DATE, SRC.[CreatedOn]), '1900-01-01'),
                                ISNULL(TRY_CONVERT(BIT, SRC.[Processed_Flag]), 0),
                                ISNULL(TRY_CONVERT(DATE, SRC.[Processed_Date]), '1900-01-01')
									))
									AS [HASH_VALUE]
    FROM [STG].[DMS_TXN_AUDIT_CTRL_ERROR_LOG] AS SRC
    INNER JOIN DBO.D_ERROR_CODE AS ERROR
    ON ISNULL(TRIM(SRC.[Error_Code]), '') = ERROR.ERROR_CODE
    INNER JOIN DBO.D_ERROR AS ERRORS
    ON ISNULL(TRIM(SRC.[Error_Desc]), '') = ERRORS.ERROR_DESC
    INNER JOIN DBO.D_JOB AS JOBS
    ON ISNULL(TRIM(SRC.[Job_Name]), '') = JOBS.JOB_NAME
    INNER JOIN DBO.D_SOURCE_ENTITY AS SOURCE
    ON ISNULL(TRIM(SRC.[Source_Entity_Name]), '') = SOURCE.SOURCE_ENTITY_NAME
    INNER JOIN DBO.D_SOURCE_ROW_KEY AS SOURCES
    ON ISNULL(TRIM(SRC.[Source_Row_Key]), '') = SOURCES.SOURCE_ROW_KEY;

------------------------------------------------------------------------------------------------------------------------------
	UPDATE DBO
	SET 
    DBO.BATCH_SESSION_ID = PRO.BATCH_SESSION_ID,
    DBO.BATCH_RUN_DATE = PRO.BATCH_RUN_DATE,
    DBO.FK_SOURCE_ENTITY_ID = PRO.FK_SOURCE_ENTITY_ID,
    DBO.FK_SOURCE_ROW_KEY_ID = PRO.FK_SOURCE_ROW_KEY_ID,
    DBO.SOURCE_ROW_KEY_VALUE = PRO.SOURCE_ROW_KEY_VALUE,
    DBO.FK_JOB_ID = PRO.FK_JOB_ID,
    DBO.FK_ERROR_CODE_ID = PRO.FK_ERROR_CODE_ID,
    DBO.FK_ERROR_ID = PRO.FK_ERROR_ID,
    DBO.CREATED_DATE = PRO.CREATED_DATE,
    DBO.FLG_PROCESSED = PRO.FLG_PROCESSED,
    DBO.PROCESSED_DATE = PRO.PROCESSED_DATE
	FROM [process].[TXN_AUDIT_CONTROL_ERROR_LOG] AS PRO
	INNER JOIN [dbo].[E_TXN_AUDIT_CONTROL_ERROR_LOG] AS DBO
	ON  ISNULL(DBO.PK_ERROR_LOG_ID, '') = PRO.PK_ERROR_LOG_ID
	WHERE PRO.HASH_VALUE <> DBO.HASH_VALUE;

	SET @Updates = @@ROWCOUNT;
------------------------------------------------------------------------------------------------------------------------------
	INSERT INTO [dbo].[E_TXN_AUDIT_CONTROL_ERROR_LOG]
           ([PK_ERROR_LOG_ID]
           ,[BATCH_SESSION_ID]
           ,[BATCH_RUN_DATE]
           ,[FK_SOURCE_ENTITY_ID]
           ,[FK_SOURCE_ROW_KEY_ID]
           ,[SOURCE_ROW_KEY_VALUE]
           ,[FK_JOB_ID]
           ,[FK_ERROR_CODE_ID]
           ,[FK_ERROR_ID]
           ,[CREATED_DATE]
           ,[FLG_PROCESSED]
           ,[PROCESSED_DATE]
           ,[HASH_VALUE]) 
		   
	SELECT 
		    PRO.PK_ERROR_LOG_ID,
            PRO.BATCH_SESSION_ID,
            PRO.BATCH_RUN_DATE,
            PRO.FK_SOURCE_ENTITY_ID,
            PRO.FK_SOURCE_ROW_KEY_ID,
            PRO.SOURCE_ROW_KEY_VALUE,
            PRO.FK_JOB_ID,
            PRO.FK_ERROR_CODE_ID,
            PRO.FK_ERROR_ID,
            PRO.CREATED_DATE,
            PRO.FLG_PROCESSED,
            PRO.PROCESSED_DATE,
			PRO.HASH_VALUE
			FROM [process].[TXN_AUDIT_CONTROL_ERROR_LOG] AS PRO
			LEFT JOIN [dbo].[E_TXN_AUDIT_CONTROL_ERROR_LOG] AS DBO
			ON  ISNULL(DBO.PK_ERROR_LOG_ID, '') = PRO.PK_ERROR_LOG_ID
			WHERE DBO.PK_ERROR_LOG_ID IS NULL;
			
			SET @Inserts = @@ROWCOUNT;
------------------------------------------------------------------------------------------------------------------------------
        /* Insert to Audit Table */
        UPDATE [sqlmi-dev-dp-cex-control-db].dbo.Load_Audit
        SET Staged_Rows = @Staged,
            New_Rows = @Inserts,
            Updated_Rows = @Updates,
            Deleted_Rows = @Deletes,
            Error_Rows = @Errors,
            Unchanged_Rows = @Unchanged,
            Load_ErrorMsg = CASE
                                WHEN Load_ErrorMsg = '' THEN
                                    ''
                                ELSE
                                    'Resolved on ' + FORMAT(GETDATE(), 'dd/MM/yyyy a   hh:mmtt') + ' - '
                                    + Load_ErrorMsg
                            END
        WHERE LoadID = @LoadID
        COMMIT TRANSACTION
    END TRY
    BEGIN CATCH
        ROLLBACK;
        /* Insert error message to Audit Table */
        UPDATE [sqlmi-dev-dp-cex-control-db].dbo.Load_Audit
        SET Load_ErrorMsg = ERROR_MESSAGE()
        WHERE LoadID = @LoadID
    END CATCH
    /* Revert entire process if failure */
    IF @@TRANCOUNT > 0
        ROLLBACK;
END
GO
